export function parseUnionTypeString(typeStr: string): string[] | undefined {
  if (!typeStr.includes("|")) {
    return undefined;
  }

  const parts = splitTopLevel(typeStr, "|")
    .map((part) => part.trim())
    .filter((part) => part.length > 0);

  return parts.length > 1 ? parts : undefined;
}

export function parseFunctionTypeString(
  typeStr: string,
): ParsedFunctionType | undefined {
  const trimmed = typeStr.trim();
  if (!trimmed.startsWith("(")) {
    return undefined;
  }

  let depth = 0;
  let closingParenIndex = -1;
  for (let i = 0; i < trimmed.length; i++) {
    const char = trimmed[i];
    if (char === "(") depth++;
    if (char === ")") {
      depth--;
      if (depth === 0) {
        closingParenIndex = i;
        break;
      }
    }
  }

  if (closingParenIndex === -1) {
    return undefined;
  }

  const afterParen = trimmed.slice(closingParenIndex + 1).trim();
  if (!afterParen.startsWith("=>")) {
    return undefined;
  }

  const returnType = afterParen.slice(2).trim();
  const paramsText = trimmed.slice(1, closingParenIndex).trim();
  const parameterTypes =
    paramsText.length === 0 ? [] : splitTopLevel(paramsText, ",");

  return {
    parameterTypes,
    returnType,
  };
}

export function parseCallableTypeString(
  typeStr: string,
): ParsedFunctionType | undefined {
  const directCallable = parseFunctionTypeString(typeStr);
  if (directCallable) {
    return directCallable;
  }

  if (typeStr.startsWith("*mut ")) {
    return parseFunctionTypeString(typeStr.slice(5));
  }

  if (typeStr.startsWith("*")) {
    return parseFunctionTypeString(typeStr.slice(1));
  }

  const vtableCallable = parseVTableCallableType(typeStr);
  if (vtableCallable) {
    return vtableCallable;
  }

  return undefined;
}

export function parseVTableCallableType(
  typeStr: string,
): ParsedFunctionType | undefined {
  if (!typeStr.startsWith("~")) {
    return undefined;
  }
  const inner = typeStr.slice(1); // "Shape<Square>"
  const ltIdx = inner.indexOf("<");
  const gtIdx = inner.lastIndexOf(">");
  if (ltIdx === -1 || gtIdx === -1 || gtIdx < ltIdx) {
    return undefined;
  }
  const contractName = inner.slice(0, ltIdx);
  const allArgs = inner.slice(ltIdx + 1, gtIdx).split(",").map((s) => s.trim());
  const concreteType = allArgs[0];
  if (!concreteType) return undefined;
  const contractTypeArgs = allArgs.slice(1);
  const returnType =
    contractTypeArgs.length > 0
      ? contractName + "<" + contractTypeArgs.join(", ") + ">"
      : contractName;
  return { parameterTypes: [concreteType], returnType };
}

export function parseCallArguments(parser: Parser): Result<ASTNode[], string> {
  const args: ASTNode[] = [];

  while (current(parser).type !== "RPAREN") {
    const argResult = parseExpression(parser);
    if (!argResult.ok) {
      return argResult;
    }
    args.push(argResult.value);

    const nextTok = current(parser);
    if (nextTok.type === "RPAREN") {
      break;
    }
    if (nextTok.type !== "COMMA") {
      return err("Expected ',' or ')' in function call argument list");
    }
    advance(parser);
  }

  if (current(parser).type !== "RPAREN") {
    return err("Expected ')' after function arguments");
  }
  advance(parser);

  return ok(args);
}

