export function tryParseModuleReference(
  parser: Parser,
): Result<ModuleReferenceNode | undefined, string> {
  const startToken = current(parser);
  if (startToken.type !== "IDENTIFIER") {
    return ok(undefined);
  }

  const savedPos = parser.pos;
  let moduleName = startToken.value;
  let segmentCount = 1;

  advance(parser);

  while (current(parser).type === "DOUBLE_COLON") {
    advance(parser);
    const segmentToken = current(parser);
    if (segmentToken.type !== "IDENTIFIER") {
      parser.pos = savedPos;
      return err("Expected module name segment after '::'");
    }

    moduleName += "::" + segmentToken.value;
    segmentCount++;
    advance(parser);
  }

  if (segmentCount === 1) {
    const nameTaken = findScopeBinding(parser.currentScope, moduleName);
    const moduleInfo = parser.modules.get(moduleName);
    if (!moduleInfo || nameTaken) {
      parser.pos = savedPos;
      return ok(undefined);
    }

    return ok({
      kind: "module-reference",
      moduleName: moduleInfo.moduleName,
      runtimeName: moduleInfo.runtimeName,
      type: moduleInfo.typeName,
    });
  }

  const moduleInfo = parser.modules.get(moduleName);
  if (!moduleInfo) {
    return err("Unknown module '" + moduleName + "'");
  }

  return ok({
    kind: "module-reference",
    moduleName: moduleInfo.moduleName,
    runtimeName: moduleInfo.runtimeName,
    type: moduleInfo.typeName,
  });
}

export function enterCallableScope(
  parser: Parser,
  parentScope: ScopeFrame,
  parameters: FunctionParameter[],
): void {
  parser.currentScope = createScopeFrame(parentScope);
  for (const param of parameters) {
    parser.variables.set(param.name, {
      type: param.type,
      mutable: false,
      aliasType: param.aliasType,
      destructorFunction: param.destructorFunction,
      moved: false,
    });
    registerScopeVariable(parser, param.name, param.type, false, true);
  }
}

export function maybeMoveExpression(
  parser: Parser,
  expression: ASTNode,
): Result<ASTNode, string> {
  if (expression.kind !== "variable") {
    return ok(expression);
  }

  const variableInfo = parser.variables.get(expression.name);
  if (!variableInfo?.destructorFunction) {
    return ok(expression);
  }

  if (variableInfo.moved) {
    return err(
      "Variable '" + expression.name + "' was moved and cannot be used",
    );
  }

  parser.variables.set(expression.name, {
    ...variableInfo,
    moved: true,
  });

  return ok({
    kind: "move",
    name: expression.name,
    type: variableInfo.type,
  });
}

export function validateAliasDestructor(
  parser: Parser,
  aliasName: string,
  destructorName: string,
): Result<void, string> {
  const fnInfo = parser.functions.get(destructorName);
  if (!fnInfo) {
    return err(
      "Destructor function '" +
        destructorName +
        "' for alias '" +
        aliasName +
        "' is not defined",
    );
  }

  if (fnInfo.returnType !== "Void") {
    return err(
      "Destructor function '" +
        destructorName +
        "' for alias '" +
        aliasName +
        "' must return Void",
    );
  }

  const firstParameter = fnInfo.parameters[0];
  if (!firstParameter) {
    return err(
      "Destructor function '" +
        destructorName +
        "' for alias '" +
        aliasName +
        "' must take a this parameter",
    );
  }

  if (firstParameter.name !== "this") {
    return err(
      "Destructor function '" +
        destructorName +
        "' for alias '" +
        aliasName +
        "' must use 'this' as its first parameter name",
    );
  }

  if (firstParameter.aliasType !== aliasName) {
    return err(
      "Destructor function '" +
        destructorName +
        "' for alias '" +
        aliasName +
        "' must take '" +
        aliasName +
        "' as its first parameter type",
    );
  }

  return ok(undefined);
}

export function isDestructorFunction(
  parser: Parser,
  functionName: string,
): boolean {
  for (const destructorName of parser.aliasDestructors.values()) {
    if (destructorName === functionName) {
      return true;
    }
  }

  return false;
}

export function parseTrailingUnionType(
  parser: Parser,
  typeStr: string,
  resolveAliases: boolean,
): Result<string, string> {
  let currentType = typeStr;

  while (current(parser).type === "PIPE") {
    advance(parser);
    const unionTypeResult = parseTypeAnnotation(parser, resolveAliases);
    if (!unionTypeResult.ok) {
      return unionTypeResult;
    }

    const appendedUnion = appendUnionType(
      parser,
      currentType,
      unionTypeResult.value,
      resolveAliases,
    );
    if (!appendedUnion.ok) {
      return appendedUnion;
    }

    currentType = appendedUnion.value;
  }

  return ok(currentType);
}

export function consumeCommaOrClosingParen(
  parser: Parser,
  errorMessage: string,
): Result<undefined, string> {
  if (current(parser).type === "COMMA") {
    advance(parser);
    return ok(undefined);
  }
  if (current(parser).type !== "RPAREN") {
    return err(errorMessage);
  }
  return ok(undefined);
}

export function isTypeAnnotationStartToken(token: Token | undefined): boolean {
  return (
    !!token &&
    (token.type === "IDENTIFIER" ||
      token.type === "LBRACKET" ||
      token.type === "LPAREN" ||
      (token.type === "OPERATOR" && token.value === "*"))
  );
}

export function isKnownTypeAnnotationName(
  parser: Parser,
  typeName: string,
): boolean {
  return (
    VALID_TYPES.has(typeName) ||
    parser.structNames.has(typeName) ||
    parser.aliasDeclarations.has(typeName) ||
    isGenericTypeParameter(parser, typeName)
  );
}

export function isLifetimeAnnotationFollower(
  token: Token | undefined,
): boolean {
  return (
    isTypeAnnotationStartToken(token) ||
    (token?.type === "KEYWORD" && token.value === "mut")
  );
}

export function getCurrentLifetimeDeclarationScope(
  parser: Parser,
): Set<string> {
  return parser.lifetimeDeclarationScopes[
    parser.lifetimeDeclarationScopes.length - 1
  ] as Set<string>;
}

export function enterLifetimeScope(
  parser: Parser,
  lifetimeName: string,
): Result<void, string> {
  const currentScope = getCurrentLifetimeDeclarationScope(parser);
  if (currentScope.has(lifetimeName)) {
    return err(
      "Lifetime '" + lifetimeName + "' is already declared in this scope",
    );
  }

  if (parser.activeLifetimeNames.includes(lifetimeName)) {
    return err(
      "Lifetime '" + lifetimeName + "' cannot shadow an enclosing lifetime",
    );
  }

  currentScope.add(lifetimeName);
  parser.activeLifetimeNames.push(lifetimeName);
  parser.lifetimeDeclarationScopes.push(new Set<string>());
  return ok(undefined);
}

export function exitLifetimeScope(parser: Parser): void {
  parser.activeLifetimeNames.pop();
  if (parser.lifetimeDeclarationScopes.length > 1) {
    parser.lifetimeDeclarationScopes.pop();
  }
}

export function parseLifetimeBlockHeader(
  parser: Parser,
): Result<string, string> {
  const lifetimeKeyword = expectKeyword(
    parser,
    "lifetime",
    "Expected 'lifetime'",
  );
  if (!lifetimeKeyword.ok) {
    return lifetimeKeyword;
  }

  const nameToken = current(parser);
  if (nameToken.type !== "IDENTIFIER") {
    return err("Expected lifetime name");
  }
  const lifetimeName = nameToken.value;
  advance(parser);

  if (current(parser).type !== "LBRACE") {
    return err("Expected '{' after lifetime name");
  }
  advance(parser);

  return ok(lifetimeName);
}

export function parseAndEnterLifetimeScope(
  parser: Parser,
): Result<void, string> {
  const lifetimeName = parseLifetimeBlockHeader(parser);
  if (!lifetimeName.ok) {
    return lifetimeName;
  }

  return enterLifetimeScope(parser, lifetimeName.value);
}

export function getImplicitReceiverType(
  parser: Parser,
): Result<string, string> {
  const receiverType = parser.currentFunctionReturnType;
  if (!receiverType || receiverType === "__inferred__") {
    return err(
      "Implicit receiver shorthand requires an enclosing function with a known return type",
    );
  }

  return ok(receiverType);
}

export function parseImplicitReceiverParameterFromAmbient(
  parser: Parser,
  isFirstParameter: boolean,
  extraAdvanceCount: number,
): Result<FunctionParameter, string> {
  if (!isFirstParameter) {
    return err("Special receiver shorthand must be the first parameter");
  }

  const receiverType = getImplicitReceiverType(parser);
  if (!receiverType.ok) {
    return receiverType;
  }

  advance(parser);
  for (let i = 0; i < extraAdvanceCount; i++) {
    advance(parser);
  }

  return ok({
    name: "this",
    type: receiverType.value,
    out: false,
  });
}

export function tryParseImplicitReceiverParameter(
  parser: Parser,
  isFirstParameter: boolean,
): Result<FunctionParameter | undefined, string> {
  const token = current(parser);

  if (token.type === "KEYWORD" && token.value === "this") {
    const nextToken = parser.tokens[parser.pos + 1];
    if (nextToken?.type === "COLON") {
      return ok(undefined);
    }

    return parseImplicitReceiverParameterFromAmbient(
      parser,
      isFirstParameter,
      0,
    );
  }

  if (token.type !== "OPERATOR" || token.value !== "*") {
    return ok(undefined);
  }

  const nextToken = parser.tokens[parser.pos + 1];
  const afterNextToken = parser.tokens[parser.pos + 2];
  const isBorrowedReceiver =
    nextToken?.type === "KEYWORD" && nextToken.value === "this";
  const isMutableReceiver =
    nextToken?.type === "KEYWORD" &&
    nextToken.value === "mut" &&
    afterNextToken?.type === "KEYWORD" &&
    afterNextToken.value === "this";

  if (!isBorrowedReceiver && !isMutableReceiver) {
    return ok(undefined);
  }

  return parseImplicitReceiverParameterFromAmbient(
    parser,
    isFirstParameter,
    isMutableReceiver ? 2 : 1,
  );
}

export function parseFunctionParameters(
  parser: Parser,
  rejectShadowing: boolean,
): Result<FunctionParameter[], string> {
  const parameters: FunctionParameter[] = [];
  const parameterNames = new Set<string>();

  while (current(parser).type !== "RPAREN") {
    const implicitReceiver = tryParseImplicitReceiverParameter(
      parser,
      parameters.length === 0,
    );
    if (!implicitReceiver.ok) {
      return implicitReceiver;
    }
    if (implicitReceiver.value) {
      parameterNames.add("this");
      parameters.push(implicitReceiver.value);

      const separatorResult = consumeCommaOrClosingParen(
        parser,
        "Expected ',' or ')' in parameter list",
      );
      if (!separatorResult.ok) {
        return separatorResult;
      }
      continue;
    }

    const paramNameTok = current(parser);
    if (
      paramNameTok.type !== "IDENTIFIER" &&
      !(paramNameTok.type === "KEYWORD" && paramNameTok.value === "this")
    ) {
      return err("Expected parameter name");
    }

    const paramName = paramNameTok.value;
    if (paramName !== "this") {
      const paramKeywordCheck = checkReservedKeyword(
        paramName,
        "parameter name",
      );
      if (!paramKeywordCheck.ok) {
        return paramKeywordCheck;
      }
    }
    if (parameterNames.has(paramName)) {
      return err("Duplicate parameter name '" + paramName + "'");
    }
    if (rejectShadowing && parser.variables.has(paramName)) {
      return err(
        "Parameter name '" + paramName + "' shadows a captured variable",
      );
    }
    parameterNames.add(paramName);
    advance(parser);

    if (current(parser).type !== "COLON") {
      return err("Expected ':' after parameter name");
    }
    advance(parser);

    const paramTypeResult = parseFunctionParameterTypeReference(parser);
    if (!paramTypeResult.ok) {
      return paramTypeResult;
    }
    parameters.push({
      name: paramName,
      type: paramTypeResult.value.type,
      out: paramTypeResult.value.out,
      aliasType: paramTypeResult.value.aliasType,
      destructorFunction: paramTypeResult.value.destructorFunction,
    });

    const separatorResult = consumeCommaOrClosingParen(
      parser,
      "Expected ',' or ')' in parameter list",
    );
    if (!separatorResult.ok) {
      return separatorResult;
    }
  }

  if (current(parser).type !== "RPAREN") {
    return err("Expected ')' after parameter list");
  }
  advance(parser);

  return ok(parameters);
}

export function canStartClosureParameterList(parser: Parser): boolean {
  if (current(parser).type === "RPAREN") {
    return true;
  }

  const currentToken = current(parser);

  if (
    currentToken.type !== "IDENTIFIER" &&
    !(currentToken.type === "KEYWORD" && currentToken.value === "this")
  ) {
    return false;
  }

  const nextTok = parser.tokens[parser.pos + 1];
  return nextTok?.type === "COLON";
}

export interface ParsedTypeAnnotationInfo {
  type: string;
  out: boolean;
}

export function parseTypeAnnotation(
  parser: Parser,
  resolveAliases: boolean = true,
): Result<string, string> {
  const typeInfo = parseTypeAnnotationInfo(parser, resolveAliases, false);
  return typeInfo.ok ? ok(typeInfo.value.type) : typeInfo;
}

export function parseTypeAnnotationInfo(
  parser: Parser,
  resolveAliases: boolean = true,
  allowOut: boolean = false,
): Result<ParsedTypeAnnotationInfo, string> {
  // Count and consume any leading * for pointer types
  let pointerDepth = 0;
  let isMutable = false;
  let isOut = false;
  while (
    current(parser).type === "OPERATOR" &&
    (current(parser) as OperatorToken).value === "*"
  ) {
    pointerDepth++;
    advance(parser);

    let consumedModifier = false;
    while (true) {
      const typeToken = current(parser);
      if (typeToken.type === "KEYWORD") {
        const keyword = typeToken.value;
        if (keyword === "mut") {
          if (isMutable) {
            return err("Pointer type cannot use 'mut' more than once");
          }
          isMutable = true;
          consumedModifier = true;
          advance(parser);
          continue;
        }

        if (keyword === "out") {
          if (!allowOut) {
            return err(
              "The 'out' modifier is only valid for function parameters",
            );
          }
          if (isOut) {
            return err("Pointer type cannot use 'out' more than once");
          }
          isOut = true;
          consumedModifier = true;
          advance(parser);
          continue;
        }

        break;
      }

      if (typeToken.type === "IDENTIFIER") {
        const nextToken = parser.tokens[parser.pos + 1];
        const isExplicitLifetime =
          isLifetimeAnnotationFollower(nextToken) &&
          (parser.activeLifetimeNames.includes(typeToken.value) ||
            !isKnownTypeAnnotationName(parser, typeToken.value));

        if (!isExplicitLifetime) {
          break;
        }

        if (!parser.activeLifetimeNames.includes(typeToken.value)) {
          return err("Unknown lifetime '" + typeToken.value + "'");
        }

        consumedModifier = true;
        advance(parser);
        continue;
      }

      break;
    }

    if (consumedModifier) {
      break;
    }
  }

  const currentTypeToken = current(parser);
  if (
    currentTypeToken.type === "IDENTIFIER" &&
    parser.activeLifetimeNames.includes(currentTypeToken.value) &&
    isLifetimeAnnotationFollower(parser.tokens[parser.pos + 1])
  ) {
    return err("Explicit lifetimes are only valid on pointer types");
  }

  if (
    current(parser).type === "KEYWORD" &&
    (current(parser) as KeywordToken).value === "out"
  ) {
    return allowOut
      ? err("Out parameters must use pointer types")
      : err("The 'out' modifier is only valid for function parameters");
  }

  if (isOut && !isMutable) {
    return err("Out pointer parameters must also be marked 'mut'");
  }

  // Check for array or slice value type [ElementType; Length] / [ElementType]
  if (current(parser).type === "LBRACKET") {
    advance(parser); // consume [

    // Parse element type recursively (can be nested arrays)
    const elemTypeResult = parseTypeAnnotation(parser, resolveAliases);
    if (!elemTypeResult.ok) {
      return elemTypeResult;
    }
    const elemType = elemTypeResult.value;

    if (current(parser).type === "RBRACKET") {
      advance(parser);
      const sliceType = parseTrailingUnionType(
        parser,
        applyPointerDecorators("[" + elemType + "]", pointerDepth, isMutable),
        resolveAliases,
      );
      return sliceType.ok
        ? ok({ type: sliceType.value, out: isOut })
        : sliceType;
    }

    // Expect ;
    if (current(parser).type !== "SEMICOLON") {
      return err("Expected ';' after array element type");
    }
    advance(parser);

    // Parse array length
    const lengthTok = current(parser);
    if (lengthTok.type !== "NUMBER") {
      return err("Expected array length as number");
    }
    const lengthValue = (lengthTok as NumberToken).value;
    if (!isBareNonNegativeIntegerLiteral(lengthValue)) {
      return err("Expected array length as a non-negative integer literal");
    }
    advance(parser);

    // Expect ]
    if (current(parser).type !== "RBRACKET") {
      return err("Expected ']' to close array type");
    }
    advance(parser);

    const arrayType = parseTrailingUnionType(
      parser,
      applyPointerDecorators(
        "[" + elemType + ";" + lengthValue + "]",
        pointerDepth,
        isMutable,
      ),
      resolveAliases,
    );
    return arrayType.ok ? ok({ type: arrayType.value, out: isOut }) : arrayType;
  }

  // Function type: (T1, T2) => R
  if (current(parser).type === "LPAREN") {
    advance(parser); // consume '('

    const parameterTypes: string[] = [];
    while (current(parser).type !== "RPAREN") {
      const paramTypeResult = parseTypeAnnotation(parser, resolveAliases);
      if (!paramTypeResult.ok) {
        return paramTypeResult;
      }
      parameterTypes.push(paramTypeResult.value);

      const separatorResult = consumeCommaOrClosingParen(
        parser,
        "Expected ',' or ')' in function type",
      );
      if (!separatorResult.ok) {
        return err("Expected ',' or ')' in function type");
      }
    }

    if (current(parser).type !== "RPAREN") {
      return err("Expected ')' after function type parameters");
    }
    advance(parser);

    if (current(parser).type !== "ARROW") {
      return err("Expected '=>' in function type");
    }
    advance(parser);

    const returnTypeResult = parseTypeAnnotation(parser, resolveAliases);
    if (!returnTypeResult.ok) {
      return returnTypeResult;
    }

    const functionType = parseTrailingUnionType(
      parser,
      applyPointerDecorators(
        "(" + parameterTypes.join(", ") + ") => " + returnTypeResult.value,
        pointerDepth,
        isMutable,
      ),
      resolveAliases,
    );
    return functionType.ok
      ? ok({ type: functionType.value, out: isOut })
      : functionType;
  }

  const typeTok = current(parser);
  if (typeTok.type !== "IDENTIFIER") {
    if (typeTok.type === "TILDE") {
      const vtableTypeResult = parseVTableType(parser);
      if (!vtableTypeResult.ok) {
        return vtableTypeResult;
      }
      return ok({ type: vtableTypeResult.value, out: isOut });
    }
    return err("Expected type annotation");
  }
  const baseType = (typeTok as IdentifierToken).value;
  advance(parser);

  let typeName = baseType;
  if (isGenericListStartToken(current(parser))) {
    if (isGenericTypeParameter(parser, baseType)) {
      return err(
        "Generic type parameter '" + baseType + "' cannot take type arguments",
      );
    }

    const savedPos = parser.pos;
    const typeArgumentsResult = parseTypeArgumentList(parser, resolveAliases);
    if (typeArgumentsResult.ok) {
      const follower = current(parser);
      const validGenericFollower =
        follower.type === "PIPE" ||
        follower.type === "SEMICOLON" ||
        follower.type === "COMMA" ||
        follower.type === "RPAREN" ||
        follower.type === "RBRACKET" ||
        follower.type === "ARROW" ||
        follower.type === "ASSIGN" ||
        follower.type === "LOGICAL" ||
        follower.type === "EOF" ||
        follower.type === "RBRACE" ||
        follower.type === "COLON" ||
        (follower.type === "COMPARISON" && follower.value === ">");

      if (validGenericFollower) {
        typeName = baseType + "<" + typeArgumentsResult.value.join(", ") + ">";
      } else {
        parser.pos = savedPos;
      }
    } else {
      parser.pos = savedPos;
    }
  }

  const normalizedTypeResult = normalizeTypeName(
    parser,
    typeName,
    resolveAliases,
  );
  if (!normalizedTypeResult.ok) {
    return normalizedTypeResult;
  }

  // Construct pointer type string: e.g., "*I32", "*mut I32", "**I32", "*mut *I32"
  const typeResult = parseTrailingUnionType(
    parser,
    applyPointerDecorators(normalizedTypeResult.value, pointerDepth, isMutable),
    resolveAliases,
  );
  return typeResult.ok
    ? ok({ type: typeResult.value, out: isOut })
    : typeResult;
}

export function parseTypeValue(
  parser: Parser,
  resolveAliases: boolean = true,
): Result<string, string> {
  const typeTok = current(parser);

  if (typeTok.type === "TILDE") {
    return parseVTableType(parser);
  }

  if (
    typeTok.type === "LBRACKET" ||
    typeTok.type === "LPAREN" ||
    typeTok.type === "IDENTIFIER" ||
    (typeTok.type === "OPERATOR" && typeTok.value === "*")
  ) {
    const result = parseTypeAnnotation(parser, resolveAliases);
    if (!result.ok) return result;
    parser.pos -= 1;
    return result;
  }

  return err("Expected type");
}

function parseVTableHeader(
  parser: Parser
): Result<VTableHeader, string> {
  const contractTok = current(parser);
  if (contractTok.type !== "IDENTIFIER") {
    return err({
      value: String(contractTok.type),
      message: "Expected contract name after '~'",
      reason: "A vtable type must be written as ~ContractName<ConcreteType>",
      fix: "Write the contract name after '~', e.g. ~Shape<Square>",
    } as unknown as string);
  }
  const contractName = contractTok.value;
  advance(parser);
  const lt = current(parser);
  if (lt.type !== "COMPARISON" || lt.value !== "<") {
    return err({
      value: String(lt.type),
      message: "Expected '<' after contract name in vtable type",
      reason:
        "A vtable type must specify the concrete type: ~ContractName<ConcreteType>",
      fix: "Add '<ConcreteType>' after the contract name, e.g. ~Shape<Square>",
    } as unknown as string);
  }
  advance(parser);
  const concreteTok = current(parser);
  if (concreteTok.type !== "IDENTIFIER") {
    return err({
      value: String(concreteTok.type),
      message: "Expected concrete type name in vtable type",
      reason:
        "A vtable type must specify the concrete type: ~ContractName<ConcreteType>",
      fix: "Provide the concrete type name inside '<>'",
    } as unknown as string);
  }
  const concreteType = concreteTok.value;
  advance(parser);

  // Parse optional contract type arguments: ~Contract<ConcreteType, TypeArg1, TypeArg2>
  const contractTypeArgs: string[] = [];
  while (current(parser).type === "COMMA") {
    advance(parser); // consume comma
    const typeArgResult = parseTypeValue(parser);
    if (!typeArgResult.ok) {
      return typeArgResult;
    }
    advance(parser);
    contractTypeArgs.push(typeArgResult.value);
  }

  const gt = current(parser);
  if (gt.type !== "COMPARISON" || gt.value !== ">") {
    return err({
      value: String(gt.type),
      message: "Expected '>' to close vtable type parameter",
      reason: "A vtable type uses angle brackets: ~ContractName<ConcreteType>",
      fix: "Add '>' after the concrete type name",
    } as unknown as string);
  }
  advance(parser);
  return ok({ contractName, concreteType, contractTypeArgs });
}

export function parseVTableType(parser: Parser): Result<string, string> {
  advance(parser); // consume ~
  const header = parseVTableHeader(parser);
  if (!header.ok) return header;
  const allArgs = [header.value.concreteType, ...header.value.contractTypeArgs];
  return ok("~" + header.value.contractName + "<" + allArgs.join(", ") + ">");
}

export function parseVTableLiteral(parser: Parser): Result<ASTNode, string> {
  advance(parser); // consume ~
  const header = parseVTableHeader(parser);
  if (!header.ok) return header;
  const { contractName, concreteType, contractTypeArgs } = header.value;

  const contractInfo = parser.contracts.get(contractName);
  if (!contractInfo) {
    return err({
      value: contractName,
      message: "Unknown contract '" + contractName + "'",
      reason: "The contract must be declared before creating a vtable for it",
      fix:
        "Declare the contract with 'contract " +
        contractName +
        " { ... }' before this vtable literal",
    } as unknown as string);
  }

  const lbrace = current(parser);
  if (lbrace.type !== "LBRACE") {
    return err({
      value: String(lbrace.type),
      message: "Expected '{' to open vtable literal body",
      reason:
        "A vtable literal body is enclosed in braces: ~Contract<Type> { method: ref; }",
      fix: "Add '{' after the type parameter",
    } as unknown as string);
  }
  advance(parser);

  const entries: VTableLiteralEntry[] = [];
  while (current(parser).type !== "RBRACE") {
    const methodNameTok = current(parser);
    if (methodNameTok.type !== "IDENTIFIER") {
      return err({
        value: String(methodNameTok.type),
        message: "Expected method name in vtable literal entry",
        reason:
          "Each vtable entry maps a contract method to a function reference: methodName : ref;",
        fix: "Provide the method name as an identifier",
      } as unknown as string);
    }
    const methodName = methodNameTok.value;
    advance(parser);

    const colon = current(parser);
    if (colon.type !== "COLON") {
      return err({
        value: String(colon.type),
        message:
          "Expected ':' between method name and reference in vtable entry",
        reason:
          "Vtable entries use the syntax: methodName : ConcreteType::method;",
        fix: "Add ':' after the method name",
      } as unknown as string);
    }
    advance(parser);

    const refResult = parseExpression(parser);
    if (!refResult.ok) {
      return refResult;
    }

    const semicolon = current(parser);
    if (semicolon.type !== "SEMICOLON") {
      return err({
        value: String(semicolon.type),
        message: "Expected ';' after vtable entry",
        reason: "Each vtable entry must be terminated with a semicolon",
        fix: "Add ';' after the method reference expression",
      } as unknown as string);
    }
    advance(parser);

    entries.push({ methodName, reference: refResult.value });
  }
  advance(parser); // consume }

  // Validate all contract methods are covered
  for (const [methodName] of contractInfo.methods) {
    if (!entries.find((e) => e.methodName === methodName)) {
      return err({
        value: methodName,
        message:
          "Vtable literal for '" +
          contractName +
          "' is missing method '" +
          methodName +
          "'",
        reason:
          "A vtable must provide references for every method declared in the contract",
        fix:
          "Add '" +
          methodName +
          " : " +
          concreteType +
          "::" +
          methodName +
          ";' to the vtable literal",
      } as unknown as string);
    }
  }

  return ok({
    kind: "vtable-literal",
    contractName,
    concreteType,
    contractTypeArgs,
    entries,
  });
}

export function getCurrentAliasType(parser: Parser): string | undefined {
  const currentToken = current(parser);
  return currentToken.type === "IDENTIFIER" &&
    parser.aliasDeclarations.has(currentToken.value)
    ? currentToken.value
    : undefined;
}

export function parseTypeReference(
  parser: Parser,
  resolveAliases: boolean = true,
): Result<ParsedTypeReference, string> {
  const aliasType = getCurrentAliasType(parser);

  const typeResult = parseTypeAnnotation(parser, resolveAliases);
  if (!typeResult.ok) {
    return typeResult;
  }

  return ok({
    type: typeResult.value,
    aliasType,
    destructorFunction: aliasType
      ? parser.aliasDestructors.get(aliasType)
      : undefined,
  });
}

export interface ParsedFunctionParameterTypeReference extends ParsedTypeReference {
  out: boolean;
}

export function parseFunctionParameterTypeReference(
  parser: Parser,
  resolveAliases: boolean = true,
): Result<ParsedFunctionParameterTypeReference, string> {
  const aliasType = getCurrentAliasType(parser);

  const typeResult = parseTypeAnnotationInfo(parser, resolveAliases, true);
  if (!typeResult.ok) {
    return typeResult;
  }

  return ok({
    type: typeResult.value.type,
    out: typeResult.value.out,
    aliasType,
    destructorFunction: aliasType
      ? parser.aliasDestructors.get(aliasType)
      : undefined,
  });
}

// Refinement type parsing
export function parseRefinementConstraint(
  parser: Parser,
  baseType: string,
): Result<RefinementConstraint, string> {
  const opTok = current(parser);

  // Check for comparison operator
  if (opTok.type !== "COMPARISON") {
    return err("Expected comparison operator in refinement constraint");
  }

  const operator = opTok.value as "<" | ">" | "<=" | ">=" | "==" | "!=";
  advance(parser);

  // Parse constraint value expression (can be variable, literal, arithmetic, function call, etc.)
  const exprResult = parseAdditive(parser);
  if (!exprResult.ok) {
    return exprResult;
  }

  // For backward compatibility, extract string representation if it's a simple literal
  let value = "?"; // default placeholder
  if (exprResult.value.kind === "number") {
    value = exprResult.value.value;
  } else if (exprResult.value.kind === "variable") {
    value = exprResult.value.name;
  }

  return ok({
    operator,
    value,
    valueExpr: exprResult.value, // Store the full expression
    baseType,
  });
}

// Parse refinement type like "I32 > 100" or "I32 > 0 && I32 < 1000"
export function parseRefinementType(
  parser: Parser,
  baseType: string,
): Result<RefinementType | undefined, string> {
  // Check if next token is a comparison operator (start of refinement)
  const tok = current(parser);
  if (tok.type !== "COMPARISON") {
    // No refinement, just the base type
    return ok(undefined);
  }

  const constraints: RefinementConstraint[] = [];

  // Parse first constraint
  const firstConstraintResult = parseRefinementConstraint(parser, baseType);
  if (!firstConstraintResult.ok) {
    return firstConstraintResult;
  }
  constraints.push(firstConstraintResult.value);

  // Parse additional constraints with && or ||
  while (true) {
    const nextTok = current(parser);
    let isOrOp = false;

    if (nextTok.type === "LOGICAL" && nextTok.value === "&&") {
      advance(parser); // consume &&
      isOrOp = false;
    } else if (nextTok.type === "LOGICAL" && nextTok.value === "||") {
      advance(parser); // consume ||
      isOrOp = true;
    } else {
      // No more constraints
      break;
    }

    // Expect another base type identifier
    const typeTok = current(parser);
    if (typeTok.type !== "IDENTIFIER") {
      return err("Expected type in chained constraint");
    }
    const nextBaseType = typeTok.value;
    if (nextBaseType !== baseType) {
      const opType = isOrOp ? "OR" : "AND";
      return err(
        "All constraints in " + opType + " must reference the same base type",
      );
    }
    advance(parser); // consume type identifier

    const constraintResult = parseRefinementConstraint(parser, baseType);
    if (!constraintResult.ok) {
      return constraintResult;
    }
    // Mark with appropriate operator
    constraintResult.value.isOr = isOrOp;
    constraints.push(constraintResult.value);
  }

  return ok({
    baseType,
    constraints,
  });
}

export function splitNumberLiteral(value: string): ParsedNumberLiteral {
  let pos = 0;

  if (value[pos] === "-") {
    pos++;
  }

  while (pos < value.length && isDigit(value[pos])) {
    pos++;
  }

  if (value[pos] === ".") {
    pos++;
    while (pos < value.length && isDigit(value[pos])) {
      pos++;
    }
  }

  return {
    numericPart: value.slice(0, pos),
    typeAnnotation: value.slice(pos),
  };
}

export function isBareNonNegativeIntegerLiteral(value: string): boolean {
  const numericPart = splitNumberLiteral(value).numericPart;
  if (numericPart.length === 0) {
    return false;
  }

  for (const char of numericPart) {
    if (char < "0" || char > "9") {
      return false;
    }
  }

  return true;
}

export function parseArrayType(typeStr: string): ParsedArrayType | undefined {
  const parts = getBracketedTypeParts(typeStr);
  if (!parts) {
    return undefined;
  }

  if (parts.length !== 2) {
    return undefined;
  }

  const length = Number(parts[1]);
  if (!Number.isInteger(length)) {
    return undefined;
  }

  return {
    elementType: parts[0] ?? "",
    length,
  };
}

export function parseSliceType(typeStr: string): ParsedSliceType | undefined {
  const parts = getBracketedTypeParts(typeStr);
  if (!parts) {
    return undefined;
  }
  if (parts.length !== 1) {
    return undefined;
  }

  const elementType = (parts[0] ?? "").trim();
  return elementType.length === 0 ? undefined : { elementType };
}

export function parseSliceReferenceType(
  typeStr: string,
): ParsedSliceReferenceType | undefined {
  if (typeStr.startsWith("*mut ")) {
    const sliceType = parseSliceType(typeStr.slice(5));
    return sliceType
      ? { elementType: sliceType.elementType, mutable: true }
      : undefined;
  }

  if (typeStr.startsWith("*")) {
    const sliceType = parseSliceType(typeStr.slice(1));
    return sliceType
      ? { elementType: sliceType.elementType, mutable: false }
      : undefined;
  }

  return undefined;
}

export function getArrayLikeInfo(
  node: ASTNode,
  parser: Parser,
): ArrayLikeInfo | undefined {
  if (node.kind === "string") {
    return {
      elementType: "Char",
      length: node.value.length,
      mutable: false,
      isSlice: true,
    };
  }

  if (node.kind === "array-slice") {
    const arrayInfo = getArrayLikeInfo(node.array, parser);
    if (!arrayInfo) {
      return undefined;
    }

    return {
      elementType: arrayInfo.elementType,
      length: node.end - node.start,
      mutable: arrayInfo.mutable,
      isSlice: true,
    };
  }

  if (node.kind !== "variable") {
    const inferredType = inferExpressionType(node, parser);
    if (!inferredType.ok) {
      return undefined;
    }

    const inferredArrayType = parseArrayType(inferredType.value);
    if (inferredArrayType) {
      return {
        elementType: inferredArrayType.elementType,
        length: inferredArrayType.length,
        mutable: false,
        isSlice: false,
      };
    }

    const inferredSliceType = parseSliceReferenceType(inferredType.value);
    if (inferredSliceType) {
      return {
        elementType: inferredSliceType.elementType,
        length: undefined,
        mutable: inferredSliceType.mutable,
        isSlice: true,
      };
    }

    return undefined;
  }

  const varInfo = parser.variables.get(node.name);
  if (!varInfo) {
    return undefined;
  }

  const fixedArrayType = parseArrayType(varInfo.type);
  if (fixedArrayType) {
    return {
      elementType: fixedArrayType.elementType,
      length: fixedArrayType.length,
      mutable: varInfo.mutable,
      isSlice: false,
    };
  }

  const sliceReferenceType = parseSliceReferenceType(varInfo.type);
  if (sliceReferenceType) {
    return {
      elementType: sliceReferenceType.elementType,
      length: varInfo.sliceLength,
      mutable: sliceReferenceType.mutable,
      isSlice: true,
    };
  }

  return undefined;
}

export function getSliceLengthFromInitializer(
  initializer: ASTNode,
  parser: Parser,
): number | undefined {
  if (
    initializer.kind === "unary-op" &&
    (initializer.operator === "&" || initializer.operator === "&mut")
  ) {
    return getSliceLengthFromInitializer(initializer.operand, parser);
  }

  if (initializer.kind === "string") {
    return initializer.value.length;
  }

  const arrayInfo = getArrayLikeInfo(initializer, parser);
  return arrayInfo?.length;
}

export function createArrayLengthConstraintExpr(
  arrayNode: ASTNode,
  arrayInfo: ArrayLikeInfo,
): ASTNode {
  if (arrayInfo.length !== undefined) {
    return {
      kind: "number",
      value: String(arrayInfo.length),
    };
  }

  return {
    kind: "field-access",
    object: arrayNode,
    fieldName: "length",
  } as FieldAccessNode;
}

export function createRequiredArrayIndexRefinement(
  arrayNode: ASTNode,
  arrayInfo: ArrayLikeInfo,
): RefinementType {
  const valueExpr = createArrayLengthConstraintExpr(arrayNode, arrayInfo);
  return {
    baseType: "USize",
    constraints: [
      {
        operator: "<",
        value: valueExpr.kind === "number" ? valueExpr.value : "?",
        valueExpr,
        baseType: "USize",
      },
    ],
  };
}

export function hasProvenArrayIndexRefinement(
  parser: Parser,
  indexName: string,
  requiredRefinement: RefinementType,
): boolean {
  const variableInfo = parser.variables.get(indexName);
  if (
    variableInfo?.refinement &&
    satisfiesRefinementConstraints(
      variableInfo.refinement,
      requiredRefinement,
      parser,
    )
  ) {
    return true;
  }

  const provenRefinement = parser.provenConstraints.get(indexName);
  return provenRefinement
    ? satisfiesRefinementConstraints(
        provenRefinement,
        requiredRefinement,
        parser,
      )
    : false;
}

export function validateArrayIndexAccess(
  parser: Parser,
  arrayNode: ASTNode,
  indexNode: ASTNode,
  arrayInfo: ArrayLikeInfo | undefined,
): Result<void, string> {
  if (indexNode.kind === "number") {
    const bareNum = splitNumberLiteral(indexNode.value).numericPart;
    if (bareNum.startsWith("-")) {
      return err("Array index must be non-negative");
    }
    if (bareNum.includes(".")) {
      return err("Array index must be an integer type, got float");
    }
    if (!arrayInfo || arrayInfo.length === undefined) {
      return err(
        "Array index must be proven in bounds; literal index requires known compile-time length",
      );
    }

    const idxVal = parseFloat(bareNum);
    if (idxVal >= arrayInfo.length) {
      return err(
        "Array index " +
          idxVal +
          " is out of bounds for array of length " +
          arrayInfo.length +
          ")",
      );
    }

    return ok(undefined);
  }

  if (indexNode.kind !== "variable") {
    return err("Array index must be a USize value proven to be < array.length");
  }

  const indexInfo = getVariable(parser, indexNode.name);
  if (!indexInfo.ok) {
    return indexInfo;
  }

  const normalizedType = normalizeTypeName(parser, indexInfo.value.type, true);
  if (!normalizedType.ok) {
    return normalizedType;
  }

  if (normalizedType.value !== "USize") {
    return err("Array index must be a USize, got " + indexInfo.value.type);
  }

  if (!arrayInfo) {
    return err("Cannot index non-array value");
  }

  const requiredRefinement = createRequiredArrayIndexRefinement(
    arrayNode,
    arrayInfo,
  );
  if (
    !hasProvenArrayIndexRefinement(parser, indexNode.name, requiredRefinement)
  ) {
    return err(
      "Array index variable '" +
        indexNode.name +
        "' must be proven to satisfy USize < array.length",
    );
  }

  return ok(undefined);
}

export function inferZeroArgCallableReturnType(
  expr: ASTNode,
  parser: Parser,
): Result<string, string> {
  if (expr.kind === "closure") {
    if (expr.parameters.length !== 0) {
      return err("Array generator must be a zero-argument callable");
    }
    return ok(expr.returnType);
  }

  if (expr.kind === "variable") {
    const fnInfo = parser.functions.get(expr.name);
    if (fnInfo) {
      if (fnInfo.parameters.length !== 0) {
        return err("Array generator must be a zero-argument callable");
      }
      return ok(fnInfo.returnType);
    }

    const varResult = getVariable(parser, expr.name);
    if (!varResult.ok) {
      return err(
        "Array generator '" + expr.name + "' is not a function or closure",
      );
    }

    const parsedFunctionType = parseCallableTypeString(varResult.value.type);
    if (!parsedFunctionType) {
      return err(
        "Array generator '" + expr.name + "' is not a function or closure",
      );
    }
    if (parsedFunctionType.parameterTypes.length !== 0) {
      return err("Array generator must be a zero-argument callable");
    }
    return ok(parsedFunctionType.returnType);
  }

  const exprTypeResult = inferExpressionType(expr, parser);
  if (!exprTypeResult.ok) {
    return err("Array generator must be a function or closure");
  }

  const parsedFunctionType = parseCallableTypeString(exprTypeResult.value);
  if (!parsedFunctionType) {
    return err("Array generator must be a function or closure");
  }
  if (parsedFunctionType.parameterTypes.length !== 0) {
    return err("Array generator must be a zero-argument callable");
  }
  return ok(parsedFunctionType.returnType);
}

export function current(parser: Parser): Token {
  if (parser.pos < parser.tokens.length) {
    const tok = parser.tokens[parser.pos];
    return tok || { type: "EOF" };
  }
  return { type: "EOF" };
}

export function advance(parser: Parser): void {
  parser.pos++;
}

// Helper to parse compound assignment operators
export function parseCompoundAssignmentOperator(
  parser: Parser,
): Result<AssignmentOperatorInfo, string> {
  const compoundOperators = new Set([
    "PLUS_ASSIGN",
    "MINUS_ASSIGN",
    "MULT_ASSIGN",
    "DIV_ASSIGN",
    "MOD_ASSIGN",
  ]);

  const tok = current(parser);
  if (compoundOperators.has(tok.type)) {
    const operatorMap: Record<string, "+" | "-" | "*" | "/" | "%"> = {
      PLUS_ASSIGN: "+",
      MINUS_ASSIGN: "-",
      MULT_ASSIGN: "*",
      DIV_ASSIGN: "/",
      MOD_ASSIGN: "%",
    };
    const operator = operatorMap[tok.type] || "+";
    advance(parser);
    return ok({ isCompound: true, operator });
  } else if (tok.type === "ASSIGN") {
    advance(parser);
    return ok({ isCompound: false, operator: "+" });
  } else {
    return err("Expected assignment operator");
  }
}

// Helper to check for 'mut' keyword and consume if present
export function tryConsumeMutKeyword(parser: Parser): boolean {
  if (
    current(parser).type === "KEYWORD" &&
    (current(parser) as KeywordToken).value === "mut"
  ) {
    advance(parser);
    return true;
  }
  return false;
}

// Helper to try parsing assignment operator and validate format
export function tryParseAndValidateAssignmentOperator(
  parser: Parser,
  savedPos: number,
): Result<AssignmentOperatorInfo | undefined, string> {
  const assignOpResult = parseCompoundAssignmentOperator(parser);
  if (!assignOpResult.ok) {
    // Not an assignment, restore position
    parser.pos = savedPos;
    return ok(undefined);
  }
  return ok(assignOpResult.value);
}

export function withParsedAssignmentOperator<T>(
  parser: Parser,
  savedPos: number,
  handler: CallableFunction,
): Result<T | undefined, string> {
  const assignOpResult = tryParseAndValidateAssignmentOperator(
    parser,
    savedPos,
  );
  if (!assignOpResult.ok) {
    return assignOpResult;
  }
  if (!assignOpResult.value) {
    return ok(undefined);
  }

  return handler(assignOpResult.value) as Result<T, string>;
}

export function parseAssignmentValue(
  parser: Parser,
  isCompound: boolean,
  operator: "+" | "-" | "*" | "/" | "%",
  lvalue: ASTNode,
): Result<ASTNode, string> {
  const valueResult = parseExpression(parser);
  if (!valueResult.ok) {
    return valueResult;
  }

  let assignValue = valueResult.value;

  // For compound assignments, wrap in a binary operation
  if (isCompound) {
    const binaryNode: BinaryNode = {
      kind: "binary",
      left: lvalue,
      operator,
      right: valueResult.value,
    };
    assignValue = binaryNode;
  }

  if (!isCompound) {
    const movedValue = maybeMoveExpression(parser, assignValue);
    if (!movedValue.ok) {
      return movedValue;
    }
    assignValue = movedValue.value;
  }

  return ok(assignValue);
}

export function validateThisAssignmentTarget(
  lvalue: FieldAccessNode,
): Result<undefined, string> {
  const resolvedThisMember = resolveThisMemberAccess(lvalue);
  if (!resolvedThisMember.ok) {
    return resolvedThisMember;
  }

  if (!resolvedThisMember.value) {
    return ok(undefined);
  }

  if (resolvedThisMember.value.binding.kind !== "variable") {
    return err(
      "Member '" + resolvedThisMember.value.memberName + "' is not assignable",
    );
  }

  if (!resolvedThisMember.value.binding.assignable) {
    return err(
      "Member '" + resolvedThisMember.value.memberName + "' is read-only",
    );
  }

  return ok(undefined);
}

export function handleAssignmentStatement(
  assignResult: Result<ASTNode | undefined, string>,
  parser: Parser,
  statements: ASTNode[],
): Result<boolean, string> {
  if (!assignResult.ok) {
    return assignResult;
  }

  if (assignResult.value !== undefined) {
    statements.push(assignResult.value);
    consumeOptionalSemicolon(parser);
    return ok(true);
  } else {
    // Not an assignment
    return ok(false);
  }
}

export function parseBlockResultExpression(
  parser: Parser,
  statements: ASTNode[],
): Result<BlockNode, string> {
  const exprResult = parseExpression(parser);
  if (!exprResult.ok) {
    return exprResult;
  }

  return ok({ kind: "block", statements, result: exprResult.value });
}

export function tryParseAssignment(
  parser: Parser,
): Result<ASTNode | undefined, string> {
  const tok = current(parser);

  // Handle dereference assignment: *y = value (or *y += value, etc.)
  if (tok.type === "OPERATOR" && tok.value === "*") {
    const savedPos = parser.pos;

    // Try to parse: parseUnary() then check for assignment operator
    const unaryResult = parseUnary(parser);
    if (!unaryResult.ok) {
      parser.pos = savedPos;
      return ok(undefined);
    }

    return withParsedAssignmentOperator(
      parser,
      savedPos,
      (assignOp: AssignmentOperatorInfo) => {
        const { isCompound, operator } = assignOp;

        // Validate that we're assigning to a dereference
        const lvalue = unaryResult.value;
        if (lvalue.kind !== "unary-op" || lvalue.operator !== "*") {
          parser.pos = savedPos;
          return ok(undefined as never);
        }

        // Validate that the pointer is mutable
        const ptrTypeResult = inferExpressionType(lvalue.operand, parser);
        if (!ptrTypeResult.ok) {
          return ptrTypeResult as Result<never, string>;
        }
        const ptrType = ptrTypeResult.value;
        if (!ptrType.startsWith("*mut ")) {
          return err("Cannot assign through immutable pointer") as Result<
            never,
            string
          >;
        }

        const assignValueResult = parseAssignmentValue(
          parser,
          isCompound,
          operator,
          lvalue,
        );
        if (!assignValueResult.ok) {
          return assignValueResult as Result<never, string>;
        }
        const assignValue = assignValueResult.value;

        // Track which variable the pointer points to (for runtime assignment)
        let targetVar: string | undefined;
        if (lvalue.operand.kind === "variable") {
          const ptrVarName = lvalue.operand.name;
          const ptrVarInfo = parser.variables.get(ptrVarName);
          if (ptrVarInfo && ptrVarInfo.pointsTo) {
            targetVar = ptrVarInfo.pointsTo;
          }
        }

        return ok({
          kind: "deref-assign",
          target: lvalue.operand,
          value: assignValue,
          targetVar,
        } as DerefAssignNode);
      },
    );
  }

  // Try to parse as a postfix expression (could be array access: arr[index])
  // Save position in case it's not an assignment
  const savedPos = parser.pos;

  // Try to parse a postfix expression to check if it's array access or field access
  const postfixResult = parsePostfix(parser);
  if (postfixResult.ok) {
    const lvalue = postfixResult.value;

    // Check if this is array access or field access that could be assigned to
    if (lvalue.kind === "array-access" || lvalue.kind === "field-access") {
      return withParsedAssignmentOperator(
        parser,
        savedPos,
        (assignOp: AssignmentOperatorInfo) => {
          const { isCompound, operator } = assignOp;
          const assignValueResult = parseAssignmentValue(
            parser,
            isCompound,
            operator,
            lvalue,
          );
          if (!assignValueResult.ok) {
            return assignValueResult as Result<never, string>;
          }

          if (lvalue.kind === "array-access") {
            const arrayInfo = getArrayLikeInfo(lvalue.array, parser);

            if (lvalue.array.kind === "variable") {
              const arrayVar = parser.variables.get(lvalue.array.name);
              const sliceReferenceType = arrayVar
                ? parseSliceReferenceType(arrayVar.type)
                : undefined;
              const isWritable = sliceReferenceType
                ? sliceReferenceType.mutable
                : arrayVar?.mutable;

              if (!isWritable) {
                return err(
                  "Cannot modify elements of immutable array '" +
                    lvalue.array.name +
                    "'",
                ) as Result<never, string>;
              }
            }

            if (arrayInfo) {
              const elemType = arrayInfo.elementType;

              const indexValidation = validateArrayIndexAccess(
                parser,
                lvalue.array,
                lvalue.index,
                arrayInfo,
              );
              if (!indexValidation.ok) {
                return indexValidation as Result<never, string>;
              }

              if (!elemType.startsWith("[")) {
                const assignedValue = assignValueResult.value;
                if (
                  assignedValue.kind === "number" &&
                  splitNumberLiteral(assignedValue.value).numericPart.includes(
                    ".",
                  )
                ) {
                  if (!elemType.startsWith("F")) {
                    return err(
                      "Type mismatch in array element assignment: expected " +
                        elemType +
                        " but got float literal",
                    ) as Result<never, string>;
                  }
                }

                const assignedTypeResult = inferExpressionType(
                  assignedValue,
                  parser,
                );
                if (assignedTypeResult.ok) {
                  const assignedType = assignedTypeResult.value;
                  const bothFloat =
                    elemType.startsWith("F") && assignedType.startsWith("F");
                  const bothInt =
                    !elemType.startsWith("F") && !assignedType.startsWith("F");
                  if (assignedType !== elemType && !bothFloat && !bothInt) {
                    return err(
                      "Type mismatch in array element assignment: expected " +
                        elemType +
                        " but got " +
                        assignedType,
                    ) as Result<never, string>;
                  }
                  if (
                    !elemType.startsWith("F") &&
                    assignedType.startsWith("F")
                  ) {
                    return err(
                      "Type mismatch in array element assignment: expected " +
                        elemType +
                        " but got " +
                        assignedType,
                    ) as Result<never, string>;
                  }
                } else if (
                  assignedValue.kind === "number" &&
                  assignedValue.value.includes(".") &&
                  !elemType.startsWith("F")
                ) {
                  return err(
                    "Type mismatch in array element assignment: expected " +
                      elemType +
                      " but got float literal",
                  ) as Result<never, string>;
                }
              }
            }

            return ok({
              kind: "array-assign",
              array: lvalue.array,
              index: lvalue.index,
              value: assignValueResult.value,
            } as ArrayAssignNode) as Result<never, string>;
          }

          const thisAssignmentValidation = validateThisAssignmentTarget(lvalue);
          if (!thisAssignmentValidation.ok) {
            return thisAssignmentValidation as Result<never, string>;
          }

          return ok({
            kind: "field-assign",
            object: lvalue.object,
            fieldName: lvalue.fieldName,
            value: assignValueResult.value,
          } as FieldAssignNode) as Result<never, string>;
        },
      );
    }
  }

  // Restore position and try identifier-based assignment
  parser.pos = savedPos;

  if (tok.type !== "IDENTIFIER") {
    return ok(undefined);
  }

  const name = tok.value;
  advance(parser);

  const nextTok = current(parser);

  // Check if it's a field assignment (object.field(.field...)* = value)
  if (nextTok.type === "DOT") {
    // Collect dot-access chain: ident.a.b.c = value
    // We need to parse all but the last segment as field-access, last as field-assign
    let objNode: ASTNode = { kind: "variable", name };
    advance(parser); // consume first DOT

    const fieldTok = current(parser);
    if (fieldTok.type !== "IDENTIFIER") {
      parser.pos = savedPos;
      return ok(undefined);
    }
    let fieldName = fieldTok.value;
    advance(parser);

    // Consume additional dots (a.b.c = ...)
    while (current(parser).type === "DOT") {
      // The current fieldName becomes an access on objNode
      objNode = {
        kind: "field-access",
        object: objNode,
        fieldName,
      } as FieldAccessNode;
      advance(parser); // consume DOT
      const nextFieldTok = current(parser);
      if (nextFieldTok.type !== "IDENTIFIER") {
        parser.pos = savedPos;
        return ok(undefined);
      }
      fieldName = nextFieldTok.value;
      advance(parser);
    }

    const assignOpTok = current(parser);
    if (assignOpTok.type !== "ASSIGN") {
      parser.pos = savedPos;
      return ok(undefined);
    }
    advance(parser); // consume ASSIGN

    const valueResult = parseExpression(parser);
    if (!valueResult.ok) {
      return valueResult;
    }

    const thisAssignmentValidation = validateThisAssignmentTarget({
      kind: "field-access",
      object: objNode,
      fieldName,
    });
    if (!thisAssignmentValidation.ok) {
      return thisAssignmentValidation;
    }

    return ok({
      kind: "field-assign",
      object: objNode,
      fieldName,
      value: valueResult.value,
    } as FieldAssignNode);
  }

  return withParsedAssignmentOperator(
    parser,
    savedPos,
    (assignOp: AssignmentOperatorInfo) => {
      const { isCompound, operator } = assignOp;

      const varResult = getVariable(parser, name);
      if (!varResult.ok) {
        return varResult as Result<never, string>;
      }
      if (!varResult.value.mutable) {
        return err(
          "Variable '" + name + "' is immutable and cannot be reassigned",
        ) as Result<never, string>;
      }

      const varLvalue: VariableNode = { kind: "variable", name };
      const assignValueResult = parseAssignmentValue(
        parser,
        isCompound,
        operator,
        varLvalue,
      );
      if (!assignValueResult.ok) {
        return assignValueResult as Result<never, string>;
      }
      const assignValue = assignValueResult.value;

      const assignedMetadata = getExpressionInstanceMetadata(
        parser,
        assignValue,
      );
      if (!assignedMetadata.ok) {
        return assignedMetadata as Result<never, string>;
      }
      const existingVarInfo = parser.variables.get(name);
      if (existingVarInfo) {
        existingVarInfo.instanceMetadata = cloneOptionalInstanceMetadata(
          assignedMetadata.value,
        );
      }

      return ok({
        kind: "assign",
        name,
        value: assignValue,
      });
    },
  );
}

export function consumeOptionalSemicolon(parser: Parser): void {
  if (current(parser).type === "SEMICOLON") {
    advance(parser);
  }
}

export function parseLifetimeBlockMembers(
  parser: Parser,
  statements: ASTNode[],
): Result<void, string> {
  while (true) {
    const token = current(parser);
    if (token.type === "EOF" || token.type === "RBRACE") {
      return ok(undefined);
    }

    if (token.type === "KEYWORD" && token.value === "extern") {
      const externStatement = parseExternStatement(parser);
      if (!externStatement.ok) {
        return externStatement;
      }
      statements.push(externStatement.value);
      continue;
    }

    if (token.type === "KEYWORD" && token.value === "type") {
      const aliasStatement = parseTypeAliasStatement(parser);
      if (!aliasStatement.ok) {
        return aliasStatement;
      }
      statements.push(aliasStatement.value);
      continue;
    }

    if (token.type === "KEYWORD" && token.value === "contract") {
      const contractStatement = parseContractStatement(parser);
      if (!contractStatement.ok) {
        return contractStatement;
      }
      statements.push(contractStatement.value);
      continue;
    }

    if (token.type === "KEYWORD" && token.value === "fn") {
      const functionStatement = parseFunctionStatement(parser);
      if (!functionStatement.ok) {
        return functionStatement;
      }
      statements.push(functionStatement.value);
      continue;
    }

    if (token.type === "KEYWORD" && token.value === "object") {
      const objectStatement = parseObjectStatement(parser);
      if (!objectStatement.ok) {
        return objectStatement;
      }
      statements.push(objectStatement.value);
      continue;
    }

    if (token.type === "KEYWORD" && token.value === "struct") {
      const structStatement = parseStructStatement(parser);
      if (!structStatement.ok) {
        return structStatement;
      }
      statements.push(structStatement.value);
      continue;
    }

    if (token.type === "KEYWORD" && token.value === "lifetime") {
      const nestedLifetimeStatements = parseLifetimeStatement(parser);
      if (!nestedLifetimeStatements.ok) {
        return nestedLifetimeStatements;
      }
      statements.push(...nestedLifetimeStatements.value);
      continue;
    }

    return err("Lifetime blocks only support declarations");
  }
}

export function parseLifetimeStatement(
  parser: Parser,
): Result<ASTNode[], string> {
  const scopeEntry = parseAndEnterLifetimeScope(parser);
  if (!scopeEntry.ok) {
    return scopeEntry;
  }

  const statements: ASTNode[] = [];
  const blockResult = parseLifetimeBlockMembers(parser, statements);
  if (!blockResult.ok) {
    exitLifetimeScope(parser);
    return blockResult;
  }

  if (current(parser).type !== "RBRACE") {
    exitLifetimeScope(parser);
    return err("Expected '}' after lifetime block");
  }
  advance(parser);
  exitLifetimeScope(parser);

  return ok(statements);
}

export function parseStatementBlock(
  parser: Parser,
  statements: ASTNode[],
  stopOnRbrace: boolean = true,
): Result<void, string> {
  while (true) {
    const tok = current(parser);
    if (tok.type === "EOF" || (stopOnRbrace && tok.type === "RBRACE")) {
      break;
    }

    const stmtResult = parseStatementInBlock(parser, statements);
    if (!stmtResult.ok) {
      return stmtResult;
    }

    if (!stmtResult.value) {
      // Not a statement, break to parse expression
      break;
    }
  }
  return ok(undefined);
}

export function parseStatementInBlock(
  parser: Parser,
  statements: ASTNode[],
): Result<boolean, string> {
  const stmtTok = current(parser);

  if (stmtTok.type === "KEYWORD" && stmtTok.value === "lifetime") {
    const lifetimeStatements = parseLifetimeStatement(parser);
    if (!lifetimeStatements.ok) {
      return lifetimeStatements;
    }
    statements.push(...lifetimeStatements.value);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "extern") {
    const externStmt = parseExternStatement(parser);
    if (!externStmt.ok) {
      return externStmt;
    }
    statements.push(externStmt.value);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "let") {
    const stmt = parseLetStatement(parser);
    if (!stmt.ok) {
      return stmt;
    }
    statements.push(stmt.value);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "type") {
    const aliasStmt = parseTypeAliasStatement(parser);
    if (!aliasStmt.ok) {
      return aliasStmt;
    }
    statements.push(aliasStmt.value);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "contract") {
    const contractStmt = parseContractStatement(parser);
    if (!contractStmt.ok) {
      return contractStmt;
    }
    statements.push(contractStmt.value);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "fn") {
    // Function declaration
    const fnStmt = parseFunctionStatement(parser);
    if (!fnStmt.ok) {
      return fnStmt;
    }
    statements.push(fnStmt.value);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "object") {
    const objectStmt = parseObjectStatement(parser);
    if (!objectStmt.ok) {
      return objectStmt;
    }
    statements.push(objectStmt.value);
    return ok(true);
  } else if (
    stmtTok.type === "KEYWORD" &&
    (stmtTok as KeywordToken).value === "struct"
  ) {
    // Struct declaration
    const structStmt = parseStructStatement(parser);
    if (!structStmt.ok) {
      return structStmt;
    }
    statements.push(structStmt.value);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "if") {
    // Nested if statement
    const ifStmt = parseIfStatement(parser);
    if (!ifStmt.ok) {
      return ifStmt;
    }
    statements.push(ifStmt.value);
    consumeOptionalSemicolon(parser);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "while") {
    // While loop statement
    const whileStmt = parseWhileStatement(parser);
    if (!whileStmt.ok) {
      return whileStmt;
    }
    statements.push(whileStmt.value);
    consumeOptionalSemicolon(parser);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "break") {
    // Break statement
    const breakStmt = parseBreakStatement(parser);
    if (!breakStmt.ok) {
      return breakStmt;
    }
    statements.push(breakStmt.value);
    consumeOptionalSemicolon(parser);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "continue") {
    // Continue statement
    const continueStmt = parseContinueStatement(parser);
    if (!continueStmt.ok) {
      return continueStmt;
    }
    statements.push(continueStmt.value);
    consumeOptionalSemicolon(parser);
    return ok(true);
  } else if (stmtTok.type === "KEYWORD" && stmtTok.value === "return") {
    // Return statement
    const returnStmt = parseReturnStatement(parser);
    if (!returnStmt.ok) {
      return returnStmt;
    }
    statements.push(returnStmt.value);
    consumeOptionalSemicolon(parser);
    return ok(true);
  } else if (
    stmtTok.type === "IDENTIFIER" ||
    (stmtTok.type === "KEYWORD" && stmtTok.value === "this") ||
    (stmtTok.type === "OPERATOR" && stmtTok.value === "*")
  ) {
    // Could be assignment - use helper
    const assignResult = tryParseAssignment(parser);
    const assignmentHandled = handleAssignmentStatement(
      assignResult,
      parser,
      statements,
    );
    if (!assignmentHandled.ok || assignmentHandled.value) {
      return assignmentHandled;
    }

    const savedPos = parser.pos;
    const exprResult = parseExpression(parser);
    if (!exprResult.ok) {
      parser.pos = savedPos;
      return ok(false);
    }
    if (
      (exprResult.value.kind === "function-call" ||
        exprResult.value.kind === "call") &&
      current(parser).type === "SEMICOLON"
    ) {
      statements.push(exprResult.value);
      consumeOptionalSemicolon(parser);
      return ok(true);
    }

    parser.pos = savedPos;
    return ok(false);
  } else {
    return ok(false);
  }
}

export function isBooleanNode(node: ASTNode): boolean {
  return (
    node.kind === "boolean" ||
    node.kind === "is" ||
    node.kind === "comparison" ||
    node.kind === "logical" ||
    node.kind === "unary-logical"
  );
}

export function validateBooleanCondition(
  node: ASTNode,
  parser?: Parser,
): Result<undefined, string> {
  // Allow boolean literals directly
  if (node.kind === "boolean") {
    return ok(undefined);
  }

  // Allow integer literals 1/0 as boolean (truthy/falsy constants)
  if (node.kind === "number") {
    const numericPart = splitNumberLiteral(node.value).numericPart;
    const numStr = numericPart.startsWith("-")
      ? numericPart.slice(1)
      : numericPart;
    // Must be 0 or 1 (without type suffix)
    if (numStr === "0" || numStr === "1") {
      return ok(undefined);
    }
    return err("Condition must be a boolean expression");
  }

  // Allow variable references only if they have Bool type
  if (node.kind === "variable") {
    if (parser) {
      const varInfo = parser.variables.get(node.name);
      if (varInfo && varInfo.type !== "Bool") {
        return err("Condition must be a boolean expression");
      }
    }
    return ok(undefined);
  }

  if (
    node.kind === "function-call" ||
    node.kind === "if" ||
    node.kind === "match"
  ) {
    return ok(undefined);
  }

  if (!isBooleanNode(node)) {
    return err("Condition must be a boolean expression");
  }

  return ok(undefined);
}

/**
 * Parses a condition expression, with optional surrounding parentheses.
 * If the next token is '(', parens are consumed; otherwise the expression
 * is parsed directly. The condition is validated as a boolean expression.
 */
export function parseConditionExpression(
  parser: Parser,
): Result<ASTNode, string> {
  const hasParen = current(parser).type === "LPAREN";

  if (hasParen) {
    advance(parser); // consume '('
  }

  const conditionResult = parseExpression(parser);
  if (!conditionResult.ok) {
    return conditionResult;
  }

  if (hasParen) {
    if (current(parser).type !== "RPAREN") {
      return err("Expected ')'");
    }
    advance(parser); // consume ')'
  }

  const boolCheck = validateBooleanCondition(conditionResult.value, parser);
  if (!boolCheck.ok) {
    return boolCheck;
  }

  return conditionResult;
}

export function parseBlockStatements(
  parser: Parser,
): Result<ASTNode[], string> {
  const stmtsResult = parseBlockStatementsInternal(parser);
  if (!stmtsResult.ok) {
    return stmtsResult;
  }

  // Expect '}'
  if (current(parser).type !== "RBRACE") {
    return err("Expected '}'");
  }
  advance(parser);

  return stmtsResult;
}

// Internal helper to parse block statements without consuming RBRACE (for if/else with final expressions)
export function parseBlockStatementsWithoutRbrace(
  parser: Parser,
): Result<ASTNode[], string> {
  return parseBlockStatementsInternal(parser);
}

// Shared internal implementation for parsing block statements
export function parseBlockStatementsInternal(
  parser: Parser,
): Result<ASTNode[], string> {
  // Expect '{'
  if (current(parser).type !== "LBRACE") {
    return err("Expected '{'");
  }
  advance(parser);

  const statements: ASTNode[] = [];
  const blockResult = parseStatementBlock(parser, statements);
  if (!blockResult.ok) {
    return blockResult;
  }

  return ok(statements);
}

// Helper: extract the last if/match as result if it exists
export function extractFinalExpressionIfPresent(
  statements: ASTNode[],
): ASTNode | undefined {
  if (statements.length === 0) {
    return undefined;
  }

  const lastStmt = statements[statements.length - 1];
  if (
    lastStmt &&
    (lastStmt.kind === "match" ||
      (lastStmt.kind === "if" && lastStmt.elseBranch !== undefined))
  ) {
    return lastStmt;
  }

  return undefined;
}

export function createBlockBodyWithOptionalExpression(
  statements: ASTNode[],
  parser: Parser,
): Result<ASTNode, string> {
  const resultTok = current(parser);

  // Check if at end of block
  if (resultTok.type === "RBRACE" || resultTok.type === "EOF") {
    const finalExpr = extractFinalExpressionIfPresent(statements);
    if (finalExpr) {
      statements.pop();
      return ok({
        kind: "block",
        statements,
        result: finalExpr,
      });
    }
    return ok({
      kind: "block",
      statements,
      result: { kind: "number", value: "0" },
    });
  }

  // Check if it's a non-expression keyword
  const nonExprKeywords = new Set([
    "let",
    "lifetime",
    "contract",
    "type",
    "fn",
    "struct",
    "while",
    "break",
    "continue",
    "return",
  ]);

  if (resultTok.type === "KEYWORD" && nonExprKeywords.has(resultTok.value)) {
    return ok({
      kind: "block",
      statements,
      result: { kind: "number", value: "0" },
    });
  }

  // For IDENTIFIER, check if it's followed by assignment or is a bare variable ref
  if (resultTok.type === "IDENTIFIER") {
    const nextIdx = parser.pos + 1;
    const nextTok =
      nextIdx < parser.tokens.length ? parser.tokens[nextIdx] : undefined;

    const assignmentOps = new Set([
      "ASSIGN",
      "PLUS_ASSIGN",
      "MINUS_ASSIGN",
      "MULT_ASSIGN",
      "DIV_ASSIGN",
      "MOD_ASSIGN",
    ]);

    // If it's an assignment, no final expression
    if (nextTok && assignmentOps.has(nextTok.type)) {
      return ok({
        kind: "block",
        statements,
        result: { kind: "number", value: "0" },
      });
    }

    // If followed by '[' or '.', parse full postfix expression (e.g. arr[0] or obj.field)
    if (nextTok && (nextTok.type === "LBRACKET" || nextTok.type === "DOT")) {
      return parseBlockResultExpression(parser, statements);
    }

    // It's a variable reference - parse it as primary (just the identifier)
    const varName = resultTok.value;
    advance(parser);

    // Check if variable exists
    const varResult = getVariable(parser, varName);
    if (!varResult.ok) {
      return varResult;
    }

    return ok({
      kind: "block",
      statements,
      result: { kind: "variable", name: varName },
    });
  }

  // Try to parse other expression types (NUMBER, BOOL, LPAREN, if, match)
  if (
    resultTok.type === "NUMBER" ||
    resultTok.type === "BOOL" ||
    resultTok.type === "CHAR" ||
    resultTok.type === "STRING" ||
    resultTok.type === "LPAREN" ||
    (resultTok.type === "KEYWORD" &&
      (resultTok.value === "if" || resultTok.value === "match"))
  ) {
    return parseBlockResultExpression(parser, statements);
  }

  // Default: no final expression
  return ok({
    kind: "block",
    statements,
    result: { kind: "number", value: "0" },
  });
}

export function createSimpleBlockNode(statements: ASTNode[]): ASTNode {
  if (statements.length === 0) {
    return { kind: "number", value: "0" };
  }

  return {
    kind: "block",
    statements,
    result: { kind: "number", value: "0" },
  };
}

export function parseIfStatement(parser: Parser): Result<ASTNode, string> {
  // Expect 'if'
  const ifTok = current(parser);
  if (ifTok.type !== "KEYWORD" || ifTok.value !== "if") {
    return err("Expected 'if'");
  }
  advance(parser);

  // Parse condition (parentheses optional)
  const conditionResult = parseConditionExpression(parser);
  if (!conditionResult.ok) {
    return conditionResult;
  }

  // Save current proven constraints for scope management
  const savedConstraints = new Map(parser.provenConstraints);
  const savedVariables = new Map(parser.variables);

  // Extract constraints from the condition for type narrowing in then-branch
  const thenConstraints = extractConstraintsFromComparison(
    conditionResult.value,
    parser,
  );
  const typeNarrowing = getTypeNarrowingFromCondition(
    conditionResult.value,
    parser,
  );
  // Add constraints to parser context for then-branch
  // MERGE with existing constraints to handle nesting (don't overwrite!)
  for (const [varName, refinement] of thenConstraints) {
    const existing = parser.provenConstraints.get(varName);
    if (existing && existing.baseType === refinement.baseType) {
      // Merge: combine all constraints from outer scope + new from condition
      existing.constraints.push(...refinement.constraints);
    } else {
      parser.provenConstraints.set(varName, refinement);
    }
  }
  applyVariableTypeNarrowing(parser, typeNarrowing.trueBranch);

  // Parse then branch (single statement or block)
  const thenResult = parseIfBody(parser);
  if (!thenResult.ok) {
    // Restore constraints even on error
    parser.provenConstraints = savedConstraints;
    parser.variables = savedVariables;
    return thenResult;
  }

  // Restore to saved constraints for else branch (proven constraints are lost outside narrowing)
  parser.provenConstraints = new Map(savedConstraints);
  parser.variables = new Map(savedVariables);

  // Check for else
  const elseTok = current(parser);
  let elseBranch: ASTNode | undefined = undefined;

  if (elseTok.type === "KEYWORD" && elseTok.value === "else") {
    advance(parser);
    applyVariableTypeNarrowing(parser, typeNarrowing.falseBranch);

    // else can be followed by another if (else if) or a body
    const nextTok = current(parser);
    if (nextTok.type === "KEYWORD" && nextTok.value === "if") {
      // else if - recursively parse another if
      const elseIfResult = parseIfStatement(parser);
      if (!elseIfResult.ok) {
        return elseIfResult;
      }
      elseBranch = elseIfResult.value;
    } else {
      // else body
      const elseBodyResult = parseIfBody(parser);
      if (!elseBodyResult.ok) {
        return elseBodyResult;
      }
      elseBranch = elseBodyResult.value;
    }
  }

  // Restore original constraints after if statement
  parser.provenConstraints = savedConstraints;
  parser.variables = savedVariables;

  return ok({
    kind: "if",
    condition: conditionResult.value,
    thenBranch: thenResult.value,
    elseBranch,
  });
}

export function parseIfBody(parser: Parser): Result<ASTNode, string> {
  const tok = current(parser);

  // Block body - use helper that doesn't consume RBRACE so we can parse final expression
  if (tok.type === "LBRACE") {
    const stmtsResult = parseBlockStatementsWithoutRbrace(parser);
    if (!stmtsResult.ok) {
      return stmtsResult;
    }

    const blockResult = createBlockBodyWithOptionalExpression(
      stmtsResult.value,
      parser,
    );
    if (!blockResult.ok) {
      return blockResult;
    }

    // Now consume the closing RBRACE
    if (current(parser).type !== "RBRACE") {
      return err("Expected '}'");
    }
    advance(parser);

    return blockResult;
  } else {
    // Single statement body - could be break, continue, assignment, or expression
    const tok = current(parser);

    // Check for break statement
    if (tok.type === "KEYWORD" && tok.value === "break") {
      const breakStmt = parseBreakStatement(parser);
      if (!breakStmt.ok) {
        return breakStmt;
      }
      return breakStmt;
    }

    // Check for continue statement
    if (tok.type === "KEYWORD" && tok.value === "continue") {
      const continueStmt = parseContinueStatement(parser);
      if (!continueStmt.ok) {
        return continueStmt;
      }
      return continueStmt;
    }

    // Try assignment
    const assignResult = tryParseAssignment(parser);
    if (!assignResult.ok) {
      return assignResult;
    }

    if (assignResult.value !== undefined) {
      return ok(assignResult.value);
    }

    // Parse as expression
    const exprResult = parseExpression(parser);
    if (!exprResult.ok) {
      return exprResult;
    }
    return exprResult;
  }
}

export function parseWhileStatement(parser: Parser): Result<ASTNode, string> {
  // Expect 'while'
  const whileTok = current(parser);
  if (whileTok.type !== "KEYWORD" || whileTok.value !== "while") {
    return err("Expected 'while'");
  }
  advance(parser);

  // Parse condition (parentheses optional)
  const conditionResult = parseConditionExpression(parser);
  if (!conditionResult.ok) {
    return conditionResult;
  }

  // Parse body (single statement or block)
  const savedInLoop = parser.inLoop;
  parser.inLoop = true;
  const bodyTok = current(parser);
  let bodyResult: Result<ASTNode, string>;

  if (bodyTok.type === "LBRACE") {
    // Block body
    const stmtsResult = parseBlockStatements(parser);
    if (!stmtsResult.ok) {
      return stmtsResult;
    }

    bodyResult = ok(createSimpleBlockNode(stmtsResult.value));
  } else {
    // Single statement body
    const statements: ASTNode[] = [];
    const stmtResult = parseStatementInBlock(parser, statements);
    if (!stmtResult.ok) {
      return stmtResult;
    }

    if (stmtResult.value && statements.length === 1) {
      bodyResult = ok(statements[0] as ASTNode);
    } else if (stmtResult.value && statements.length > 1) {
      bodyResult = ok({
        kind: "block",
        statements,
        result: { kind: "number", value: "0" },
      });
    } else {
      return err("Expected statement or block in while body");
    }
  }

  if (!bodyResult.ok) {
    parser.inLoop = savedInLoop;
    return bodyResult;
  }

  parser.inLoop = savedInLoop;

  return ok({
    kind: "while",
    condition: conditionResult.value,
    body: bodyResult.value,
  });
}

export function parseBreakStatement(parser: Parser): Result<ASTNode, string> {
  const breakTok = current(parser);
  if (breakTok.type !== "KEYWORD" || breakTok.value !== "break") {
    return err("Expected 'break'");
  }
  if (!parser.inLoop) {
    return err("'break' is only valid inside a loop");
  }
  advance(parser);

  return ok({ kind: "break" });
}

export function parseContinueStatement(
  parser: Parser,
): Result<ASTNode, string> {
  const continueTok = current(parser);
  if (continueTok.type !== "KEYWORD" || continueTok.value !== "continue") {
    return err("Expected 'continue'");
  }
  if (!parser.inLoop) {
    return err("'continue' is only valid inside a loop");
  }
  advance(parser);

  return ok({ kind: "continue" });
}

export function parseReturnStatement(parser: Parser): Result<ASTNode, string> {
  // Expect 'return'
  const returnTok = current(parser);
  if (returnTok.type !== "KEYWORD" || returnTok.value !== "return") {
    return err("Expected 'return'");
  }
  advance(parser);

  // Parse return value expression
  const valueResult = parseExpression(parser);
  if (!valueResult.ok) {
    return valueResult;
  }

  const movedValue = maybeMoveExpression(parser, valueResult.value);
  if (!movedValue.ok) {
    return movedValue;
  }

  return ok({
    kind: "return",
    value: movedValue.value,
  });
}

export function parseMatchExpression(parser: Parser): Result<ASTNode, string> {
  // Expect 'match'
  const matchTok = current(parser);
  if (matchTok.type !== "KEYWORD" || matchTok.value !== "match") {
    return err("Expected 'match'");
  }
  advance(parser);

  // Expect '('
  const lparen = current(parser);
  if (lparen.type !== "LPAREN") {
    return err("Expected '(' after 'match'");
  }
  advance(parser);

  // Parse match expression
  const exprResult = parseExpression(parser);
  if (!exprResult.ok) {
    return exprResult;
  }

  // Expect ')'
  const rparen = current(parser);
  if (rparen.type !== "RPAREN") {
    return err("Expected ')' after match expression");
  }
  advance(parser);

  // Expect '{'
  const lbrace = current(parser);
  if (lbrace.type !== "LBRACE") {
    return err("Expected '{' before match cases");
  }
  advance(parser);

  // Parse cases
  const cases: MatchCase[] = [];
  const patternsUsed = new Set<string>();

  while (current(parser).type !== "RBRACE" && current(parser).type !== "EOF") {
    // Expect 'case'
    const caseTok = current(parser);
    if (caseTok.type !== "KEYWORD" || caseTok.value !== "case") {
      return err("Expected 'case' in match expression");
    }
    advance(parser);

    // Parse pattern
    const patternResult = parseMatchPattern(parser);
    if (!patternResult.ok) {
      return patternResult;
    }

    const pattern = patternResult.value;

    // Check for duplicate patterns
    const patternKey = pattern.type + ":" + String(pattern.value);
    if (patternsUsed.has(patternKey)) {
      return err(
        "Duplicate case pattern: " +
          (pattern.type === "wildcard" ? "_" : pattern.value),
      );
    }
    patternsUsed.add(patternKey);

    // Expect '=>'
    const arrow = current(parser);
    if (arrow.type !== "ARROW") {
      return err("Expected '=>' after match pattern");
    }
    advance(parser);

    // Parse case result expression
    const resultExpr = parseExpression(parser);
    if (!resultExpr.ok) {
      return resultExpr;
    }

    // Expect ';'
    const semi = current(parser);
    if (semi.type !== "SEMICOLON") {
      return err("Expected ';' after match case");
    }
    advance(parser);

    cases.push({
      pattern,
      result: resultExpr.value,
    });
  }

  // Expect '}'
  if (current(parser).type !== "RBRACE") {
    return err("Expected '}' after match cases");
  }
  advance(parser);

  // Validate: must have either wildcard or exhaustive coverage
  const hasWildcard = cases.some((c) => c.pattern.type === "wildcard");

  if (!hasWildcard) {
    // Check if coverage is exhaustive for booleans (true and false both present)
    const booleanCases = cases.filter((c) => c.pattern.type === "boolean");
    const hasTrue = booleanCases.some((c) => c.pattern.value === true);
    const hasFalse = booleanCases.some((c) => c.pattern.value === false);
    const allCasesAreBoolean = cases.every((c) => c.pattern.type === "boolean");

    if (!(allCasesAreBoolean && hasTrue && hasFalse)) {
      return err(
        "Match expression must have a wildcard case or be exhaustive (for booleans, need both true and false cases)",
      );
    }
  }

  return ok({
    kind: "match",
    matchExpr: exprResult.value,
    cases,
  });
}

export function parseMatchPattern(parser: Parser): Result<CasePattern, string> {
  const tok = current(parser);

  // Check for wildcard
  if (tok.type === "IDENTIFIER" && tok.value === "_") {
    advance(parser);
    return ok({ type: "wildcard" });
  }

  // Check for boolean
  if (tok.type === "BOOL") {
    const value = tok.value === "true";
    advance(parser);
    return ok({ type: "boolean", value });
  }

  // Check for number (including negative)
  if (tok.type === "NUMBER") {
    const value = tok.value;
    advance(parser);
    return ok({ type: "literal", value });
  }

  return err("Expected pattern (number, boolean, or wildcard) in match case");
}

export function parseProgram(parser: Parser): Result<ASTNode, string> {
  const statements: ASTNode[] = [];

  // Parse all let and assignment statements and if statements
  const blockResult = parseStatementBlock(parser, statements, false);
  if (!blockResult.ok) {
    return blockResult;
  }

  // Check if we're at EOF before trying to parse a final expression
  if (current(parser).type === "EOF") {
    // If we have statements, use the last expression-like statement as the result
    if (statements.length > 0) {
      const finalExpr = extractFinalExpressionIfPresent(statements);
      if (finalExpr) {
        // Use this as the result, remove it from statements
        statements.pop();
        if (statements.length === 0) {
          return ok(finalExpr);
        }
        return ok({ kind: "block", statements, result: finalExpr });
      }
      // Otherwise, return a block with the statements and a default result
      return ok({
        kind: "block",
        statements,
        result: { kind: "number", value: "0" },
      });
    }
    // If no statements and EOF, return 0
    return ok({ kind: "number", value: "0" });
  }

  // Parse final expression
  const expr = parseExpression(parser);
  if (!expr.ok) {
    return expr;
  }

  if (statements.length === 0) {
    return expr;
  }

  return ok({ kind: "block", statements, result: expr.value });
}

export function parseLetStatement(parser: Parser): Result<ASTNode, string> {
  const letKeyword = expectKeyword(parser, "let", "Expected 'let'");
  if (!letKeyword.ok) {
    return letKeyword;
  }

  // Check for 'mut'
  let mutable = false;
  const mutTok = current(parser);
  if (mutTok.type === "KEYWORD" && mutTok.value === "mut") {
    mutable = true;
    advance(parser);
  }

  if (current(parser).type === "LBRACE") {
    return parseDestructuringLetStatement(parser, mutable);
  }

  // Peek: if next tokens are `name =` (no colon), use inferred-type let
  const peekNameTok = current(parser);
  if (peekNameTok.type === "IDENTIFIER") {
    const peekPos = parser.pos;
    advance(parser); // consume name
    const peekNext = current(parser);
    if (peekNext.type === "ASSIGN") {
      // Inferred-type let: `let name = expr`
      const varName = peekNameTok.value;
      if (parser.variables.has(varName)) {
        return err("Variable '" + varName + "' already declared");
      }
      advance(parser); // consume =
      const initResult = parseExpression(parser);
      if (!initResult.ok) {
        return initResult;
      }
      const semiTok = current(parser);
      if (semiTok.type !== "SEMICOLON") {
        return err("Expected ';' after let initializer");
      }
      advance(parser);
      const initializerNode = initResult.value;
      const inferredTypeResult = inferExpressionType(initializerNode, parser);
      if (!inferredTypeResult.ok) {
        return err(
          "Cannot infer type of '" + varName + "': " + inferredTypeResult.error,
        );
      }
      const inferredType = inferredTypeResult.value;
      parser.variables.set(varName, {
        type: inferredType,
        mutable,
      });
      registerScopeVariable(parser, varName, inferredType, mutable, true);
      return ok({
        kind: "let",
        name: varName,
        type: inferredType,
        mutable,
        initializer: initializerNode,
      } as LetNode);
    }
    // Not inferred-type — restore and fall through to normal parsing
    parser.pos = peekPos;
  }

  const declarationResult = parseNamedTypeDeclaration(parser);
  if (!declarationResult.ok) {
    return declarationResult;
  }
  const {
    name,
    type: typeStr,
    aliasType,
    destructorFunction,
  } = declarationResult.value;

  // Check for duplicate declaration
  if (parser.variables.has(name)) {
    return err("Variable '" + name + "' already declared");
  }

  if (parseSliceType(typeStr) && !parseArrayType(typeStr)) {
    return err(
      "Slice value types must be referenced as *[T] or *mut [T] in let bindings",
    );
  }

  // Try to parse refinement constraints
  let refinement: RefinementType | undefined;
  const refinementResult = parseRefinementType(parser, typeStr);
  if (!refinementResult.ok) {
    return refinementResult;
  }
  refinement = refinementResult.value;

  parser.currentExpectedType = typeStr;
  const initResult = parseRequiredLetInitializer(parser);
  parser.currentExpectedType = undefined;
  if (!initResult.ok) {
    return initResult;
  }

  // Check type compatibility for numeric literals
  let initializer = initResult.value;
  const originalInitializer = initializer;
  const movedInitializer = maybeMoveExpression(parser, initializer);
  if (!movedInitializer.ok) {
    return movedInitializer;
  }
  initializer = movedInitializer.value;

  // Type check for array types: validate fixed-length initialization
  if (typeStr.startsWith("[")) {
    const parsedArrayType = parseArrayType(typeStr);
    if (parsedArrayType) {
      const { elementType, length } = parsedArrayType;

      if (length <= 0) {
        return err("Array length must be > 0");
      }

      if (
        initializer.kind !== "array-literal" &&
        initializer.kind !== "function-call" &&
        initializer.kind !== "variable"
      ) {
        return err("Expected array literal for array type");
      }

      if (initializer.kind !== "array-literal") {
        const matchTypeResult = ensureExpressionType(
          parser,
          initializer,
          typeStr,
        );
        if (!matchTypeResult.ok) {
          return matchTypeResult;
        }
      } else {
        const arrayLit = initializer as ArrayLiteralNode;
        const elemType = elementType;

        if (arrayLit.generator) {
          if (arrayLit.repeatCount !== length) {
            return err(
              "Array generator repeats " +
                (arrayLit.repeatCount ?? 0) +
                " times but type specifies length " +
                length,
            );
          }

          const generatorTypeResult = inferZeroArgCallableReturnType(
            arrayLit.generator,
            parser,
          );
          if (!generatorTypeResult.ok) {
            return generatorTypeResult;
          }

          if (generatorTypeResult.value !== elemType) {
            const bothFloat =
              elemType.startsWith("F") &&
              generatorTypeResult.value.startsWith("F");
            const bothInt =
              !elemType.startsWith("F") &&
              !elemType.startsWith("Bool") &&
              !generatorTypeResult.value.startsWith("F") &&
              generatorTypeResult.value !== "Bool";
            if (!bothFloat && !bothInt) {
              return err(
                "Type mismatch in array generator: expected " +
                  elemType +
                  " but got " +
                  generatorTypeResult.value,
              );
            }
          }
        } else {
          if (arrayLit.elements.length !== length) {
            return err(
              "Array initializer has " +
                arrayLit.elements.length +
                " elements but type specifies " +
                length,
            );
          }

          // Type-check each element against the declared element type
          if (elemType && !elemType.startsWith("[")) {
            for (let idx = 0; idx < arrayLit.elements.length; idx++) {
              const elemNode = arrayLit.elements[idx];
              if (elemNode && elemNode.kind === "number") {
                // Check element type annotation if present
                const numVal = elemNode.value;
                let numTypeAnnotation = "";
                for (let ci = numVal.length - 1; ci >= 0; ci--) {
                  if (isLetter(numVal[ci]) || numVal[ci] === "_") {
                    numTypeAnnotation = numVal[ci] + numTypeAnnotation;
                  } else {
                    break;
                  }
                }
                // Check float assigned to integer type
                const isFloatType = elemType.startsWith("F");
                const isIntType = !isFloatType && !elemType.startsWith("Bool");
                if (isIntType && numVal.includes(".")) {
                  return err(
                    "Type mismatch in array element " +
                      idx +
                      ": expected " +
                      elemType +
                      " but got float literal",
                  );
                }
                if (numTypeAnnotation && numTypeAnnotation !== elemType) {
                  return err(
                    "Type mismatch in array element " +
                      idx +
                      ": expected " +
                      elemType +
                      " but got " +
                      numTypeAnnotation,
                  );
                }
              } else {
                const elemTypeResult = inferExpressionType(elemNode!, parser);
                if (elemTypeResult.ok && elemTypeResult.value !== elemType) {
                  // Check for type mismatch (allow widening from same family)
                  const bothFloat =
                    elemType.startsWith("F") &&
                    elemTypeResult.value.startsWith("F");
                  const bothInt =
                    !elemType.startsWith("F") &&
                    !elemTypeResult.value.startsWith("F");
                  if (!bothFloat && !bothInt) {
                    return err(
                      "Type mismatch in array element " +
                        idx +
                        ": expected " +
                        elemType +
                        " but got " +
                        elemTypeResult.value,
                    );
                  }
                }
              }
            }
          }
        }

        arrayLit.elemType = elemType;
      } // close else (array-literal branch)
    }
  } else if (parseFunctionTypeString(typeStr)) {
    const matchTypeResult = ensureExpressionType(parser, initializer, typeStr);
    if (!matchTypeResult.ok) {
      return matchTypeResult;
    }
  } else if (initializer.kind === "array-literal") {
    return err("Array literal used with non-array type '" + typeStr + "'");
  }

  // Type check for pointer types: must infer expression type for correct pointer assignment
  if (typeStr.startsWith("*")) {
    const exprTypeResult = inferExpressionType(initializer, parser);
    if (!exprTypeResult.ok) {
      return exprTypeResult;
    }
    const exprType = exprTypeResult.value;

    // Check that expression type matches declared type, with coercion support
    // Allow *mut T to coerce to *T
    let isCompatible = exprType === typeStr;
    if (
      !isCompatible &&
      exprType.startsWith("*mut ") &&
      typeStr.startsWith("*")
    ) {
      // Strip "*mut " from exprType and "*" from typeStr and compare base types
      const exprBase = exprType.slice(5); // Remove "*mut "
      const typeBase = typeStr.slice(1); // Remove one "*"
      isCompatible = exprBase === typeBase;
    }
    if (!isCompatible) {
      const declaredCallableType = parseCallableTypeString(typeStr);
      const expressionCallableType = parseCallableTypeString(exprType);
      if (declaredCallableType && expressionCallableType) {
        isCompatible = haveMatchingCallSignatures(
          declaredCallableType,
          expressionCallableType,
        );
      }
    }
    if (!isCompatible) {
      return err(
        "Type mismatch: expression has type '" +
          exprType +
          "' but variable declared as '" +
          typeStr +
          "'",
      );
    }
  }

  if (typeStr === "Char" || initializer.kind === "char") {
    const exprTypeResult = inferExpressionType(initializer, parser);
    if (!exprTypeResult.ok) {
      return exprTypeResult;
    }
    if (!areTypesCompatible(typeStr, exprTypeResult.value)) {
      return err(
        "Type mismatch: expression has type '" +
          exprTypeResult.value +
          "' but variable declared as '" +
          typeStr +
          "'",
      );
    }
  }

  if (originalInitializer.kind === "number") {
    // Check if negative literal is assigned to unsigned type
    if (
      originalInitializer.value.startsWith("-") &&
      !typeStr.startsWith("I") &&
      !typeStr.startsWith("F") &&
      !typeStr.startsWith("*")
    ) {
      return err(
        "Cannot assign negative value to unsigned type '" + typeStr + "'",
      );
    }

    // If there's a refinement type, validate the literal against constraints
    if (refinement) {
      if (
        !validateConstraints(
          originalInitializer.value,
          refinement,
          parser.variables,
          parser,
        )
      ) {
        return err(
          "Literal value does not satisfy refinement constraints for type",
        );
      }
    }
  } else if (originalInitializer.kind === "variable" && refinement) {
    // Assigning a variable to a refined type - check if we can prove the constraint
    const sourceVarName = originalInitializer.name;
    if (!canAssignToRefinedType(sourceVarName, refinement, parser)) {
      return err(
        "Cannot assign variable '" +
          sourceVarName +
          "' to refined type - constraint cannot be proven",
      );
    }
  }

  const coercedInitializer = coerceExpressionToType(
    parser,
    initializer,
    typeStr,
  );
  if (!coercedInitializer.ok) {
    return coercedInitializer;
  }
  initializer = coercedInitializer.value;

  // Expect ';'
  const semiTok = current(parser);
  if (semiTok.type !== "SEMICOLON") {
    return err("Expected ';' after let statement");
  }
  advance(parser);

  // Register variable in parser context with refinement info
  // Store initValue if it's a numeric literal (so we can constant-fold constraints)
  const varInfo: VariableInfo = {
    type: typeStr,
    mutable,
    aliasType,
    destructorFunction,
    moved: false,
    refinement,
  };
  if (originalInitializer.kind === "number") {
    varInfo.initValue = originalInitializer.value;
  }

  const sliceReferenceType = parseSliceReferenceType(typeStr);
  if (sliceReferenceType) {
    varInfo.sliceLength = getSliceLengthFromInitializer(initializer, parser);
  }

  // Track what variable a pointer points to (for lvalue operations)
  // Also enforce exclusive access for mutable pointers
  if (
    typeStr.startsWith("*") &&
    initializer.kind === "unary-op" &&
    (initializer.operator === "&" || initializer.operator === "&mut")
  ) {
    const targetVar = initializer.operand;
    if (targetVar.kind === "variable") {
      varInfo.pointsTo = targetVar.name;

      // Enforce exclusive access: only one &mut per variable
      if (initializer.operator === "&mut") {
        // Check if another variable already has a mutable pointer to this target
        for (const [, otherInfo] of parser.variables.entries()) {
          if (
            otherInfo.pointsTo === targetVar.name &&
            otherInfo.type.startsWith("*mut ") &&
            !parseSliceReferenceType(otherInfo.type)
          ) {
            return err(
              `Cannot create multiple mutable pointers to '${targetVar.name}' - exclusive access violation`,
            );
          }
        }
      }
    }
  }

  // If initialized with another pointer, inherit its pointsTo
  if (typeStr.startsWith("*") && initializer.kind === "variable") {
    const sourceVarInfo = parser.variables.get(initializer.name);
    if (sourceVarInfo && sourceVarInfo.pointsTo) {
      varInfo.pointsTo = sourceVarInfo.pointsTo;
    }
  }

  parser.variables.set(name, varInfo);
  registerScopeVariable(parser, name, typeStr, mutable, mutable);

  // Record proven constraints for this variable
  // If initialized with a literal that satisfies the constraints, the constraint is proven
  if (refinement && originalInitializer.kind === "number") {
    parser.provenConstraints.set(name, refinement);
  }
  // If initialized with a variable, inherit its proven constraints
  else if (originalInitializer.kind === "variable") {
    const sourceVarName = originalInitializer.name;
    const sourceProven = parser.provenConstraints.get(sourceVarName);
    if (sourceProven) {
      parser.provenConstraints.set(name, sourceProven);
    }
  }

  const initializerMetadata = getExpressionInstanceMetadata(
    parser,
    initializer,
  );
  if (!initializerMetadata.ok) {
    return initializerMetadata;
  }
  varInfo.instanceMetadata = cloneOptionalInstanceMetadata(
    initializerMetadata.value,
  );

  return ok({
    kind: "let",
    mutable,
    name,
    type: typeStr,
    aliasType,
    destructorFunction,
    initializer,
  });
}

export function createDestructureTempName(parser: Parser): string {
  let tempIndex = parser.pos;
  let tempName = "$tuffDestructure" + tempIndex;

  while (parser.variables.has(tempName)) {
    tempIndex += 1;
    tempName = "$tuffDestructure" + tempIndex;
  }

  return tempName;
}

export function parseDestructuringPattern(
  parser: Parser,
): Result<DestructuredBinding[], string> {
  if (current(parser).type !== "LBRACE") {
    return err("Expected '{' after 'let'");
  }
  advance(parser);

  const bindings: DestructuredBinding[] = [];
  const seenBindingNames = new Set<string>();

  while (current(parser).type !== "RBRACE") {
    const sourceTok = current(parser);
    if (sourceTok.type !== "IDENTIFIER") {
      return err("Expected field name in destructuring pattern");
    }
    const sourceName = sourceTok.value;
    advance(parser);

    let bindingName = sourceName;
    if (current(parser).type === "COLON") {
      advance(parser);
      const bindingTok = current(parser);
      if (bindingTok.type !== "IDENTIFIER") {
        return err("Expected binding name after ':' in destructuring pattern");
      }
      bindingName = bindingTok.value;
      advance(parser);
    }

    if (seenBindingNames.has(bindingName)) {
      return err("Duplicate binding name '" + bindingName + "'");
    }
    seenBindingNames.add(bindingName);
    bindings.push({ sourceName, bindingName });

    if (current(parser).type === "RBRACE") {
      break;
    }
    if (current(parser).type !== "COMMA") {
      return err("Expected ',' or '}' in destructuring pattern");
    }
    advance(parser);
  }

  if (current(parser).type !== "RBRACE") {
    return err("Expected '}' after destructuring pattern");
  }
  advance(parser);

  return ok(bindings);
}

export function parseRequiredLetInitializer(
  parser: Parser,
): Result<ASTNode, string> {
  if (current(parser).type !== "ASSIGN") {
    return err("Expected '=' in let statement");
  }
  advance(parser);

  return parseExpression(parser);
}

export function parseDestructuringLetStatement(
  parser: Parser,
  mutable: boolean,
): Result<ASTNode, string> {
  if (mutable) {
    return err("Destructuring bindings cannot use 'mut'");
  }

  const bindingsResult = parseDestructuringPattern(parser);
  if (!bindingsResult.ok) {
    return bindingsResult;
  }
  const bindings = bindingsResult.value;

  const initResult = parseRequiredLetInitializer(parser);
  if (!initResult.ok) {
    return initResult;
  }

  const sourceTypeResult = inferExpressionType(initResult.value, parser);
  if (!sourceTypeResult.ok) {
    return sourceTypeResult;
  }
  const sourceType = sourceTypeResult.value;

  const objectInfo = parser.objects.get(sourceType);
  const structInfo = parser.structs.get(sourceType);
  if (!objectInfo && !structInfo) {
    return err(
      "Type mismatch: cannot destructure non-struct/non-object type '" +
        sourceType +
        "'",
    );
  }

  const tempName = createDestructureTempName(parser);
  const coercedInitializer = coerceExpressionToType(
    parser,
    initResult.value,
    sourceType,
  );
  if (!coercedInitializer.ok) {
    return coercedInitializer;
  }

  const statements: LetNode[] = [
    {
      kind: "let",
      mutable: false,
      name: tempName,
      type: sourceType,
      initializer: coercedInitializer.value,
    },
  ];

  parser.variables.set(tempName, {
    type: sourceType,
    mutable: false,
    moved: false,
  });
  registerScopeVariable(parser, tempName, sourceType, false, false);

  for (const binding of bindings) {
    if (parser.variables.has(binding.bindingName)) {
      return err("Variable '" + binding.bindingName + "' already declared");
    }

    const memberType = inferContainerMemberType(
      parser,
      { kind: "variable", name: tempName },
      binding.sourceName,
    );
    if (!memberType.ok) {
      return memberType;
    }

    const declaration: LetNode = {
      kind: "let",
      mutable: false,
      name: binding.bindingName,
      type: memberType.value,
      initializer: {
        kind: "field-access",
        object: { kind: "variable", name: tempName },
        fieldName: binding.sourceName,
      },
    };

    statements.push(declaration);
    parser.variables.set(binding.bindingName, {
      type: memberType.value,
      mutable: false,
      moved: false,
    });
    registerScopeVariable(
      parser,
      binding.bindingName,
      memberType.value,
      false,
      false,
    );
  }

  if (current(parser).type !== "SEMICOLON") {
    return err("Expected ';' after let statement");
  }
  advance(parser);

  return ok({ kind: "destructure", statements });
}

export function isReservedKeyword(name: string): boolean {
  return (
    name === "let" ||
    name === "lifetime" ||
    name === "contract" ||
    name === "extern" ||
    name === "object" ||
    name === "type" ||
    name === "then" ||
    name === "this" ||
    name === "is" ||
    name === "mut" ||
    name === "out" ||
    name === "if" ||
    name === "else" ||
    name === "while" ||
    name === "break" ||
    name === "continue" ||
    name === "match" ||
    name === "case" ||
    name === "fn" ||
    name === "return" ||
    name === "struct"
  );
}

export function checkReservedKeyword(
  name: string,
  context:
    | "function name"
    | "parameter name"
    | "type alias name"
    | "contract name",
): Result<undefined, string> {
  if (isReservedKeyword(name)) {
    return err("Cannot use reserved keyword '" + name + "' as " + context);
  }
  return ok(undefined);
}

export function parseTypeAliasDeclaration(
  parser: Parser,
  resolveAliases: boolean,
): Result<ParsedTypeAliasDeclaration, string> {
  const typeTok = current(parser);
  if (typeTok.type !== "KEYWORD" || typeTok.value !== "type") {
    return err("Expected 'type'");
  }
  advance(parser);

  const nameTok = current(parser);
  if (nameTok.type === "KEYWORD") {
    return err(
      "Cannot use reserved keyword '" + nameTok.value + "' as type alias name",
    );
  }
  if (nameTok.type !== "IDENTIFIER") {
    return err("Expected type alias name");
  }
  const aliasName = nameTok.value;

  const aliasKeywordCheck = checkReservedKeyword(aliasName, "type alias name");
  if (!aliasKeywordCheck.ok) {
    return aliasKeywordCheck;
  }
  if (VALID_TYPES.has(aliasName)) {
    return err("Type '" + aliasName + "' already declared");
  }
  advance(parser);

  if (current(parser).type !== "ASSIGN") {
    return err("Expected '=' in type alias declaration");
  }
  advance(parser);

  const targetTypeResult = parseTypeAnnotation(parser, resolveAliases);
  if (!targetTypeResult.ok) {
    return targetTypeResult;
  }

  let destructorName: string | undefined;
  const nextToken = current(parser);
  if (nextToken.type === "KEYWORD" && nextToken.value === "then") {
    advance(parser);

    const destructorTok = current(parser);
    if (destructorTok.type !== "IDENTIFIER") {
      return err("Expected destructor function name after 'then'");
    }
    destructorName = destructorTok.value;
    advance(parser);
  }

  if (current(parser).type !== "SEMICOLON") {
    return err("Expected ';' after type alias declaration");
  }
  advance(parser);

  return ok({
    name: aliasName,
    targetType: targetTypeResult.value,
    destructorName,
  });
}

export function parseTypeAliasStatement(
  parser: Parser,
): Result<ASTNode, string> {
  const aliasNode = parseTypeAliasLikeStatement(parser, createTypeAliasNode);
  if (!aliasNode.ok) {
    return aliasNode;
  }

  if (aliasNode.value.kind === "type-alias" && aliasNode.value.destructorName) {
    const destructorValidation = validateAliasDestructor(
      parser,
      aliasNode.value.name,
      aliasNode.value.destructorName,
    );
    if (!destructorValidation.ok) {
      return destructorValidation;
    }
  }

  return aliasNode;
}

export interface ParsedNamedTypeDeclaration {
  name: string;
  type: string;
  aliasType?: string;
  destructorFunction?: string;
}

export interface ParsedFunctionSignatureHead {
  name: string;
  typeParameters: string[];
  typeParameterConstraints?: Map<string, string[]>;
  parameters: FunctionParameter[];
  returnType: string;
  hasExplicitReturnType: boolean;
}

export function expectKeyword(
  parser: Parser,
  keyword: string,
  errorMessage: string,
): Result<void, string> {
  const tok = current(parser);
  if (tok.type !== "KEYWORD" || tok.value !== keyword) {
    return err(errorMessage);
  }
  advance(parser);
  return ok(undefined);
}

export function parseNamedTypeDeclaration(
  parser: Parser,
): Result<ParsedNamedTypeDeclaration, string> {
  const nameTok = current(parser);
  if (nameTok.type !== "IDENTIFIER") {
    return err("Expected variable name");
  }
  const name = nameTok.value;
  advance(parser);

  if (current(parser).type !== "COLON") {
    return err("Expected ':' after variable name");
  }
  advance(parser);

  const typeResult = parseTypeReference(parser);
  if (!typeResult.ok) {
    return typeResult;
  }

  return ok({
    name,
    type: typeResult.value.type,
    aliasType: typeResult.value.aliasType,
    destructorFunction: typeResult.value.destructorFunction,
  });
}

export function createTypeAliasNode(
  name: string,
  targetType: string,
  destructorName?: string,
): ASTNode {
  return {
    kind: "type-alias",
    name,
    targetType,
    destructorName,
  };
}

export function createExternTypeNode(
  name: string,
  targetType: string,
): ASTNode {
  return {
    kind: "extern-type",
    name,
    targetType,
  };
}

export function parseTypeAliasLikeStatement(
  parser: Parser,
  nodeFactory: CallableFunction,
): Result<ASTNode, string> {
  const aliasDeclaration = parseTypeAliasDeclaration(parser, true);
  if (!aliasDeclaration.ok) {
    return aliasDeclaration;
  }

  return ok(
    nodeFactory(
      aliasDeclaration.value.name,
      aliasDeclaration.value.targetType,
      aliasDeclaration.value.destructorName,
    ) as ASTNode,
  );
}

export function registerParsedFunctionSignature(
  parser: Parser,
  declarationStart: number,
  signature: ParsedFunctionSignatureHead,
): Result<void, string> {
  const existing = parser.functions.get(signature.name);
  if (!existing) {
    parser.functions.set(signature.name, {
      typeParameters: signature.typeParameters,
      typeParameterConstraints: signature.typeParameterConstraints,
      parameters: signature.parameters,
      returnType: signature.returnType,
    });
    return ok(undefined);
  }

  const allOverloads = getAllFunctionOverloads(existing);
  const isDuplicate = allOverloads.some(
    (o) =>
      o.parameters.length === signature.parameters.length &&
      o.parameters.every((p, i) => p.type === signature.parameters[i]?.type) &&
      o.returnType === signature.returnType,
  );

  if (isDuplicate) {
    parser.pos = declarationStart;
    return err(
      "Function '" +
        signature.name +
        "' already declared with identical signature",
    );
  }

  if (!existing.overloads) {
    existing.mangledName = existing.mangledName ?? signature.name + "$$0";
    existing.overloads = [];
  }
  existing.overloads.push({
    typeParameters: signature.typeParameters,
    typeParameterConstraints: signature.typeParameterConstraints,
    parameters: signature.parameters,
    returnType: signature.returnType,
    mangledName: signature.name + "$$" + (existing.overloads.length + 1),
  });
  return ok(undefined);
}

export function scanTypeDeclarationKeywords(
  parser: Parser,
  handler: CallableFunction,
): Result<void, string> {
  return scanTokensFromStart(parser, (savedPos: number) => {
    const tok = current(parser);
    let declarationKind: "struct" | "type" | undefined;

    if (tok.type === "KEYWORD" && tok.value === "struct") {
      declarationKind = "struct";
      advance(parser);
    } else if (tok.type === "KEYWORD" && tok.value === "type") {
      declarationKind = "type";
      advance(parser);
    } else if (tok.type === "KEYWORD" && tok.value === "extern") {
      const externStart = parser.pos;
      advance(parser);
      const nestedTok = current(parser);
      if (nestedTok.type !== "KEYWORD" || nestedTok.value !== "type") {
        parser.pos = externStart + 1;
        return ok(true);
      }
      declarationKind = "type";
      advance(parser);
    } else {
      return ok(false);
    }

    const result = handler(savedPos, declarationKind) as Result<void, string>;
    return result.ok ? ok(true) : result;
  });
}

export function parseFunctionSignatureHead(
  parser: Parser,
  requireExplicitReturnType: boolean,
  rejectShadowing: boolean,
): Result<ParsedFunctionSignatureHead, string> {
  const fnKeyword = expectKeyword(parser, "fn", "Expected 'fn'");
  if (!fnKeyword.ok) {
    return fnKeyword;
  }

  const nameTok = current(parser);
  if (nameTok.type !== "IDENTIFIER") {
    return err("Expected function name");
  }
  const functionName = nameTok.value;

  const fnNameCheck = checkReservedKeyword(functionName, "function name");
  if (!fnNameCheck.ok) {
    return fnNameCheck;
  }
  advance(parser);

  const typeParameterDeclarations =
    parseConstrainedGenericParameterList(parser);
  if (!typeParameterDeclarations.ok) {
    return typeParameterDeclarations;
  }

  const typeParameters = typeParameterDeclarations.value.map(
    (declaration) => declaration.name,
  );
  const typeParameterConstraints = createTypeParameterConstraintMap(
    typeParameterDeclarations.value,
  );

  return withTemporaryGenericTypeParameters(
    parser,
    typeParameters,
    (): Result<ParsedFunctionSignatureHead, string> => {
      if (current(parser).type !== "LPAREN") {
        return err("Expected '(' after function name");
      }
      advance(parser);

      const parametersResult = parseFunctionParameters(parser, rejectShadowing);
      if (!parametersResult.ok) {
        return parametersResult;
      }

      let hasExplicitReturnType = false;
      let returnType = "__inferred__";
      if (current(parser).type === "COLON") {
        advance(parser);
        const returnTypeResult = parseTypeValue(parser);
        if (!returnTypeResult.ok) {
          return returnTypeResult;
        }
        returnType = returnTypeResult.value;
        hasExplicitReturnType = true;
        advance(parser);
      }

      if (requireExplicitReturnType && !hasExplicitReturnType) {
        return err(
          "Extern function declarations require an explicit return type",
        );
      }

      return ok({
        name: functionName,
        typeParameters,
        typeParameterConstraints,
        parameters: parametersResult.value,
        returnType,
        hasExplicitReturnType,
      });
    },
  );
}

export function ensureContractAllowed(parser: Parser): Result<void, string> {
  if (parser.currentScope !== parser.globalScope) {
    return err("Contract declarations are only allowed at top level");
  }

  return ok(undefined);
}

export function parseContractMethodSignature(
  parser: Parser,
): Result<ContractMethodSignature, string> {
  const signatureResult = parseFunctionSignatureHead(parser, true, false);
  if (!signatureResult.ok) {
    return signatureResult;
  }

  if (
    signatureResult.value.parameters.some(
      (parameter) => parameter.name === "this",
    )
  ) {
    return err(
      "Contract methods use an implicit receiver and cannot declare 'this' explicitly",
    );
  }

  if (current(parser).type !== "SEMICOLON") {
    return err("Expected ';' after contract method signature");
  }
  advance(parser);

  return ok({
    name: signatureResult.value.name,
    parameters: signatureResult.value.parameters,
    returnType: signatureResult.value.returnType,
  });
}

export function createContractInfo(
  typeParameters: string[],
  methods: ContractMethodSignature[],
): ContractInfo {
  return {
    typeParameters,
    methods: new Map(
      methods.map((method) => [
        method.name,
        {
          parameterTypes: method.parameters.map((parameter) => parameter.type),
          returnType: method.returnType,
        },
      ]),
    ),
  };
}

export function parseContractStatement(
  parser: Parser,
): Result<ASTNode, string> {
  const contractKeyword = expectKeyword(
    parser,
    "contract",
    "Expected 'contract'",
  );
  if (!contractKeyword.ok) {
    return contractKeyword;
  }

  const placementResult = ensureContractAllowed(parser);
  if (!placementResult.ok) {
    return placementResult;
  }

  const nameToken = current(parser);
  if (nameToken.type === "KEYWORD") {
    return err(
      "Cannot use reserved keyword '" + nameToken.value + "' as contract name",
    );
  }
  if (nameToken.type !== "IDENTIFIER") {
    return err("Expected contract name");
  }

  const contractName = nameToken.value;
  const contractNameCheck = checkReservedKeyword(contractName, "contract name");
  if (!contractNameCheck.ok) {
    return contractNameCheck;
  }
  advance(parser);

  const typeParameters: string[] = [];
  if (isGenericListStartToken(current(parser))) {
    const genericParamsResult = parseGenericParameterDeclarations(parser, false);
    if (!genericParamsResult.ok) {
      return genericParamsResult;
    }
    for (const entry of genericParamsResult.value) {
      typeParameters.push(entry.name);
    }
  }

  if (current(parser).type !== "LBRACE") {
    return err("Expected '{' after contract name");
  }
  advance(parser);

  const methods: ContractMethodSignature[] = [];
  const seenMethods = new Set<string>();

  const parseBodyResult = withTemporaryGenericTypeParameters(
    parser,
    typeParameters,
    (): Result<ContractMethodSignature[], string> => {
      while (current(parser).type !== "RBRACE") {
        const methodToken = current(parser);
        if (methodToken.type !== "KEYWORD" || methodToken.value !== "fn") {
          return err("Contracts only support function signatures");
        }

        const methodResult = parseContractMethodSignature(parser);
        if (!methodResult.ok) {
          return methodResult;
        }

        if (seenMethods.has(methodResult.value.name)) {
          return err(
            "Contract '" +
              contractName +
              "' already declares member '" +
              methodResult.value.name +
              "'",
          );
        }

        seenMethods.add(methodResult.value.name);
        methods.push(methodResult.value);
      }
      return ok(methods);
    },
  );
  if (!parseBodyResult.ok) {
    return parseBodyResult;
  }

  if (current(parser).type !== "RBRACE") {
    return err("Expected '}' after contract body");
  }
  advance(parser);

  return ok({
    kind: "contract",
    name: contractName,
    typeParameters,
    methods,
  });
}

export function ensureExternAllowed(parser: Parser): Result<void, string> {
  if (!parser.currentModuleName || parser.modules.size === 0) {
    return err("Extern declarations require project compilation");
  }

  if (parser.currentScope !== parser.globalScope) {
    return err("Extern declarations are only allowed at module top level");
  }

  return ok(undefined);
}

export function parseModulePath(parser: Parser): Result<string, string> {
  const first = current(parser);
  if (first.type !== "IDENTIFIER") {
    return err("Expected module name");
  }

  let moduleName = first.value;
  advance(parser);

  while (current(parser).type === "DOUBLE_COLON") {
    advance(parser);
    const segment = current(parser);
    if (segment.type !== "IDENTIFIER") {
      return err("Expected module name segment after '::'");
    }

    moduleName += "::" + segment.value;
    advance(parser);
  }

  return ok(moduleName);
}

export function parseExternModuleStatement(
  parser: Parser,
): Result<ASTNode, string> {
  const moduleNameResult = parseModulePath(parser);
  if (!moduleNameResult.ok) {
    return moduleNameResult;
  }

  if (current(parser).type !== "SEMICOLON") {
    return err("Expected ';' after extern module declaration");
  }
  advance(parser);

  if (
    parser.currentModuleName &&
    moduleNameResult.value !== parser.currentModuleName
  ) {
    return err(
      "Extern module declaration must match current module '" +
        parser.currentModuleName +
        "'",
    );
  }

  return ok({
    kind: "extern-module",
    moduleName: moduleNameResult.value,
  });
}

export function parseExternFunctionStatement(
  parser: Parser,
): Result<ASTNode, string> {
  const signatureResult = parseFunctionSignatureHead(parser, true, false);
  if (!signatureResult.ok) {
    return signatureResult;
  }

  if (parser.variables.has(signatureResult.value.name)) {
    return err(
      "Variable '" + signatureResult.value.name + "' already declared",
    );
  }

  if (current(parser).type !== "SEMICOLON") {
    return err("Expected ';' after extern function declaration");
  }
  advance(parser);

  registerScopeFunction(
    parser,
    signatureResult.value.name,
    signatureResult.value.parameters,
    signatureResult.value.returnType,
    signatureResult.value.typeParameters,
  );

  return ok({
    kind: "extern-function",
    name: signatureResult.value.name,
    parameters: signatureResult.value.parameters,
    returnType: signatureResult.value.returnType,
  });
}

export function parseExternLetStatement(
  parser: Parser,
): Result<ASTNode, string> {
  const letKeyword = expectKeyword(
    parser,
    "let",
    "Expected 'let' after 'extern'",
  );
  if (!letKeyword.ok) {
    return letKeyword;
  }
  const declarationResult = parseNamedTypeDeclaration(parser);
  if (!declarationResult.ok) {
    return declarationResult;
  }
  const { name, type } = declarationResult.value;

  if (parser.variables.has(name) || parser.functions.has(name)) {
    return err("Member '" + name + "' already declared");
  }

  if (current(parser).type !== "SEMICOLON") {
    return err("Expected ';' after extern let declaration");
  }
  advance(parser);

  parser.variables.set(name, { type, mutable: false, moved: false });
  registerScopeVariable(parser, name, type, false, false);

  return ok({
    kind: "extern-let",
    name,
    type,
  });
}

export function parseExternTypeStatement(
  parser: Parser,
): Result<ASTNode, string> {
  return parseTypeAliasLikeStatement(parser, createExternTypeNode);
}

export function parseExternStatement(parser: Parser): Result<ASTNode, string> {
  const externTok = current(parser);
  if (externTok.type !== "KEYWORD" || externTok.value !== "extern") {
    return err("Expected 'extern'");
  }
  advance(parser);

  const placementResult = ensureExternAllowed(parser);
  if (!placementResult.ok) {
    return placementResult;
  }

  const nextTok = current(parser);
  if (nextTok.type === "KEYWORD" && nextTok.value === "fn") {
    return parseExternFunctionStatement(parser);
  }
  if (nextTok.type === "KEYWORD" && nextTok.value === "let") {
    return parseExternLetStatement(parser);
  }
  if (nextTok.type === "KEYWORD" && nextTok.value === "type") {
    return parseExternTypeStatement(parser);
  }

  return parseExternModuleStatement(parser);
}

export function restoreFunctionParsingState(
  parser: Parser,
  savedVariables: Map<string, VariableInfo>,
  savedScope: ScopeFrame,
  savedInLoop: boolean,
  savedGenericTypeParameters: string[],
  savedGenericTypeConstraints: Map<string, string[]>,
  savedCurrentFunctionReturnType?: string,
): void {
  parser.variables = savedVariables;
  parser.currentScope = savedScope;
  parser.inLoop = savedInLoop;
  parser.genericTypeParameters = savedGenericTypeParameters;
  parser.genericTypeConstraints = savedGenericTypeConstraints;
  parser.currentFunctionReturnType = savedCurrentFunctionReturnType;
}

export interface FunctionParsingStateSnapshot {
  variables: Map<string, VariableInfo>;
  scope: ScopeFrame;
  inLoop: boolean;
  genericTypeParameters: string[];
  genericTypeConstraints: Map<string, string[]>;
  currentFunctionReturnType?: string;
}

export function restoreFunctionParsingStateWithError<T>(
  parser: Parser,
  state: FunctionParsingStateSnapshot,
  message: string,
): Result<T, string> {
  restoreFunctionParsingState(
    parser,
    state.variables,
    state.scope,
    state.inLoop,
    state.genericTypeParameters,
    state.genericTypeConstraints,
    state.currentFunctionReturnType,
  );
  return err(message);
}

export function cloneOptionalInstanceMetadata(
  metadata: InstanceValueMetadata | undefined,
): InstanceValueMetadata | undefined {
  return metadata ? cloneInstanceMetadata(metadata) : undefined;
}

export function getBoundInstanceMethodCallableInfo(
  parser: Parser,
  callee: FieldAccessNode,
): Result<BoundInstanceMethodCallableInfo | undefined, string> {
  const instanceMethod = getInstanceMethodInfo(
    parser,
    callee.object,
    callee.fieldName,
    parser.currentExpectedType,
  );
  if (!instanceMethod.ok) {
    return instanceMethod;
  }

  return ok(
    instanceMethod.value
      ? {
          parameterTypes: instanceMethod.value.receiverType
            ? instanceMethod.value.parameterTypes.slice(1)
            : [...instanceMethod.value.parameterTypes],
          returnType: instanceMethod.value.returnType,
          mangledName: instanceMethod.value.mangledName,
        }
      : undefined,
  );
}

export function createMethodReferenceClosure(
  ownerType: string,
  receiverType: string,
  methodName: string,
  parameterTypes: string[],
  returnType: string,
): ASTNode {
  const receiverName = "$receiver";
  const argumentParameters = parameterTypes.map((type, index) => ({
    name: "$arg" + index,
    type,
  }));

  const receiverExpression: ASTNode = receiverType.startsWith("*")
    ? {
        kind: "unary-op",
        operator: "*",
        operand: { kind: "variable", name: receiverName },
      }
    : { kind: "variable", name: receiverName };

  return {
    kind: "closure",
    parameters: [
      {
        name: receiverName,
        type: receiverType,
      },
      ...argumentParameters,
    ],
    returnType,
    body: {
      kind: "call",
      callee: {
        kind: "field-access",
        object: receiverExpression,
        fieldName: methodName,
      },
      arguments: argumentParameters.map((parameter) => ({
        kind: "variable",
        name: parameter.name,
      })),
      returnType,
    },
  };
}

export function tryParseTypeMethodReference(
  parser: Parser,
): Result<ASTNode | undefined, string> {
  const ownerToken = current(parser);
  const separatorToken = parser.tokens[parser.pos + 1];
  const methodToken = parser.tokens[parser.pos + 2];

  if (
    ownerToken?.type !== "IDENTIFIER" ||
    separatorToken?.type !== "DOUBLE_COLON" ||
    methodToken?.type !== "IDENTIFIER"
  ) {
    return ok(undefined);
  }

  const ownerType = ownerToken.value;
  const methodName = methodToken.value;
  const constructorInfo = parser.functions.get(ownerType);
  const instanceMethod = constructorInfo?.instanceMetadata?.methods.find(
    (method) => method.name === methodName,
  );

  if (instanceMethod) {
    parser.pos += 3;
    const receiverType = instanceMethod.receiverType ?? "*" + ownerType;
    const parameterTypes = instanceMethod.receiverType
      ? instanceMethod.parameterTypes.slice(1)
      : [...instanceMethod.parameterTypes];
    return ok(
      createMethodReferenceClosure(
        ownerType,
        receiverType,
        methodName,
        parameterTypes,
        instanceMethod.returnType,
      ),
    );
  }

  return ok(undefined);
}

export function buildConstructorInstanceMetadata(
  parser: Parser,
  constructorName: string,
  body: ASTNode,
): Result<InstanceValueMetadata | undefined, string> {
  if (body.kind !== "block") {
    return ok(undefined);
  }

  const structInfo = parser.structs.get(constructorName);

  const methods: InstanceMethodInfo[] = [];
  const seenSignatures = new Set<string>(); // "name|returnType" to detect identical duplicates
  for (const statement of body.statements) {
    if (statement.kind !== "function") {
      continue;
    }

    // Strip mangling suffix (e.g. "into$$0" → "into") to get the original name
    const originalName = stripMangledOverloadSuffix(statement.name);
    const mangledName =
      statement.name !== originalName ? statement.name : undefined;

    const sigKey = originalName + "|" + statement.returnType;
    if (seenSignatures.has(sigKey)) {
      return err(
        "Constructor-local method '" + originalName + "' already declared",
      );
    }
    seenSignatures.add(sigKey);
    if (structInfo?.fields.some((field) => field.name === originalName)) {
      return err(
        "Constructor-local method '" +
          originalName +
          "' conflicts with struct field '" +
          originalName +
          "'",
      );
    }

    methods.push({
      name: originalName,
      mangledName,
      receiverType:
        statement.parameters[0]?.name === "this"
          ? statement.parameters[0].type
          : undefined,
      parameterTypes: statement.parameters.map((parameter) => parameter.type),
      returnType: statement.returnType,
    });
  }

  return methods.length > 0
    ? ok({ methods, fields: new Map() })
    : ok(undefined);
}

export interface OutParameterFlowResult {
  normalStates: Set<string>[];
  returnStates: Set<string>[];
}

export function cloneAssignedState(state: Set<string>): Set<string> {
  return new Set(state);
}

export function cloneAssignedStates(states: Set<string>[]): Set<string>[] {
  return states.map((state) => cloneAssignedState(state));
}

export function analyzeOutParameterChildren(
  parser: Parser,
  currentFunctionName: string,
  outParameters: Set<string>,
  states: Set<string>[],
  children: ASTNode[],
): Result<OutParameterFlowResult, string> {
  let normalStates = cloneAssignedStates(states);
  const returnStates: Set<string>[] = [];

  for (const child of children) {
    const childFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      normalStates,
      child,
    );
    if (!childFlow.ok) {
      return childFlow;
    }

    normalStates = childFlow.value.normalStates;
    returnStates.push(...childFlow.value.returnStates);
  }

  return ok({ normalStates, returnStates });
}

export function getCallParameterMetadata(
  parser: Parser,
  currentFunctionName: string,
  node: ASTNode,
): FunctionParameter[] {
  if (node.kind === "function-call") {
    return node.name === currentFunctionName
      ? []
      : (parser.functions.get(node.name)?.parameters ?? []);
  }

  if (node.kind === "call" && node.callee.kind === "variable") {
    return node.callee.name === currentFunctionName
      ? []
      : (parser.functions.get(node.callee.name)?.parameters ?? []);
  }

  return [];
}

export function markOutParametersAssignedFromCall(
  parser: Parser,
  currentFunctionName: string,
  node: ASTNode,
  outParameters: Set<string>,
  states: Set<string>[],
): Set<string>[] {
  const parameters = getCallParameterMetadata(
    parser,
    currentFunctionName,
    node,
  );
  if (!parameters.some((parameter) => parameter.out)) {
    return states;
  }

  const args =
    node.kind === "function-call" || node.kind === "call" ? node.arguments : [];

  return states.map((state) => {
    const nextState = cloneAssignedState(state);
    for (let i = 0; i < parameters.length; i++) {
      const parameter = parameters[i];
      const arg = args[i];
      if (
        parameter?.out &&
        arg?.kind === "variable" &&
        outParameters.has(arg.name)
      ) {
        nextState.add(arg.name);
      }
    }
    return nextState;
  });
}

export function analyzeOutParameterFlow(
  parser: Parser,
  currentFunctionName: string,
  outParameters: Set<string>,
  states: Set<string>[],
  node: ASTNode,
): Result<OutParameterFlowResult, string> {
  if (
    node.kind === "number" ||
    node.kind === "boolean" ||
    node.kind === "char" ||
    node.kind === "string" ||
    node.kind === "read" ||
    node.kind === "module-reference" ||
    node.kind === "variable" ||
    node.kind === "move" ||
    node.kind === "this" ||
    node.kind === "break" ||
    node.kind === "continue" ||
    node.kind === "type-alias" ||
    node.kind === "contract" ||
    node.kind === "extern-module" ||
    node.kind === "extern-function" ||
    node.kind === "extern-let" ||
    node.kind === "extern-type" ||
    node.kind === "struct" ||
    node.kind === "function" ||
    node.kind === "closure" ||
    node.kind === "object" ||
    node.kind === "module"
  ) {
    return ok({ normalStates: cloneAssignedStates(states), returnStates: [] });
  }

  if (node.kind === "let") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.initializer,
    );
  }

  if (node.kind === "destructure") {
    return analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.statements.map((statement) => statement.initializer),
    );
  }

  if (node.kind === "deref-assign") {
    const targetFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.target,
    );
    if (!targetFlow.ok) {
      return targetFlow;
    }

    const valueFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      targetFlow.value.normalStates,
      node.value,
    );
    if (!valueFlow.ok) {
      return valueFlow;
    }

    return ok({
      normalStates: valueFlow.value.normalStates.map((state) => {
        const nextState = cloneAssignedState(state);
        if (
          node.target.kind === "variable" &&
          outParameters.has(node.target.name)
        ) {
          nextState.add(node.target.name);
        }
        return nextState;
      }),
      returnStates: [
        ...targetFlow.value.returnStates,
        ...valueFlow.value.returnStates,
      ],
    });
  }

  if (node.kind === "assign") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.value,
    );
  }

  if (node.kind === "field-assign") {
    return analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      [node.object, node.value],
    );
  }

  if (node.kind === "array-assign") {
    return analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      [node.array, node.index, node.value],
    );
  }

  if (node.kind === "block") {
    let normalStates = cloneAssignedStates(states);
    const returnStates: Set<string>[] = [];

    for (const statement of node.statements) {
      const statementFlow = analyzeOutParameterFlow(
        parser,
        currentFunctionName,
        outParameters,
        normalStates,
        statement,
      );
      if (!statementFlow.ok) {
        return statementFlow;
      }

      normalStates = statementFlow.value.normalStates;
      returnStates.push(...statementFlow.value.returnStates);
    }

    const resultFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      normalStates,
      node.result,
    );
    if (!resultFlow.ok) {
      return resultFlow;
    }

    return ok({
      normalStates: resultFlow.value.normalStates,
      returnStates: [...returnStates, ...resultFlow.value.returnStates],
    });
  }

  if (node.kind === "if") {
    const conditionFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.condition,
    );
    if (!conditionFlow.ok) {
      return conditionFlow;
    }

    const thenFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      conditionFlow.value.normalStates,
      node.thenBranch,
    );
    if (!thenFlow.ok) {
      return thenFlow;
    }

    if (!node.elseBranch) {
      return ok({
        normalStates: [
          ...cloneAssignedStates(conditionFlow.value.normalStates),
          ...thenFlow.value.normalStates,
        ],
        returnStates: [
          ...conditionFlow.value.returnStates,
          ...thenFlow.value.returnStates,
        ],
      });
    }

    const elseFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      conditionFlow.value.normalStates,
      node.elseBranch,
    );
    if (!elseFlow.ok) {
      return elseFlow;
    }

    return ok({
      normalStates: [
        ...thenFlow.value.normalStates,
        ...elseFlow.value.normalStates,
      ],
      returnStates: [
        ...conditionFlow.value.returnStates,
        ...thenFlow.value.returnStates,
        ...elseFlow.value.returnStates,
      ],
    });
  }

  if (node.kind === "while") {
    const conditionFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.condition,
    );
    if (!conditionFlow.ok) {
      return conditionFlow;
    }

    const bodyFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      conditionFlow.value.normalStates,
      node.body,
    );
    if (!bodyFlow.ok) {
      return bodyFlow;
    }

    return ok({
      normalStates: conditionFlow.value.normalStates,
      returnStates: [
        ...conditionFlow.value.returnStates,
        ...bodyFlow.value.returnStates,
      ],
    });
  }

  if (node.kind === "return") {
    const valueFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.value,
    );
    if (!valueFlow.ok) {
      return valueFlow;
    }

    return ok({
      normalStates: [],
      returnStates: [
        ...valueFlow.value.returnStates,
        ...cloneAssignedStates(valueFlow.value.normalStates),
      ],
    });
  }

  if (node.kind === "match") {
    const matchExprFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.matchExpr,
    );
    if (!matchExprFlow.ok) {
      return matchExprFlow;
    }

    const normalStates: Set<string>[] = [];
    const returnStates = [...matchExprFlow.value.returnStates];
    for (const matchCase of node.cases) {
      const caseFlow = analyzeOutParameterFlow(
        parser,
        currentFunctionName,
        outParameters,
        matchExprFlow.value.normalStates,
        matchCase.result,
      );
      if (!caseFlow.ok) {
        return caseFlow;
      }

      normalStates.push(...caseFlow.value.normalStates);
      returnStates.push(...caseFlow.value.returnStates);
    }

    return ok({ normalStates, returnStates });
  }

  if (node.kind === "function-call") {
    const argFlow = analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.arguments,
    );
    if (!argFlow.ok) {
      return argFlow;
    }

    return ok({
      normalStates: markOutParametersAssignedFromCall(
        parser,
        currentFunctionName,
        node,
        outParameters,
        argFlow.value.normalStates,
      ),
      returnStates: argFlow.value.returnStates,
    });
  }

  if (node.kind === "call") {
    const callFlow = analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      [node.callee, ...node.arguments],
    );
    if (!callFlow.ok) {
      return callFlow;
    }

    return ok({
      normalStates: markOutParametersAssignedFromCall(
        parser,
        currentFunctionName,
        node,
        outParameters,
        callFlow.value.normalStates,
      ),
      returnStates: callFlow.value.returnStates,
    });
  }

  if (node.kind === "binary" || node.kind === "comparison") {
    return analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      [node.left, node.right],
    );
  }

  if (node.kind === "logical") {
    const leftFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.left,
    );
    if (!leftFlow.ok) {
      return leftFlow;
    }

    const rightFlow = analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      leftFlow.value.normalStates,
      node.right,
    );
    if (!rightFlow.ok) {
      return rightFlow;
    }

    return ok({
      normalStates: leftFlow.value.normalStates,
      returnStates: [
        ...leftFlow.value.returnStates,
        ...rightFlow.value.returnStates,
      ],
    });
  }

  if (node.kind === "unary-logical") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.operand,
    );
  }

  if (node.kind === "unary-op") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.operand,
    );
  }

  if (node.kind === "is") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.expression,
    );
  }

  if (node.kind === "union-wrap") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.expression,
    );
  }

  if (node.kind === "field-access") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.object,
    );
  }

  if (node.kind === "struct-instantiation") {
    return analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.fields.map((field) => field.value),
    );
  }

  if (node.kind === "array-literal") {
    return analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.generator ? [node.generator] : node.elements,
    );
  }

  if (node.kind === "array-access") {
    return analyzeOutParameterChildren(
      parser,
      currentFunctionName,
      outParameters,
      states,
      [node.array, node.index],
    );
  }

  if (node.kind === "array-slice") {
    return analyzeOutParameterFlow(
      parser,
      currentFunctionName,
      outParameters,
      states,
      node.array,
    );
  }

  return ok({ normalStates: cloneAssignedStates(states), returnStates: [] });
}

export function validateOutParameterAssignments(
  parser: Parser,
  currentFunctionName: string,
  parameters: FunctionParameter[],
  body: ASTNode,
): Result<void, string> {
  const outParameters = new Set(
    parameters
      .filter((parameter) => parameter.out)
      .map((parameter) => parameter.name),
  );
  if (outParameters.size === 0) {
    return ok(undefined);
  }

  const flow = analyzeOutParameterFlow(
    parser,
    currentFunctionName,
    outParameters,
    [new Set<string>()],
    body,
  );
  if (!flow.ok) {
    return flow;
  }

  const exitStates = [...flow.value.returnStates, ...flow.value.normalStates];
  for (const state of exitStates) {
    for (const parameterName of outParameters) {
      if (!state.has(parameterName)) {
        return err(
          "Out parameter '" +
            parameterName +
            "' must be assigned on all control-flow paths before the function returns",
        );
      }
    }
  }

  return ok(undefined);
}

export function parseFunctionStatement(
  parser: Parser,
): Result<ASTNode, string> {
  const signatureResult = parseFunctionSignatureHead(parser, false, true);
  if (!signatureResult.ok) {
    return signatureResult;
  }
  const functionName = signatureResult.value.name;
  const typeParameters = signatureResult.value.typeParameters;
  const typeParameterConstraints =
    signatureResult.value.typeParameterConstraints;
  const parameters = signatureResult.value.parameters;
  const explicitReturnType = signatureResult.value.hasExplicitReturnType
    ? signatureResult.value.returnType
    : undefined;
  let returnType = signatureResult.value.returnType;
  let instanceMetadata: InstanceValueMetadata | undefined;

  // Expect '=>'
  const arrowTok = current(parser);
  if (arrowTok.type !== "ARROW") {
    return err("Expected '=>' after return type");
  }
  advance(parser);

  // Register function in parser context BEFORE parsing body
  // This allows recursive calls to find the function
  setOrUpdateFunctionOverload(parser, functionName, {
    typeParameters,
    typeParameterConstraints,
    parameters,
    returnType,
  });

  // Assign mangled names for local overloads (like top-level prescan does)
  // and update the scope registration to use the mangled name
  const fnEntry = parser.functions.get(functionName);
  let scopeRegistrationName = functionName;
  if (fnEntry?.overloads) {
    if (!fnEntry.mangledName) {
      fnEntry.mangledName = functionName + "$$0";
      const existingBinding = parser.currentScope.members.get(functionName);
      if (existingBinding) {
        parser.currentScope.members.delete(functionName);
        parser.currentScope.members.set(fnEntry.mangledName, existingBinding);
      }
    }
    const newOverload = fnEntry.overloads[fnEntry.overloads.length - 1];
    if (newOverload && !newOverload.mangledName) {
      newOverload.mangledName = functionName + "$$" + fnEntry.overloads.length;
    }
    // Use this function's specific mangled name based on its signature
    scopeRegistrationName = getCurrentFunctionMangledName(
      parser,
      functionName,
      parameters,
      returnType,
    );
  }

  registerScopeFunction(
    parser,
    scopeRegistrationName,
    parameters,
    returnType,
    typeParameters,
  );

  // Parse function body
  // Save current variable scope and loop context
  const savedVariables = new Map(parser.variables);
  const savedScope = parser.currentScope;
  const savedInLoop = parser.inLoop;
  const savedGenericTypeParameters = [...parser.genericTypeParameters];
  const savedGenericTypeConstraints = new Map(parser.genericTypeConstraints);
  const savedCurrentFunctionReturnType = parser.currentFunctionReturnType;
  parser.inLoop = false;
  parser.genericTypeParameters = [
    ...savedGenericTypeParameters,
    ...typeParameters,
  ];
  parser.genericTypeConstraints = new Map(savedGenericTypeConstraints);
  if (typeParameterConstraints) {
    for (const [typeParameter, constraints] of typeParameterConstraints) {
      parser.genericTypeConstraints.set(typeParameter, [...constraints]);
    }
  }
  parser.currentFunctionReturnType =
    explicitReturnType ?? functionName;
  enterCallableScope(parser, savedScope, parameters);

  const bodyTok = current(parser);
  let body: ASTNode;

  if (bodyTok.type === "LBRACE") {
    // Block body with statements - handle manually to support implicit return
    advance(parser); // consume LBRACE

    const statements: ASTNode[] = [];
    const blockResult = parseStatementBlock(parser, statements);
    if (!blockResult.ok) {
      restoreFunctionParsingState(
        parser,
        savedVariables,
        savedScope,
        savedInLoop,
        savedGenericTypeParameters,
        savedGenericTypeConstraints,
        savedCurrentFunctionReturnType,
      );
      return blockResult;
    }

    // Try to parse a final expression (required when return type is not Void)
    let result: ASTNode = { kind: "number", value: "0" };

    const exprTok = current(parser);
    if (exprTok.type !== "RBRACE") {
      const exprResult = parseExpression(parser);
      if (exprResult.ok) {
        result = exprResult.value;
      } else {
        if (current(parser).type !== "RBRACE") {
          restoreFunctionParsingState(
            parser,
            savedVariables,
            savedScope,
            savedInLoop,
            savedGenericTypeParameters,
            savedGenericTypeConstraints,
            savedCurrentFunctionReturnType,
          );
          return exprResult;
        }
      }
    } else if (explicitReturnType && returnType !== "Void") {
      // No final expression ΓÇö acceptable only if last statement is a return
      const lastStmt =
        statements.length > 0 ? statements[statements.length - 1] : undefined;
      if (!lastStmt || lastStmt.kind !== "return") {
        return restoreFunctionParsingStateWithError(
          parser,
          {
            variables: savedVariables,
            scope: savedScope,
            inLoop: savedInLoop,
            genericTypeParameters: savedGenericTypeParameters,
            genericTypeConstraints: savedGenericTypeConstraints,
            currentFunctionReturnType: savedCurrentFunctionReturnType,
          },
          "Function body must end with an expression when return type is not Void",
        );
      }
    }

    // Expect closing brace
    if (current(parser).type !== "RBRACE") {
      restoreFunctionParsingState(
        parser,
        savedVariables,
        savedScope,
        savedInLoop,
        savedGenericTypeParameters,
        savedGenericTypeConstraints,
        savedCurrentFunctionReturnType,
      );
      return err("Expected '}'");
    }
    advance(parser);

    body = {
      kind: "block",
      statements,
      result,
    };
  } else {
    // Arrow body
    const assignResult = tryParseAssignment(parser);
    if (!assignResult.ok) {
      restoreFunctionParsingState(
        parser,
        savedVariables,
        savedScope,
        savedInLoop,
        savedGenericTypeParameters,
        savedGenericTypeConstraints,
        savedCurrentFunctionReturnType,
      );
      return assignResult;
    }

    if (assignResult.value !== undefined) {
      if (explicitReturnType && returnType !== "Void") {
        restoreFunctionParsingState(
          parser,
          savedVariables,
          savedScope,
          savedInLoop,
          savedGenericTypeParameters,
          savedGenericTypeConstraints,
          savedCurrentFunctionReturnType,
        );
        return err(
          "Function with non-Void return type must have an expression body",
        );
      }
      body = assignResult.value;
    } else {
      const exprResult = parseExpression(parser);
      if (!exprResult.ok) {
        restoreFunctionParsingState(
          parser,
          savedVariables,
          savedScope,
          savedInLoop,
          savedGenericTypeParameters,
          savedGenericTypeConstraints,
          savedCurrentFunctionReturnType,
        );
        return exprResult;
      }

      if (explicitReturnType && returnType === "Void") {
        restoreFunctionParsingState(
          parser,
          savedVariables,
          savedScope,
          savedInLoop,
          savedGenericTypeParameters,
          savedGenericTypeConstraints,
          savedCurrentFunctionReturnType,
        );
        return err(
          "Function with Void return type cannot have an expression body",
        );
      }

      body = exprResult.value;
    }

    // Expect ';' after expression
    const semiTok = current(parser);
    if (semiTok.type !== "SEMICOLON") {
      return restoreFunctionParsingStateWithError(
        parser,
        {
          variables: savedVariables,
          scope: savedScope,
          inLoop: savedInLoop,
          genericTypeParameters: savedGenericTypeParameters,
          genericTypeConstraints: savedGenericTypeConstraints,
          currentFunctionReturnType: savedCurrentFunctionReturnType,
        },
        "Expected ';' after function arrow expression",
      );
    }
    advance(parser);
  }

  const coercedBody = coerceFunctionBodyToReturnType(parser, body, returnType);
  if (explicitReturnType) {
    if (!coercedBody.ok) {
      restoreFunctionParsingState(
        parser,
        savedVariables,
        savedScope,
        savedInLoop,
        savedGenericTypeParameters,
        savedGenericTypeConstraints,
        savedCurrentFunctionReturnType,
      );
      return coercedBody;
    }
    body = coercedBody.value;
  } else {
    const inferredReturnType = inferFunctionReturnTypeFromBody(parser, body);
    if (!inferredReturnType.ok) {
      restoreFunctionParsingState(
        parser,
        savedVariables,
        savedScope,
        savedInLoop,
        savedGenericTypeParameters,
        savedGenericTypeConstraints,
        savedCurrentFunctionReturnType,
      );
      return inferredReturnType;
    }

    returnType = inferredReturnType.value;

    // If this function infers its return type as its own name (constructor returning `this`),
    // register it as a struct-like type so annotations like `let x : Square` are valid.
    if (returnType === functionName && !parser.structNames.has(functionName)) {
      parser.structNames.add(functionName);
    }

    setOrUpdateFunctionOverload(parser, functionName, {
      typeParameters,
      typeParameterConstraints,
      parameters,
      returnType,
    });
    updateScopeFunctionBinding(
      savedScope,
      functionName,
      parameters,
      returnType,
      typeParameters,
    );

    const inferredCoercedBody = coerceFunctionBodyToReturnType(
      parser,
      body,
      returnType,
    );
    if (!inferredCoercedBody.ok) {
      restoreFunctionParsingState(
        parser,
        savedVariables,
        savedScope,
        savedInLoop,
        savedGenericTypeParameters,
        savedGenericTypeConstraints,
        savedCurrentFunctionReturnType,
      );
      return inferredCoercedBody;
    }

    body = inferredCoercedBody.value;
  }

  const outAssignmentValidation = validateOutParameterAssignments(
    parser,
    functionName,
    parameters,
    body,
  );
  if (!outAssignmentValidation.ok) {
    restoreFunctionParsingState(
      parser,
      savedVariables,
      savedScope,
      savedInLoop,
      savedGenericTypeParameters,
      savedGenericTypeConstraints,
      savedCurrentFunctionReturnType,
    );
    return outAssignmentValidation;
  }

  // Fix up local function FunctionNode names: when a function gains overloads
  // after its FunctionNode was already emitted (with original name), update
  // the node name to the correct mangled name.
  if (body.kind === "block") {
    for (const stmt of body.statements) {
      if (stmt.kind !== "function") continue;
      const baseName = stripMangledOverloadSuffix(stmt.name);
      const fnInfo = parser.functions.get(baseName);
      if (!fnInfo?.overloads) continue;
      const mangledName = getCurrentFunctionMangledName(
        parser,
        baseName,
        stmt.parameters,
        stmt.returnType,
      );
      if (mangledName !== stmt.name) {
        const previousName = stmt.name;
        const binding = parser.currentScope.members.get(previousName);
        stmt.name = mangledName;
        // Also update the scope member key so the scope object getter uses the right name
        if (binding) {
          parser.currentScope.members.delete(previousName);
          parser.currentScope.members.set(mangledName, binding);
        }
      }
    }
  }

  const constructorMetadata = buildConstructorInstanceMetadata(
    parser,
    functionName,
    body,
  );
  if (!constructorMetadata.ok) {
    restoreFunctionParsingState(
      parser,
      savedVariables,
      savedScope,
      savedInLoop,
      savedGenericTypeParameters,
      savedGenericTypeConstraints,
      savedCurrentFunctionReturnType,
    );
    return constructorMetadata;
  }
  instanceMetadata = constructorMetadata.value;

  setOrUpdateFunctionOverload(parser, functionName, {
    typeParameters,
    typeParameterConstraints,
    parameters,
    returnType,
    instanceMetadata,
  });

  // Restore variable scope and loop context
  restoreFunctionParsingState(
    parser,
    savedVariables,
    savedScope,
    savedInLoop,
    savedGenericTypeParameters,
    savedGenericTypeConstraints,
    savedCurrentFunctionReturnType,
  );

  return ok({
    kind: "function",
    name: getCurrentFunctionMangledName(
      parser,
      functionName,
      parameters,
      returnType,
    ),
    typeParameters,
    typeParameterConstraints,
    parameters,
    returnType,
    body,
    isDestructor: isDestructorFunction(parser, functionName),
  });
}

export function parseObjectStatement(parser: Parser): Result<ASTNode, string> {
  const objectTok = current(parser);
  if (objectTok.type !== "KEYWORD" || objectTok.value !== "object") {
    return err("Expected 'object'");
  }
  advance(parser);

  const nameTok = current(parser);
  if (nameTok.type !== "IDENTIFIER") {
    return err("Expected object name");
  }

  const objectName = nameTok.value;
  const objectNameCheck = checkReservedKeyword(objectName, "function name");
  if (!objectNameCheck.ok) {
    return objectNameCheck;
  }
  if (parser.variables.has(objectName)) {
    return err("Variable '" + objectName + "' already declared");
  }
  advance(parser);

  if (current(parser).type !== "LBRACE") {
    return err("Expected '{' after object name");
  }

  const objectType = createObjectTypeName(objectName);
  const objectScope = createScopeFrame(parser.currentScope, "object");
  const savedVariables = new Map(parser.variables);
  const savedFunctions = new Map(parser.functions);
  const savedScope = parser.currentScope;
  const savedInLoop = parser.inLoop;

  parser.variables.set(objectName, {
    type: objectType,
    mutable: false,
    moved: false,
  });
  registerScopeVariable(parser, objectName, objectType, false, false);
  parser.objects.set(objectType, {
    name: objectName,
    type: objectType,
    scope: objectScope,
  });

  parser.currentScope = objectScope;

  advance(parser);

  const bodyStatements: ASTNode[] = [];
  const bodyResult = parseStatementBlock(parser, bodyStatements);
  if (!bodyResult.ok) {
    parser.variables = savedVariables;
    parser.functions = savedFunctions;
    parser.currentScope = savedScope;
    parser.inLoop = savedInLoop;
    return bodyResult;
  }

  if (current(parser).type !== "RBRACE") {
    parser.variables = savedVariables;
    parser.functions = savedFunctions;
    parser.currentScope = savedScope;
    parser.inLoop = savedInLoop;
    return err("Expected '}'");
  }
  advance(parser);

  parser.variables = savedVariables;
  parser.variables.set(objectName, {
    type: objectType,
    mutable: false,
    moved: false,
  });
  parser.functions = savedFunctions;
  parser.currentScope = savedScope;
  parser.inLoop = savedInLoop;

  return ok({
    kind: "object",
    name: objectName,
    type: objectType,
    body: bodyStatements,
    scope: objectScope,
  });
}

export function tryParseClosureLiteral(
  parser: Parser,
): Result<ClosureNode | undefined, string> {
  const savedPos = parser.pos;
  if (current(parser).type !== "LPAREN") {
    return ok(undefined);
  }
  advance(parser);

  if (!canStartClosureParameterList(parser)) {
    parser.pos = savedPos;
    return ok(undefined);
  }

  const parametersResult = parseFunctionParameters(parser, true);
  if (!parametersResult.ok) {
    return parametersResult;
  }
  const parameters = parametersResult.value;

  if (current(parser).type !== "ARROW") {
    parser.pos = savedPos;
    return ok(undefined);
  }
  advance(parser);

  const savedVariables = new Map(parser.variables);
  const savedScope = parser.currentScope;
  enterCallableScope(parser, savedScope, parameters);

  let body: ASTNode;
  if (current(parser).type === "LBRACE") {
    const statementsResult = parseBlockStatementsWithoutRbrace(parser);
    if (!statementsResult.ok) {
      parser.variables = savedVariables;
      parser.currentScope = savedScope;
      return statementsResult;
    }

    const blockBody = createBlockBodyWithOptionalExpression(
      statementsResult.value,
      parser,
    );
    if (!blockBody.ok) {
      parser.variables = savedVariables;
      parser.currentScope = savedScope;
      return blockBody;
    }

    if (current(parser).type !== "RBRACE") {
      parser.variables = savedVariables;
      parser.currentScope = savedScope;
      return err("Expected '}'");
    }
    advance(parser);

    body = blockBody.value;
  } else {
    const assignResult = tryParseAssignment(parser);
    if (!assignResult.ok) {
      parser.variables = savedVariables;
      parser.currentScope = savedScope;
      return assignResult;
    }

    if (assignResult.value !== undefined) {
      body = assignResult.value;
    } else {
      const exprResult = parseExpression(parser);
      if (!exprResult.ok) {
        parser.variables = savedVariables;
        parser.currentScope = savedScope;
        return exprResult;
      }
      body = exprResult.value;
    }
  }

  const returnTypeResult = inferFunctionReturnTypeFromBody(parser, body);
  if (!returnTypeResult.ok) {
    parser.variables = savedVariables;
    parser.currentScope = savedScope;
    return returnTypeResult;
  }
  const returnType = returnTypeResult.value;

  parser.variables = savedVariables;
  parser.currentScope = savedScope;
  return ok({
    kind: "closure",
    parameters,
    returnType,
    body,
  });
}

/**
 * Parses struct field list from `{` to `}` (inclusive).
 * Returns the parsed fields or an error.
 */
export function parseStructFieldList(
  parser: Parser,
): Result<StructField[], string> {
  // Expect '{'
  if (current(parser).type !== "LBRACE") {
    return err("Expected '{' after struct name");
  }
  advance(parser);

  const fields: StructField[] = [];
  const fieldNames = new Set<string>();

  while (current(parser).type !== "RBRACE") {
    // Check for mut modifier
    let mutable = false;
    const tok = current(parser);
    if (tok.type === "KEYWORD") {
      const keywordTok = tok as KeywordToken;
      if (keywordTok.value === "mut") {
        mutable = true;
        advance(parser);
      }
    }

    // Get field name
    if (current(parser).type !== "IDENTIFIER") {
      return err("Expected field name");
    }
    const fieldNameTok = current(parser) as IdentifierToken;
    const fieldName = fieldNameTok.value;
    advance(parser);

    // Reject duplicate field names
    const prevSize = fieldNames.size;
    fieldNames.add(fieldName);
    if (fieldNames.size === prevSize) {
      return err("Duplicate field name '" + fieldName + "'");
    }

    // Expect ':'
    if (current(parser).type !== "COLON") {
      return err("Expected ':' after field name");
    }
    advance(parser);

    // Parse field type
    const fieldTypeResult = parseTypeReference(parser);
    if (!fieldTypeResult.ok) {
      return fieldTypeResult;
    }
    const fieldType = fieldTypeResult.value.type;

    fields.push({
      name: fieldName,
      type: fieldType,
      mutable,
      aliasType: fieldTypeResult.value.aliasType,
      destructorFunction: fieldTypeResult.value.destructorFunction,
    });

    // Expect ';'
    if (current(parser).type !== "SEMICOLON") {
      return err("Expected ';' after field");
    }
    advance(parser);
  }

  if (current(parser).type !== "RBRACE") {
    return err("Expected '}' after struct fields");
  }
  advance(parser); // consume '}'

  return ok(fields);
}

export function parseStructStatement(parser: Parser): Result<ASTNode, string> {
  // Expect 'struct'
  const structTok = current(parser);
  if (
    structTok.type !== "KEYWORD" ||
    (structTok as KeywordToken).value !== "struct"
  ) {
    return err("Expected 'struct'");
  }
  advance(parser);

  // Expect struct name
  const nameTok = current(parser);
  if (nameTok.type !== "IDENTIFIER") {
    return err("Expected struct name");
  }
  const structName = (nameTok as IdentifierToken).value;
  advance(parser);

  const typeParametersResult = parseGenericParameterList(parser);
  if (!typeParametersResult.ok) {
    return typeParametersResult;
  }

  const fieldsResult = withTemporaryGenericTypeParameters(
    parser,
    typeParametersResult.value,
    () => parseStructFieldList(parser),
  );
  if (!fieldsResult.ok) {
    return fieldsResult;
  }

  return ok({
    kind: "struct",
    name: structName,
    typeParameters: typeParametersResult.value,
    fields: fieldsResult.value,
  });
}

export function parseExpression(parser: Parser): Result<ASTNode, string> {
  const tok = current(parser);

  // Check for if expression
  if (tok.type === "KEYWORD" && tok.value === "if") {
    return parseIfStatement(parser);
  }

  // Check for match expression
  if (tok.type === "KEYWORD" && tok.value === "match") {
    return parseMatchExpression(parser);
  }

  return parseLogicalOr(parser);
}

export function parseLeftAssociative(
  parser: Parser,
  nextParser: CallableFunction,
  stepParser: CallableFunction,
): Result<ASTNode, string> {
  const left = nextParser(parser) as Result<ASTNode, string>;
  if (!left.ok) {
    return left;
  }

  let node = left.value;

  while (true) {
    const nextNode = stepParser(node) as Result<ASTNode | undefined, string>;
    if (!nextNode.ok) {
      return nextNode;
    }
    if (!nextNode.value) {
      break;
    }
    node = nextNode.value;
  }

  return ok(node);
}

export function parseBinary(
  parser: Parser,
  config: ParseBinaryConfig,
): Result<ASTNode, string> {
  return parseLeftAssociative(
    parser,
    config.nextParser,
    (node: ASTNode): Result<ASTNode | undefined, string> => {
      const tok = current(parser);
      if (!config.tokenMatcher(tok)) {
        return ok(undefined);
      }

      const operator = config.operatorExtractor(tok);
      advance(parser);

      const right = config.nextParser(parser);
      if (!right.ok) {
        return right;
      }

      return ok(config.nodeMaker(operator, node, right.value));
    },
  );
}

export function logicalNodeMaker(
  op: string,
  left: ASTNode,
  right: ASTNode,
): LogicalNode {
  return {
    kind: "logical",
    operator: op as "&&" | "||",
    left,
    right,
  };
}

export function comparisonNodeMaker(
  op: string,
  left: ASTNode,
  right: ASTNode,
): ComparisonNode {
  return {
    kind: "comparison",
    operator: op as "<" | ">" | "<=" | ">=" | "==" | "!=",
    left,
    right,
  };
}

export function parseComparison(parser: Parser): Result<ASTNode, string> {
  return parseLeftAssociative(
    parser,
    parseUnaryLogical,
    (node: ASTNode): Result<ASTNode | undefined, string> => {
      const tok = current(parser);
      if (tok.type === "COMPARISON") {
        advance(parser);

        const right = parseUnaryLogical(parser);
        if (!right.ok) {
          return right;
        }

        return ok(comparisonNodeMaker(tok.value, node, right.value));
      }

      if (tok.type === "KEYWORD" && tok.value === "is") {
        advance(parser);

        const checkedType = parseTypeAnnotation(parser);
        if (!checkedType.ok) {
          return checkedType;
        }

        const isMatch = evaluateIsType(parser, node, checkedType.value);
        if (!isMatch.ok) {
          return isMatch;
        }

        return ok({
          kind: "is",
          expression: node,
          checkedType: checkedType.value,
          matches: isMatch.value,
          runtimeCheck: expressionHasUnionType(parser, node),
        } as IsNode);
      }

      return ok(undefined);
    },
  );
}

export function parseLogicalOr(parser: Parser): Result<ASTNode, string> {
  return parseBinary(parser, {
    nextParser: parseLogicalAnd,
    tokenMatcher: (tok: Token) => tok.type === "LOGICAL" && tok.value === "||",
    operatorExtractor: (tok: Token) =>
      tok.type === "LOGICAL" ? tok.value : "",
    nodeMaker: logicalNodeMaker,
  });
}

export function parseLogicalAnd(parser: Parser): Result<ASTNode, string> {
  return parseBinary(parser, {
    nextParser: parseComparison,
    tokenMatcher: (tok: Token) => tok.type === "LOGICAL" && tok.value === "&&",
    operatorExtractor: (tok: Token) =>
      tok.type === "LOGICAL" ? tok.value : "",
    nodeMaker: logicalNodeMaker,
  });
}

export function parseUnaryLogical(parser: Parser): Result<ASTNode, string> {
  const tok = current(parser);

  if (tok.type === "LOGICAL" && tok.value === "!") {
    advance(parser);

    const operand = parseUnaryLogical(parser);
    if (!operand.ok) {
      return operand;
    }

    return ok({
      kind: "unary-logical",
      operator: "!",
      operand: operand.value,
    });
  }

  return parseAdditive(parser);
}

export function parseBinaryOperator(
  parser: Parser,
  // eslint-disable-next-line no-unused-vars
  nextParser: (p: Parser) => Result<ASTNode, string>,
  operators: Set<string>,
  castType: "+" | "-" | "*" | "/" | "%",
): Result<ASTNode, string> {
  const result = parseBinary(parser, {
    nextParser,
    tokenMatcher: (tok: Token) =>
      tok.type === "OPERATOR" && operators.has(tok.value),
    operatorExtractor: (tok: Token) => (tok as OperatorToken).value,
    nodeMaker: (
      operator: string,
      left: ASTNode,
      right: ASTNode,
    ): BinaryNode => ({
      kind: "binary",
      operator: operator as typeof castType,
      left,
      right,
    }),
  });

  // Validate that neither operand has pointer type (no pointer arithmetic)
  if (result.ok && result.value.kind === "binary") {
    const leftType = inferExpressionType(result.value.left, parser);
    const rightType = inferExpressionType(result.value.right, parser);

    if (leftType.ok && leftType.value.startsWith("*")) {
      return err("Cannot use pointer in arithmetic operation");
    }
    if (rightType.ok && rightType.value.startsWith("*")) {
      return err("Cannot use pointer in arithmetic operation");
    }
  }

  return result;
}

export function parseAdditive(parser: Parser): Result<ASTNode, string> {
  return parseBinaryOperator(
    parser,
    parseMultiplicative,
    new Set(["+", "-"]),
    "+" as "+" | "-",
  );
}

export function parseMultiplicative(parser: Parser): Result<ASTNode, string> {
  return parseBinaryOperator(
    parser,
    parseUnary,
    new Set(["*", "/", "%"]),
    "*" as "*" | "/" | "%",
  );
}

export function parseUnary(parser: Parser): Result<ASTNode, string> {
  const tok = current(parser);

  // Handle unary prefix operators: * (dereference) and & (address-of)
  if (tok.type === "OPERATOR" && tok.value === "*") {
    advance(parser);
    const operandResult = parseUnary(parser); // Right-associative: **a means *(*a)
    if (!operandResult.ok) {
      return operandResult;
    }

    // Validate that we're dereferencing a pointer type
    const operandTypeResult = inferExpressionType(operandResult.value, parser);
    if (operandTypeResult.ok && !operandTypeResult.value.startsWith("*")) {
      return err(
        "Cannot dereference non-pointer type: " + operandTypeResult.value,
      );
    }

    return ok({
      kind: "unary-op",
      operator: "*",
      operand: operandResult.value,
    } as UnaryOpNode);
  }

  if (tok.type === "ADDRESS_OF") {
    advance(parser);

    // Check for 'move' keyword after & (ownership transfer)
    const nextTokForMove = current(parser);
    if (
      nextTokForMove.type === "KEYWORD" &&
      nextTokForMove.value === "move"
    ) {
      advance(parser);
      const operandResult = parseUnary(parser);
      if (!operandResult.ok) {
        return operandResult;
      }
      const operandNode = operandResult.value;
      if (operandNode.kind !== "variable") {
        return err({
          value: operandNode.kind,
          message: "Cannot move a non-variable expression",
          reason: "&move requires a named variable to transfer ownership",
          fix: "Assign the expression to a variable first, then use &move on the variable",
        } as unknown as string);
      }
      return ok({
        kind: "unary-op",
        operator: "&move",
        operand: operandNode,
      } as UnaryOpNode);
    }

    // Check for 'mut' keyword after &
    const isMutable = tryConsumeMutKeyword(parser);

    const operandResult = parseUnary(parser); // Right-associative: &&a means &(&a)
    if (!operandResult.ok) {
      return operandResult;
    }

    let operandNode = operandResult.value;
    if (operandNode.kind === "variable") {
      const arrayInfo = getArrayLikeInfo(operandNode, parser);
      if (arrayInfo && !arrayInfo.isSlice && arrayInfo.length !== undefined) {
        operandNode = {
          kind: "array-slice",
          array: operandNode,
          start: 0,
          end: arrayInfo.length,
        } as ArraySliceNode;
      }
    }

    // Validate that we're taking address of a variable or array slice
    if (operandNode.kind !== "variable" && operandNode.kind !== "array-slice") {
      return err("Cannot take address of non-variable expression");
    }

    // Validate that for &mut, the underlying array/variable must be mutable
    if (isMutable) {
      const targetNode =
        operandNode.kind === "array-slice" ? operandNode.array : operandNode;
      if (targetNode.kind !== "variable") {
        return err("Cannot take mutable reference to non-variable expression");
      }
      const varName = targetNode.name;
      const varResult = getVariable(parser, varName);
      if (!varResult.ok) {
        return varResult;
      }
      if (!varResult.value.mutable) {
        return err(
          `Cannot take mutable reference to immutable variable '${varName}'`,
        );
      }
    }

    return ok({
      kind: "unary-op",
      operator: isMutable ? "&mut" : "&",
      operand: operandNode,
    } as UnaryOpNode);
  }

  // Otherwise, parse postfix expression
  return parsePostfix(parser);
}

export function parsePostfix(parser: Parser): Result<ASTNode, string> {
  let result = parsePrimary(parser);
  if (!result.ok) {
    return result;
  }

  let node = result.value;

  // Handle postfix operations: field access (dot) and array access (brackets)
  while (true) {
    if (current(parser).type === "LPAREN") {
      const callResult = parsePostfixCall(parser, node);
      if (!callResult.ok) {
        return callResult;
      }

      node = callResult.value;
    } else if (current(parser).type === "DOT") {
      advance(parser); // consume DOT
      const fieldToken = current(parser);

      // Expect identifier for field name or property
      if (
        fieldToken.type !== "IDENTIFIER" &&
        !(fieldToken.type === "KEYWORD" && fieldToken.value === "this")
      ) {
        return err("Expected field name or property after '.'");
      }
      const fieldName =
        fieldToken.type === "IDENTIFIER"
          ? (fieldToken as IdentifierToken).value
          : "this";
      advance(parser);

      const explicitTypeArguments = tryParseTypeArgumentList(parser, [
        "LPAREN",
      ]);
      if (!explicitTypeArguments.ok) {
        return explicitTypeArguments;
      }

      // Check if this is the 'length' property
      if (fieldName === "length") {
        // Special case for .length on arrays - return as field-access which will be handled during codegen
        node = {
          kind: "field-access",
          object: node,
          fieldName: "length",
          typeArguments: explicitTypeArguments.value,
        } as FieldAccessNode;
      } else {
        node = {
          kind: "field-access",
          object: node,
          fieldName,
          typeArguments: explicitTypeArguments.value,
        } as FieldAccessNode;
      }
    } else if (current(parser).type === "LBRACKET") {
      advance(parser); // consume [

      const arrayInfo = getArrayLikeInfo(node, parser);

      const isRangeStart =
        (current(parser).type === "DOT" &&
          parser.tokens[parser.pos + 1]?.type === "DOT") ||
        ((current(parser).type === "NUMBER" ||
          current(parser).type === "IDENTIFIER") &&
          parser.tokens[parser.pos + 1]?.type === "DOT" &&
          parser.tokens[parser.pos + 2]?.type === "DOT");

      if (isRangeStart) {
        if (!arrayInfo || arrayInfo.length === undefined) {
          return err("Can only slice arrays with known compile-time length");
        }

        let start = 0;
        let end = arrayInfo.length;

        if (
          current(parser).type !== "DOT" ||
          parser.tokens[parser.pos + 1]?.type !== "DOT"
        ) {
          const startTok = current(parser);
          if (startTok.type === "IDENTIFIER") {
            return err(
              "Array slice bounds must be constant proven in bounds; dynamic bounds not allowed",
            );
          }
          if (startTok.type !== "NUMBER") {
            return err("Expected slice start bound");
          }

          const bareStart = splitNumberLiteral(startTok.value).numericPart;
          if (bareStart.startsWith("-")) {
            return err("Array slice start must be non-negative");
          }
          if (bareStart.includes(".")) {
            return err("Array slice bounds must be integer values");
          }
          start = Number(bareStart);
          advance(parser);
        }

        if (
          current(parser).type !== "DOT" ||
          parser.tokens[parser.pos + 1]?.type !== "DOT"
        ) {
          return err("Expected '..' in array slice");
        }
        advance(parser);
        advance(parser);

        if (current(parser).type !== "RBRACKET") {
          const endTok = current(parser);
          if (endTok.type === "IDENTIFIER") {
            return err(
              "Array slice bounds must be constant proven in bounds; dynamic bounds not allowed",
            );
          }
          if (endTok.type !== "NUMBER") {
            return err("Expected slice end bound");
          }

          const bareEnd = splitNumberLiteral(endTok.value).numericPart;
          if (bareEnd.startsWith("-")) {
            return err("Array slice end must be non-negative");
          }
          if (bareEnd.includes(".")) {
            return err("Array slice bounds must be integer values");
          }
          end = Number(bareEnd);
          advance(parser);
        }

        if (current(parser).type !== "RBRACKET") {
          return err("Expected ']' after array slice");
        }
        advance(parser);

        if (start > end) {
          return err("Array slice start must be <= end");
        }
        if (end > arrayInfo.length) {
          return err(
            "Array slice end " +
              end +
              " is out of bounds for array of length " +
              arrayInfo.length,
          );
        }

        node = {
          kind: "array-slice",
          array: node,
          start,
          end,
        } as ArraySliceNode;
        continue;
      }

      // Parse index expression
      const indexResult = parseExpression(parser);
      if (!indexResult.ok) {
        return indexResult;
      }

      if (current(parser).type !== "RBRACKET") {
        return err("Expected ']' after array index");
      }
      advance(parser); // consume ]

      const indexNode = indexResult.value;

      const currentArrayInfo = getArrayLikeInfo(node, parser);
      const indexValidation = validateArrayIndexAccess(
        parser,
        node,
        indexNode,
        currentArrayInfo,
      );
      if (!indexValidation.ok) {
        return indexValidation;
      }

      node = {
        kind: "array-access",
        array: node,
        index: indexNode,
      } as ArrayAccessNode;
    } else {
      break;
    }
  }

  return ok(node);
}

export function tryGetDirectMemberCallableInfo(
  parser: Parser,
  callee: FieldAccessNode,
  args: ASTNode[],
): Result<ParsedFunctionType | undefined, string> {
  const instantiateBoundCallable = (
    callableType: ParsedFunctionType,
    typeParameters: string[] = [],
  ): Result<ParsedFunctionType, string> => {
    const callableDescription =
      callee.object.kind === "module-reference"
        ? callee.object.moduleName + "." + callee.fieldName
        : callee.fieldName;

    return instantiateParsedFunctionType(
      parser,
      callableDescription,
      callableType,
      typeParameters,
      callee.typeArguments,
      args,
    );
  };

  const resolvedThisMember = resolveThisMemberAccess(callee);
  if (!resolvedThisMember.ok) {
    return resolvedThisMember;
  }

  if (resolvedThisMember.value) {
    const parsedCallableType = parseCallableTypeString(
      resolvedThisMember.value.binding.type,
    );
    if (!parsedCallableType) {
      return ok(undefined);
    }

    return instantiateBoundCallable(
      parsedCallableType,
      resolvedThisMember.value.binding.typeParameters,
    );
  }

  const instanceMethod = getBoundInstanceMethodCallableInfo(parser, callee);
  if (!instanceMethod.ok) {
    return instanceMethod;
  }
  if (instanceMethod.value) {
    return ok(instanceMethod.value);
  }

  const ownerType = inferExpressionType(callee.object, parser);
  if (!ownerType.ok) {
    return ok(undefined);
  }

  const objectInfo = parser.objects.get(ownerType.value);
  if (objectInfo) {
    const binding = objectInfo.scope.members.get(callee.fieldName);
    if (!binding) {
      return ok(undefined);
    }

    const parsedBoundCallableType = parseCallableTypeString(binding.type);
    if (!parsedBoundCallableType) {
      return ok(undefined);
    }

    return instantiateBoundCallable(
      parsedBoundCallableType,
      binding.typeParameters,
    );
  }

  const contractInfo = parser.contracts.get(ownerType.value);
  if (contractInfo) {
    const methodSig = contractInfo.methods.get(callee.fieldName);
    if (methodSig) {
      return ok(methodSig);
    }
    return ok(undefined);
  }

  const ownerTypeLtIdx = ownerType.value.indexOf("<");
  const ownerTypeGtIdx = ownerType.value.lastIndexOf(">");
  if (ownerTypeLtIdx !== -1 && ownerTypeGtIdx > ownerTypeLtIdx) {
    const baseContractName = ownerType.value.slice(0, ownerTypeLtIdx);
    const typeArgsStr = ownerType.value.slice(ownerTypeLtIdx + 1, ownerTypeGtIdx);
    const genericContractInfo = parser.contracts.get(baseContractName);
    if (genericContractInfo && genericContractInfo.typeParameters.length > 0) {
      const typeArgs = typeArgsStr.split(",").map((s) => s.trim());
      const substitutions = new Map(
        genericContractInfo.typeParameters.map((tp, i) => [tp, typeArgs[i] ?? tp]),
      );
      const methodSig = genericContractInfo.methods.get(callee.fieldName);
      if (methodSig) {
        let substitutedReturn = methodSig.returnType;
        for (const [tp, replacement] of substitutions) {
          substitutedReturn = substitutedReturn
            .split(tp)
            .join(replacement);
        }
        return ok({ parameterTypes: methodSig.parameterTypes, returnType: substitutedReturn });
      }
      return ok(undefined);
    }
  }

  const memberType = inferContainerMemberType(
    parser,
    callee.object,
    callee.fieldName,
  );
  if (!memberType.ok) {
    return ok(undefined);
  }

  const parsedCallableType = parseCallableTypeString(memberType.value);
  if (!parsedCallableType) {
    return ok(undefined);
  }

  return instantiateBoundCallable(parsedCallableType);
}

export function tryGetExtensionMethodCallableInfoForOverload(
  parser: Parser,
  callee: FieldAccessNode,
  fnInfo: FunctionInfo,
  receiverType: string,
): Result<ParsedFunctionType | undefined, string> {
  const receiverParam = fnInfo.parameters[0];
  if (!receiverParam || receiverParam.name !== "this") {
    return ok(undefined);
  }

  if (fnInfo.typeParameters.length > 0) {
    const bindings = new Map<string, string>();
    const savedGenericTypeParameters = [...parser.genericTypeParameters];
    parser.genericTypeParameters = [
      ...savedGenericTypeParameters,
      ...fnInfo.typeParameters,
    ];

    const bindingResult = inferTypeParameterBindings(
      parser,
      receiverParam.type,
      receiverType,
      bindings,
    );
    parser.genericTypeParameters = savedGenericTypeParameters;
    if (!bindingResult.ok) {
      return ok(undefined);
    }

    for (const typeParameter of fnInfo.typeParameters) {
      if (!bindings.has(typeParameter)) {
        return ok(undefined);
      }
    }

    const parameterTypes: string[] = [];
    for (const parameter of fnInfo.parameters.slice(1)) {
      const substitutedParameterType = substituteTypeParameters(
        parser,
        parameter.type,
        bindings,
      );
      if (!substitutedParameterType.ok) {
        return substitutedParameterType;
      }
      parameterTypes.push(substitutedParameterType.value);
    }

    const substitutedReturnType = substituteTypeParameters(
      parser,
      fnInfo.returnType,
      bindings,
    );
    if (!substitutedReturnType.ok) {
      return substitutedReturnType;
    }

    return ok({
      parameterTypes,
      returnType: substitutedReturnType.value,
    });
  }

  if (!areTypesCompatible(receiverParam.type, receiverType)) {
    return ok(undefined);
  }

  return ok({
    parameterTypes: fnInfo.parameters
      .slice(1)
      .map((parameter: FunctionParameter) => parameter.type),
    returnType: fnInfo.returnType,
  });
}

export function tryGetExtensionMethodCallableInfo(
  parser: Parser,
  callee: FieldAccessNode,
): Result<ExtensionMethodCallableInfo | undefined, string> {
  if (callee.fieldName === "length") {
    return ok(undefined);
  }

  const contractCallable = getContractMethodCallableInfo(parser, callee);
  if (!contractCallable.ok) {
    return contractCallable;
  }
  if (contractCallable.value) {
    return ok({ ...contractCallable.value, callName: callee.fieldName });
  }

  const primaryInfo = parser.functions.get(callee.fieldName);
  if (!primaryInfo) {
    return ok(undefined);
  }

  const receiverType = inferExpressionType(callee.object, parser);
  if (!receiverType.ok) {
    return ok(undefined);
  }

  const allOverloads = getAllFunctionOverloads(primaryInfo);

  for (const overload of allOverloads) {
    const result = tryGetExtensionMethodCallableInfoForOverload(
      parser,
      callee,
      overload,
      receiverType.value,
    );
    if (!result.ok) {
      return result;
    }
    if (result.value) {
      return ok({
        ...result.value,
        callName: overload.mangledName ?? callee.fieldName,
      });
    }
  }

  return ok(undefined);
}

export function parsePostfixCall(
  parser: Parser,
  callee: ASTNode,
): Result<ASTNode, string> {
  advance(parser); // consume LPAREN

  const argsResult = parseCallArguments(parser);
  if (!argsResult.ok) {
    return argsResult;
  }

  if (callee.kind === "field-access") {
    const memberCallable = tryGetDirectMemberCallableInfo(
      parser,
      callee,
      argsResult.value,
    );
    if (!memberCallable.ok) {
      return memberCallable;
    }

    const extensionCallable = tryGetExtensionMethodCallableInfo(parser, callee);
    if (!extensionCallable.ok) {
      return extensionCallable;
    }

    if (memberCallable.value && extensionCallable.value) {
      const instanceMethod = getBoundInstanceMethodCallableInfo(parser, callee);
      if (!instanceMethod.ok) {
        return instanceMethod;
      }

      if (instanceMethod.value) {
        return createValidatedCallNode(
          parser,
          callee,
          argsResult.value,
          memberCallable.value.parameterTypes,
          memberCallable.value.returnType,
        );
      }

      return err(
        "Ambiguous method call '" +
          callee.fieldName +
          "': both a callable member and a this-parameter function match",
      );
    }

    if (extensionCallable.value) {
      const validatedArgs = validateCallArguments(
        parser,
        callee.fieldName,
        argsResult.value,
        extensionCallable.value.parameterTypes,
      );
      if (!validatedArgs.ok) {
        return validatedArgs;
      }

      const receiverType = inferExpressionType(callee.object, parser);
      if (!receiverType.ok) {
        return receiverType;
      }

      return ok({
        kind: "function-call",
        name: extensionCallable.value.callName,
        arguments: [callee.object, ...validatedArgs.value],
        parameterTypes: [
          receiverType.value,
          ...extensionCallable.value.parameterTypes,
        ],
        returnType: extensionCallable.value.returnType,
      });
    }

    if (memberCallable.value) {
      const boundMethodInfo = getBoundInstanceMethodCallableInfo(
        parser,
        callee,
      );
      const resolvedCallee =
        boundMethodInfo.ok && boundMethodInfo.value?.mangledName
          ? { ...callee, fieldName: boundMethodInfo.value.mangledName }
          : callee;
      return createValidatedCallNode(
        parser,
        resolvedCallee,
        argsResult.value,
        memberCallable.value.parameterTypes,
        memberCallable.value.returnType,
      );
    }
  }

  const callableInfo = getCallableInfo(parser, callee);
  if (!callableInfo.ok) {
    return callableInfo;
  }

  return createValidatedCallNode(
    parser,
    callee,
    argsResult.value,
    callableInfo.value.parameterTypes,
    callableInfo.value.returnType,
  );
}

export function createValidatedCallNode(
  parser: Parser,
  callee: ASTNode,
  args: ASTNode[],
  parameterTypes: string[],
  returnType?: string,
): Result<ASTNode, string> {
  const validatedArgs = validateCallArguments(
    parser,
    "call expression",
    args,
    parameterTypes,
  );
  if (!validatedArgs.ok) {
    return validatedArgs;
  }

  return ok({
    kind: "call",
    callee,
    arguments: validatedArgs.value,
    returnType,
  } as CallNode);
}

export function parsePrimary(parser: Parser): Result<ASTNode, string> {
  const tok = current(parser);

  if (tok.type === "TILDE") {
    return parseVTableLiteral(parser);
  }

  if (tok.type === "NUMBER") {
    advance(parser);
    return ok({ kind: "number", value: tok.value });
  }

  if (tok.type === "BOOL") {
    advance(parser);
    return ok({ kind: "boolean", value: tok.value === "true" });
  }

  if (tok.type === "CHAR") {
    advance(parser);
    return ok({ kind: "char", value: tok.value });
  }

  if (tok.type === "STRING") {
    advance(parser);
    return ok({ kind: "string", value: tok.value });
  }

  if (tok.type === "KEYWORD" && tok.value === "this") {
    if (parser.variables.has("this")) {
      advance(parser);
      return ok({ kind: "variable", name: "this" });
    }

    advance(parser);
    return ok({ kind: "this", scope: parser.currentScope });
  }

  if (tok.type === "IDENTIFIER" && tok.value === "read") {
    advance(parser);
    const lt = current(parser);
    if (lt.type !== "COMPARISON" || (lt.value !== "<" && lt.value !== "<=")) {
      return err("Expected '<' after read");
    }
    if (lt.type === "COMPARISON" && lt.value === "<=") {
      return err("Expected '<' after read, not '<='");
    }
    advance(parser);

    const typeResult = parseTypeValue(parser);
    if (!typeResult.ok) {
      return typeResult;
    }
    const typeStr = typeResult.value;
    advance(parser);

    const gt = current(parser);
    if (gt.type !== "COMPARISON" || (gt.value !== ">" && gt.value !== ">=")) {
      return err("Expected '>' after type");
    }
    if (gt.type === "COMPARISON" && gt.value === ">=") {
      return err("Expected '>' after type, not '>='");
    }
    advance(parser);

    const lparen = current(parser);
    if (lparen.type !== "LPAREN") {
      return err("Expected '(' after read<TYPE>");
    }
    advance(parser);

    const rparen = current(parser);
    if (rparen.type !== "RPAREN") {
      return err("Expected ')' after read<TYPE>(");
    }
    advance(parser);

    return ok({ kind: "read", type: typeStr });
  }

  if (tok.type === "IDENTIFIER") {
    const typeMethodReference = tryParseTypeMethodReference(parser);
    if (!typeMethodReference.ok) {
      return typeMethodReference;
    }
    if (typeMethodReference.value) {
      return ok(typeMethodReference.value);
    }

    const moduleReference = tryParseModuleReference(parser);
    if (!moduleReference.ok) {
      return moduleReference;
    }
    if (moduleReference.value) {
      return ok(moduleReference.value);
    }

    const name = tok.value;
    advance(parser);

    const explicitTypeArguments = tryParseTypeArgumentList(parser, [
      "LPAREN",
      "LBRACE",
    ]);
    if (!explicitTypeArguments.ok) {
      return explicitTypeArguments;
    }

    // Check if this is a function call (identifier followed by LPAREN)
    if (current(parser).type === "LPAREN") {
      advance(parser); // consume LPAREN
      const argsResult = parseCallArguments(parser);
      if (!argsResult.ok) {
        return argsResult;
      }

      if (explicitTypeArguments.value || parser.functions.has(name)) {
        return createResolvedFunctionCallNode(
          parser,
          name,
          argsResult.value,
          explicitTypeArguments.value,
        );
      }

      const callableInfo = getCallableInfo(parser, {
        kind: "variable",
        name,
      });
      if (!callableInfo.ok) {
        return callableInfo;
      }

      const validatedArgs = validateCallArguments(
        parser,
        name,
        argsResult.value,
        callableInfo.value.parameterTypes,
      );
      if (!validatedArgs.ok) {
        return validatedArgs;
      }

      return ok({
        kind: "function-call",
        name,
        arguments: validatedArgs.value,
        parameterTypes: callableInfo.value.parameterTypes,
        returnType: callableInfo.value.returnType,
      });
    }

    // Check if this is a struct instantiation (identifier followed by LBRACE)
    if (current(parser).type === "LBRACE" && parser.structs.has(name)) {
      // Struct instantiation
      const structInfo = parser.structs.get(name);
      if (!structInfo) {
        return err("Struct '" + name + "' is not defined");
      }

      let resolvedStructName = name;
      let resolvedStructInfo = structInfo;
      if (
        explicitTypeArguments.value &&
        explicitTypeArguments.value.length > 0
      ) {
        if (
          structInfo.typeParameters.length !==
          explicitTypeArguments.value.length
        ) {
          return err(
            "Struct '" +
              name +
              "' expects " +
              structInfo.typeParameters.length +
              " type arguments, got " +
              explicitTypeArguments.value.length,
          );
        }

        resolvedStructName =
          name + "<" + explicitTypeArguments.value.join(", ") + ">";
        const resolvedStructInfoResult = getStructInfoForType(
          parser,
          resolvedStructName,
        );
        if (!resolvedStructInfoResult.ok) {
          return resolvedStructInfoResult;
        }
        resolvedStructInfo = resolvedStructInfoResult.value;
      }

      advance(parser); // consume LBRACE

      // Parse fields
      const fields: StructInstantiationField[] = [];
      const providedFields = new Set<string>();

      while (current(parser).type !== "RBRACE") {
        // Get field name
        const fieldNameTok = current(parser);
        if (fieldNameTok.type !== "IDENTIFIER") {
          return err("Expected field name in struct instantiation");
        }
        const fieldName = (fieldNameTok as IdentifierToken).value;
        advance(parser);

        // Check for duplicate field names
        if (providedFields.has(fieldName)) {
          return err(
            "Duplicate field name '" + fieldName + "' in struct instantiation",
          );
        }
        providedFields.add(fieldName);

        // Expect ':'
        if (current(parser).type !== "COLON") {
          return err("Expected ':' after field name in struct instantiation");
        }
        advance(parser);

        // Parse field value
        const valueResult = parseExpression(parser);
        if (!valueResult.ok) {
          return valueResult;
        }

        fields.push({
          name: fieldName,
          value: valueResult.value,
        });

        // Check for comma or RBRACE
        const fieldNextTok = current(parser);
        if (fieldNextTok.type === "RBRACE") {
          break;
        } else if (fieldNextTok.type === "COMMA") {
          advance(parser);
        } else {
          return err("Expected ',' or '}' in struct instantiation");
        }
      }

      // Expect RBRACE
      if (current(parser).type !== "RBRACE") {
        return err("Expected '}' after struct fields");
      }
      advance(parser);

      // Validate all required fields are provided
      for (const structField of structInfo.fields) {
        if (!providedFields.has(structField.name)) {
          return err(
            "Missing required field '" +
              structField.name +
              "' in struct instantiation",
          );
        }
      }

      // Check for extra fields
      for (const providedField of providedFields) {
        if (!structInfo.fields.find((f) => f.name === providedField)) {
          return err(
            "Unknown field '" + providedField + "' in struct instantiation",
          );
        }
      }

      // Validate field value types match declared field types
      if (
        explicitTypeArguments.value?.length ||
        resolvedStructInfo.typeParameters.length === 0
      ) {
        for (const f of fields) {
          const declaredField = resolvedStructInfo.fields.find(
            (sf) => sf.name === f.name,
          );
          if (!declaredField) continue;
          const coercedFieldValue = coerceExpressionToType(
            parser,
            f.value,
            declaredField.type,
          );
          if (!coercedFieldValue.ok) {
            return err(
              "Field '" + f.name + "' is invalid: " + coercedFieldValue.error,
            );
          }
          f.value = coercedFieldValue.value;
        }
      }

      return ok({
        kind: "struct-instantiation",
        structName: resolvedStructName,
        fields,
        typeArguments: explicitTypeArguments.value,
      });
    }

    // Variable reference - just check it exists
    const declaredVariable = parser.variables.get(name);
    if (declaredVariable) {
      if (declaredVariable.moved) {
        return err("Variable '" + name + "' was moved and cannot be used");
      }
      return ok({ kind: "variable", name });
    }

    const scopeBinding = findScopeBinding(parser.currentScope, name);
    if (!scopeBinding) {
      return err("Variable '" + name + "' is not defined");
    }

    return ok({ kind: "variable", name });
  }

  if (tok.type === "LPAREN") {
    const closureResult = tryParseClosureLiteral(parser);
    if (!closureResult.ok) {
      return closureResult;
    }
    if (closureResult.value) {
      return ok(closureResult.value);
    }

    advance(parser);
    const expr = parseExpression(parser);
    if (!expr.ok) {
      return expr;
    }

    const closing = current(parser);
    if (closing.type !== "RPAREN") {
      return err("Expected closing parenthesis");
    }

    advance(parser);
    return ok(expr.value);
  }

  // Delegate if/match to parseExpression (avoids duplicate dispatch)
  if (tok.type === "KEYWORD" && (tok.value === "if" || tok.value === "match")) {
    return parseExpression(parser);
  }

  // Array literals [expr, expr, ...] or generator construction [callable; count]
  if (tok.type === "LBRACKET") {
    advance(parser); // consume [

    const elements: ASTNode[] = [];

    if (current(parser).type === "RBRACKET") {
      advance(parser); // consume ]
      return ok({
        kind: "array-literal",
        elements,
      } as ArrayLiteralNode);
    }

    let firstElementResult: Result<ASTNode, string>;
    if (
      current(parser).type === "IDENTIFIER" &&
      parser.functions.has((current(parser) as IdentifierToken).value) &&
      parser.tokens[parser.pos + 1]?.type === "SEMICOLON"
    ) {
      firstElementResult = ok({
        kind: "variable",
        name: (current(parser) as IdentifierToken).value,
      } as VariableNode);
      advance(parser);
    } else {
      firstElementResult = parseExpression(parser);
    }

    if (!firstElementResult.ok) {
      return firstElementResult;
    }

    if (current(parser).type === "SEMICOLON") {
      advance(parser);

      const repeatCountTok = current(parser);
      if (repeatCountTok.type !== "NUMBER") {
        return err("Expected array repeat count as number");
      }

      const repeatCountValue = repeatCountTok.value;
      if (!isBareNonNegativeIntegerLiteral(repeatCountValue)) {
        return err(
          "Expected array repeat count as a non-negative integer literal",
        );
      }
      const repeatCount = Number(repeatCountValue);
      advance(parser);

      if (current(parser).type !== "RBRACKET") {
        return err("Expected ']' after array repeat count");
      }
      advance(parser); // consume ]

      return ok({
        kind: "array-literal",
        elements,
        generator: firstElementResult.value,
        repeatCount,
      } as ArrayLiteralNode);
    }

    elements.push(firstElementResult.value);

    while (current(parser).type !== "RBRACKET") {
      const nextTok = current(parser);
      if (nextTok.type === "RBRACKET") {
        break;
      } else if (nextTok.type === "COMMA") {
        advance(parser); // consume comma
        const elemResult = parseExpression(parser);
        if (!elemResult.ok) {
          return elemResult;
        }
        elements.push(elemResult.value);
      } else {
        return err("Expected ',' or ']' in array literal");
      }
    }

    if (current(parser).type !== "RBRACKET") {
      return err("Expected ']' after array literal");
    }
    advance(parser); // consume ]

    return ok({
      kind: "array-literal",
      elements,
    } as ArrayLiteralNode);
  }

  return err("Unexpected token: " + tok.type);
}

/**
 * Consumes the current keyword token then returns the following identifier
 * name, restoring parser.pos to savedPos on failure.
 */
export function consumeKeywordAndGetName(
  parser: Parser,
  savedPos: number,
  errorMsg: string,
): Result<string, string> {
  advance(parser); // consume keyword
  const nameTok = current(parser);
  if (nameTok.type !== "IDENTIFIER") {
    parser.pos = savedPos;
    return err(errorMsg);
  }
  const name = (nameTok as IdentifierToken).value;
  advance(parser);
  return ok(name);
}

/**
 * Walks the token stream from the beginning, letting the visitor decide
 * whether it consumed the current token sequence.
 */
export function scanTokensFromStart(
  parser: Parser,
  visitor: CallableFunction,
): Result<void, string> {
  const savedPos = parser.pos;
  parser.pos = 0;

  while (current(parser).type !== "EOF") {
    const visitResult = visitor(savedPos) as Result<boolean, string>;
    if (!visitResult.ok) {
      return visitResult;
    }
    if (!visitResult.value) {
      advance(parser);
    }
  }

  parser.pos = savedPos;
  return ok(undefined);
}

export function scanMatchingKeywords(
  parser: Parser,
  matcher: CallableFunction,
  handler: CallableFunction,
): Result<void, string> {
  return scanTokensFromStart(parser, (savedPos: number) => {
    const tok = current(parser);
    if (tok.type !== "KEYWORD") {
      return ok(false);
    }

    const matchedKeyword = matcher(tok.value) as string | undefined;
    if (!matchedKeyword) {
      return ok(false);
    }

    const result = handler(savedPos, matchedKeyword) as Result<void, string>;
    return result.ok ? ok(true) : result;
  });
}

export function collectTypeDeclarationNames(
  parser: Parser,
): Result<void, string> {
  return scanTypeDeclarationKeywords(
    parser,
    (savedPos: number, declarationKind: "struct" | "type") => {
      const nameTok = current(parser);
      if (nameTok.type !== "IDENTIFIER") {
        parser.pos = savedPos;
        return err(
          "Expected " +
            (declarationKind === "type" ? "type alias" : "struct") +
            " name",
        );
      }

      const declaredName = nameTok.value;
      if (VALID_TYPES.has(declaredName)) {
        parser.pos = savedPos;
        return err("Type '" + declaredName + "' already declared");
      }

      if (declarationKind === "struct") {
        if (
          parser.structNames.has(declaredName) ||
          parser.aliasDeclarations.has(declaredName)
        ) {
          parser.pos = savedPos;
          return err("Type '" + declaredName + "' already declared");
        }
        parser.structNames.add(declaredName);
      } else {
        if (
          parser.aliasDeclarations.has(declaredName) ||
          parser.structNames.has(declaredName)
        ) {
          parser.pos = savedPos;
          return err("Type '" + declaredName + "' already declared");
        }
        parser.aliasDeclarations.set(declaredName, "");
      }

      advance(parser);
      return ok(undefined);
    },
  );
}

export function prescanTypeAliases(parser: Parser): Result<void, string> {
  return scanTypeDeclarationKeywords(
    parser,
    (_savedPos: number, declarationKind: "struct" | "type") => {
      if (declarationKind !== "type") {
        return ok(undefined);
      }
      parser.pos -= 1;
      const aliasDeclaration = parseTypeAliasDeclaration(parser, false);
      if (!aliasDeclaration.ok) {
        return aliasDeclaration;
      }

      parser.aliasDeclarations.set(
        aliasDeclaration.value.name,
        aliasDeclaration.value.targetType,
      );
      if (aliasDeclaration.value.destructorName) {
        parser.aliasDestructors.set(
          aliasDeclaration.value.name,
          aliasDeclaration.value.destructorName,
        );
      }
      return ok(undefined);
    },
  );
}

export function runPrescan(
  parser: Parser,
  keyword: string,
  handler: CallableFunction,
): Result<void, string> {
  return scanMatchingKeywords(
    parser,
    (matchedKeyword: string) => {
      return matchedKeyword === keyword ? matchedKeyword : undefined;
    },
    (savedPos: number) => handler(savedPos) as Result<void, string>,
  );
}

/**
 * Helper to register all struct definitions before parsing bodies
 * Supports nested structs and struct field types
 */
export function prescanStructDefinitions(parser: Parser): Result<void, string> {
  return runPrescan(parser, "struct", (savedPos: number) => {
    const nameResult = consumeKeywordAndGetName(
      parser,
      savedPos,
      "Expected struct name",
    );
    if (!nameResult.ok) return nameResult;
    const structName = nameResult.value;

    const typeParametersResult = parseGenericParameterList(parser);
    if (!typeParametersResult.ok) {
      parser.pos = savedPos;
      return typeParametersResult;
    }

    const fieldsResult = withTemporaryGenericTypeParameters(
      parser,
      typeParametersResult.value,
      () => parseStructFieldList(parser),
    );
    if (!fieldsResult.ok) {
      parser.pos = savedPos;
      return fieldsResult;
    }

    // Register struct
    if (!parser.structs.has(structName)) {
      parser.structs.set(structName, {
        typeParameters: typeParametersResult.value,
        fields: fieldsResult.value,
      });
    } else {
      parser.pos = savedPos;
      return err("Struct '" + structName + "' already declared");
    }

    return ok(undefined);
  });
}

/* eslint-disable no-unused-vars */
export interface PrescanTraversalHandlers {
  onTopLevelContract?(
    declarationStart: number,
    contractNode: ContractNode,
  ): Result<void, string>;
  onExternFunctionSignature?(
    declarationStart: number,
    signature: ParsedFunctionSignatureHead,
  ): Result<void, string>;
  onFunctionSignature?(
    declarationStart: number,
    signature: ParsedFunctionSignatureHead,
  ): Result<void, string>;
}
/* eslint-enable no-unused-vars */

export function getPendingFunctionReturnTypeFromSignature(
  parser: Parser,
  signature: ParsedFunctionSignatureHead,
): string | undefined {
  return signature.hasExplicitReturnType
    ? signature.returnType
    : parser.structs.has(signature.name)
      ? signature.name
      : undefined;
}

export function walkPrescanDeclarations(
  parser: Parser,
  handlers: PrescanTraversalHandlers,
): Result<void, string> {
  const savedPos = parser.pos;
  const savedCurrentFunctionReturnType = parser.currentFunctionReturnType;
  const savedActiveLifetimeNames = [...parser.activeLifetimeNames];
  const savedLifetimeDeclarationScopes = parser.lifetimeDeclarationScopes.map(
    (scope) => new Set(scope),
  );
  parser.pos = 0;
  parser.activeLifetimeNames = [];
  parser.lifetimeDeclarationScopes = [new Set<string>()];
  const braceContexts: Array<"function" | "object" | "other" | "lifetime"> = [];
  const functionReturnTypes: string[] = [];
  let pendingObjectBrace = false;
  let pendingFunctionReturnType: string | undefined;

  const updateCurrentFunctionReturnType = (): void => {
    parser.currentFunctionReturnType =
      functionReturnTypes.length > 0
        ? functionReturnTypes[functionReturnTypes.length - 1]
        : undefined;
  };

  while (current(parser).type !== "EOF") {
    const tok = current(parser);

    if (
      pendingFunctionReturnType !== undefined &&
      tok.type !== "ARROW" &&
      tok.type !== "LBRACE"
    ) {
      pendingFunctionReturnType = undefined;
    }

    if (tok.type === "KEYWORD" && tok.value === "object") {
      pendingObjectBrace = true;
      advance(parser);
      continue;
    }

    if (
      tok.type === "KEYWORD" &&
      tok.value === "contract" &&
      braceContexts.length === 0
    ) {
      const contractStart = parser.pos;
      const contractResult = parseContractStatement(parser);
      if (!contractResult.ok) {
        parser.pos = contractStart;
        return contractResult;
      }

      if (handlers.onTopLevelContract) {
        const contractRegistration = handlers.onTopLevelContract(
          contractStart,
          contractResult.value as ContractNode,
        );
        if (!contractRegistration.ok) {
          return contractRegistration;
        }
      }

      pendingObjectBrace = false;
      pendingFunctionReturnType = undefined;
      continue;
    }

    if (tok.type === "KEYWORD" && tok.value === "lifetime") {
      const scopeEntry = parseAndEnterLifetimeScope(parser);
      if (!scopeEntry.ok) {
        return scopeEntry;
      }

      braceContexts.push("lifetime");
      pendingObjectBrace = false;
      pendingFunctionReturnType = undefined;
      continue;
    }

    if (tok.type === "LBRACE") {
      if (pendingObjectBrace) {
        braceContexts.push("object");
      } else if (pendingFunctionReturnType !== undefined) {
        braceContexts.push("function");
        functionReturnTypes.push(pendingFunctionReturnType);
        updateCurrentFunctionReturnType();
      } else {
        braceContexts.push("other");
      }

      pendingObjectBrace = false;
      pendingFunctionReturnType = undefined;
      advance(parser);
      continue;
    }

    if (tok.type === "RBRACE") {
      const endedContext = braceContexts.pop();
      if (endedContext === "function") {
        functionReturnTypes.pop();
        updateCurrentFunctionReturnType();
      } else if (endedContext === "lifetime") {
        exitLifetimeScope(parser);
      }
      advance(parser);
      continue;
    }

    if (
      tok.type === "KEYWORD" &&
      tok.value === "extern" &&
      !braceContexts.includes("object")
    ) {
      const externStart = parser.pos;
      advance(parser);

      const nestedTok = current(parser);
      if (!(nestedTok.type === "KEYWORD" && nestedTok.value === "fn")) {
        pendingObjectBrace = false;
        continue;
      }

      const signatureResult = parseFunctionSignatureHead(parser, true, false);
      if (!signatureResult.ok) {
        parser.pos = externStart;
        return signatureResult;
      }

      if (current(parser).type !== "SEMICOLON") {
        parser.pos = externStart;
        return err("Expected ';' after extern function declaration");
      }
      advance(parser);

      if (handlers.onExternFunctionSignature) {
        const externRegistration = handlers.onExternFunctionSignature(
          externStart,
          signatureResult.value,
        );
        if (!externRegistration.ok) {
          return externRegistration;
        }
      }

      pendingObjectBrace = false;
      pendingFunctionReturnType = undefined;
      continue;
    }

    if (
      tok.type === "KEYWORD" &&
      tok.value === "fn" &&
      !braceContexts.includes("object")
    ) {
      const declarationStart = parser.pos;
      const signatureResult = parseFunctionSignatureHead(parser, false, false);
      if (!signatureResult.ok) {
        parser.pos = declarationStart;
        return signatureResult;
      }

      if (handlers.onFunctionSignature) {
        const signatureRegistration = handlers.onFunctionSignature(
          declarationStart,
          signatureResult.value,
        );
        if (!signatureRegistration.ok) {
          return signatureRegistration;
        }
      }

      pendingObjectBrace = false;
      pendingFunctionReturnType = getPendingFunctionReturnTypeFromSignature(
        parser,
        signatureResult.value,
      );
      continue;
    }

    pendingObjectBrace = false;
    advance(parser);
  }

  parser.pos = savedPos;
  parser.currentFunctionReturnType = savedCurrentFunctionReturnType;
  parser.activeLifetimeNames = savedActiveLifetimeNames;
  parser.lifetimeDeclarationScopes = savedLifetimeDeclarationScopes;
  return ok(undefined);
}

export function prescanContractDefinitions(
  parser: Parser,
): Result<void, string> {
  return walkPrescanDeclarations(parser, {
    onTopLevelContract: (
      declarationStart: number,
      contractNode: ContractNode,
    ) => {
      if (parser.contracts.has(contractNode.name)) {
        parser.pos = declarationStart;
        return err("Contract '" + contractNode.name + "' already declared");
      }

      parser.contracts.set(
        contractNode.name,
        createContractInfo(contractNode.typeParameters, contractNode.methods),
      );
      return ok(undefined);
    },
  });
}

/**
 * Helper to register all function signatures before parsing bodies
 * Supports mutual recursion by allowing functions to reference each other
 */
export function prescanFunctionSignatures(
  parser: Parser,
): Result<void, string> {
  return walkPrescanDeclarations(parser, {
    onExternFunctionSignature: (
      declarationStart: number,
      signature: ParsedFunctionSignatureHead,
    ) => registerParsedFunctionSignature(parser, declarationStart, signature),
    onFunctionSignature: (
      declarationStart: number,
      signature: ParsedFunctionSignatureHead,
    ) => registerParsedFunctionSignature(parser, declarationStart, signature),
  });
}
